-- Poems batch 126
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ad6f36e0-fdd7-463c-9aea-a6abebe29e20','窗下戲詠三首  其二','陸游','宋','宋诗','song-poetry','','[]','三尺清池鏡面平，剪刀葉底戲魚行。',32,'全唐诗/poet.song.136000.json','["三尺清池鏡面平，剪刀葉底戲魚行。", "吾曹安得如渠樂，傍渚跳波過此生。"]'),
('bb0989da-66ad-4f2a-8430-510ef3a9e607','窗下戲詠三首  其三','陸游','宋','宋诗','song-poetry','','[]','何處輕黄雙小蝶，翩翩與我共徘徊。',32,'全唐诗/poet.song.136000.json','["何處輕黄雙小蝶，翩翩與我共徘徊。", "綠陰芳草佳風月，不是花時也解來。"]'),
('67f17bb8-aec8-4c42-afff-fdec4030a93c','埭西小聚','陸游','宋','宋诗','song-poetry','','[]','瓦盎盛蠶蛹，沙𩰮煮麥人。',48,'全唐诗/poet.song.136000.json','["瓦盎盛蠶蛹，沙𩰮煮麥人。", "三家小聚落，兩姓世婚姻。", "父老衣冠古，閭閻風俗淳。", "不應陶靖節，獨號葛天民。"]'),
('f07d2180-6792-46b4-a63c-bbf7599fed5d','老嘆','陸游','宋','宋诗','song-poetry','','[]','步遲腰傴僂，面瘦骨崢嶸。',48,'全唐诗/poet.song.136000.json','["步遲腰傴僂，面瘦骨崢嶸。", "貧病消前業，耕樵樂太平。", "有歌悲易水，無酒醉湖城。", "何許容身得，門前釣艇橫。"]'),
('31296e30-8b48-4303-9f8b-3708203ce45f','衰甚書感','陸游','宋','宋诗','song-poetry','','[]','髮殘不勝冠，齒墮欲廢嚼。',144,'全唐诗/poet.song.136000.json','["髮殘不勝冠，齒墮欲廢嚼。", "譬如亭皋木，秋至葉自落。", "豈惟形骸變，意氣已非昨。", "床隅倚拄杖，壁上挂雙屩。", "經旬不出戶，薄飯羹藜藿。", "居然遠霜露，因得養腰脚。", "年衰固應死，延促未可度。", "人之生實難，壽終固爲樂。", "開卷思千載，閲世等六博。", "志士有蹈海，儒生亦投閣。", "何如釀濁醪，遇興時獨酌。", "半酣望青天，萬事付一噱。"]'),
('e40f6d0f-2c0f-4c8c-abe8-144180a40c20','山行過僧庵不入','陸游','宋','宋诗','song-poetry','','[]','垣屋參差竹塢深，舊題名處懶重尋。',64,'全唐诗/poet.song.136000.json','["垣屋參差竹塢深，舊題名處懶重尋。", "茶爐烟起知高興，棋子聲疏識苦心。", "淡日暉暉孤市散，殘雲漠漠半川陰。", "長吟未斷清愁起，已見橫林宿暮禽。"]'),
('da83ec02-a56f-4b53-9d1c-fba6bb52f6dc','山行','陸游','宋','宋诗','song-poetry','','[]','閑人日日得閑行，况值今朝小雨晴。',64,'全唐诗/poet.song.136000.json','["閑人日日得閑行，况值今朝小雨晴。", "水淺遊魚渾可數，山深藥草半無名。", "臨溪旋喚罾船渡，過寺初聞浴鼓聲。", "小醉未應風味減，滿盤青杏伴朱櫻。"]'),
('612f7208-b8cc-445a-a488-78853149cfb0','夜窗','陸游','宋','宋诗','song-poetry','','[]','性中汝本具光明，蔽障除時道自成。',64,'全唐诗/poet.song.136000.json','["性中汝本具光明，蔽障除時道自成。", "手刈茆苫數椽屋，身鉏菜煮一杯羹。", "天人迭勝誰能測，禍福無常不待評。", "惟有吾心終可恃，夜窗袖手聽松聲。"]'),
('d8e32d5a-e522-4382-8f17-80ed22ea5918','送邢芻甫入閩二首  其一','陸游','宋','宋诗','song-poetry','','[]','兩窮相值每相憐，聞子南遊一愴然。',32,'全唐诗/poet.song.136000.json','["兩窮相值每相憐，聞子南遊一愴然。", "莫道此行非久別，衰翁何敢望明年。"]'),
('550d22ed-618e-4085-90e3-29934300e0be','送邢芻甫入閩二首  其二','陸游','宋','宋诗','song-poetry','','[]','君行正及荔枝丹，想見臨觴爲破顔。',32,'全唐诗/poet.song.136000.json','["君行正及荔枝丹，想見臨觴爲破顔。", "此外但宜烹茗雪，傷生不用擘蠔山。"]'),
('699e7e64-6255-4f1a-a5b6-b6eabc608518','從邢芻甫求桃竹拄杖','陸游','宋','宋诗','song-poetry','','[]','拄杖當年盛得名，一枝尚覺百金輕。',32,'全唐诗/poet.song.136000.json','["拄杖當年盛得名，一枝尚覺百金輕。", "老人不復須春草，只要携渠處處行。"]'),
('c797d79e-0de4-46e7-a9d5-760544dfe526','老鷄','陸游','宋','宋诗','song-poetry','','[]','老鷄擁腫不良行，將旦猶能效一鳴。',32,'全唐诗/poet.song.136000.json','["老鷄擁腫不良行，將旦猶能效一鳴。", "碓下糠粞幸不乏，何妨相倚過餘生。"]'),
('15f94851-89f4-4ede-a99e-b5cc881f9484','還東','陸游','宋','宋诗','song-poetry','','[]','還東寒暑幾推移，漸近黄梅細雨時。',64,'全唐诗/poet.song.136000.json','["還東寒暑幾推移，漸近黄梅細雨時。", "窗下興闌初掩卷，花前技癢又成詩。", "囊錢不貯還成癖，官事都捐未免癡。", "頼是病軀差勝舊，一杯藜粥且扶衰。"]'),
('388b8e14-fd2a-4d2e-81c7-aa17d930acf4','行東山下至南巖','陸游','宋','宋诗','song-poetry','','[]','穿林了不厭崎嶇，邂逅幽懷得少攄。',64,'全唐诗/poet.song.136000.json','["穿林了不厭崎嶇，邂逅幽懷得少攄。", "昔愧出山成小草，今知臨水羨遊魚。", "呦呦馴鹿隨輕策，决决流泉入野渠。", "坐覺塵襟真一洗，正如頭垢得爬梳。"]'),
('f44bdb2b-4403-4e75-a691-300b70df3dce','書幸','陸游','宋','宋诗','song-poetry','','[]','謀身從昔本迂疏，豈料餘年却晏如。',64,'全唐诗/poet.song.136000.json','["謀身從昔本迂疏，豈料餘年却晏如。", "盤箸無時闕鮭菜，道途隨事有舟車。", "故衣已敝月三浣，短髮雖殘日一梳。", "里巷浮沉亦何憾，見賢猶及渡江初。"]'),
('c99a1369-7148-4067-905d-6de74c406c88','放言','陸游','宋','宋诗','song-poetry','','[]','酒熟固可喜，酒盡亦陶然。',96,'全唐诗/poet.song.136000.json','["酒熟固可喜，酒盡亦陶然。", "有客則劇談，無客枕書眠。", "饑啜羹不糝，閑玩琴無弦。", "摘嗅砌下花，掬弄澗底泉。", "啄木抱蠹卉，搏黍鳴桑顛。", "欣然爲一笑，世故何足捐。", "無人駡鄭虔，亦無嘲孝先。", "回顧三角童，吾與汝忘年。"]'),
('71577661-6fed-44b0-857a-6e8d16fa324a','晚步門外','陸游','宋','宋诗','song-poetry','','[]','槐葉已成陰，楸花亦離離。',72,'全唐诗/poet.song.136000.json','["槐葉已成陰，楸花亦離離。", "日暮門無人，迨我消搖時。", "左持漆園書，右挾栗里詩。", "風從湖面來，成此一段奇。", "石路雖甚狹，雅稱拖筇枝。", "少頃山月明，照我角巾欹。"]'),
('fc4988a5-1221-4dd0-b109-623e05dc4266','夏夜','陸游','宋','宋诗','song-poetry','','[]','風便更漏明，室虛蚊蚋靜。',48,'全唐诗/poet.song.136000.json','["風便更漏明，室虛蚊蚋靜。", "筋骸日益衰，厭事樂幽屏。", "清燈北窗下，突兀寫孤影。", "進學無新功，賦詩聊自警。"]'),
('3fe7c87b-5bbd-4f37-aacd-e310397a7d1d','甕池','陸游','宋','宋诗','song-poetry','','[]','薶甕東階下，灧灧一石水。',72,'全唐诗/poet.song.136000.json','["薶甕東階下，灧灧一石水。", "買魚畜其間，鱍鱍三十尾。", "力微思及物，爲惠止於此。", "無風水不搖，得志魚自喜。", "涵泳藻與蒲，永不畏刀几。", "飯罷時來觀，相娛從此始。"]'),
('3e9e51c0-014a-452b-829f-3f08f5c240be','種菜四首  其一','陸游','宋','宋诗','song-poetry','','[]','菜把青青間藥苗，豉香鹽白自烹調。',32,'全唐诗/poet.song.136000.json','["菜把青青間藥苗，豉香鹽白自烹調。", "須臾徹案呼茶碗，盤箸何曾覺寂寥。"]'),
('a5289603-28fc-4216-b7cd-a4cad89e171b','種菜四首  其二','陸游','宋','宋诗','song-poetry','','[]','老農飯粟出躬耕，捫腹何殊享大烹。',32,'全唐诗/poet.song.136000.json','["老農飯粟出躬耕，捫腹何殊享大烹。", "吳地四時常足菜，一番過後一番生。"]'),
('69fd572b-0db8-4d30-8975-f97d20b7f270','種菜四首  其三','陸游','宋','宋诗','song-poetry','','[]','白苣黄瓜上市稀，盤中頓覺有光輝。',32,'全唐诗/poet.song.136000.json','["白苣黄瓜上市稀，盤中頓覺有光輝。", "時清閭里俱安業，殊勝周人詠采薇。"]'),
('7ae31e53-5c42-4e31-bc69-ff1774648dae','種菜四首  其四','陸游','宋','宋诗','song-poetry','','[]','引水何妨藝芥菘，圃功自古補三農。',32,'全唐诗/poet.song.136000.json','["引水何妨藝芥菘，圃功自古補三農。", "恨君不見岷山芋，藏蓄猶堪過歲凶。"]'),
('d42f9552-93f7-42e0-9c3d-75aeeb8fb2ff','白首','陸游','宋','宋诗','song-poetry','','[]','白首歸來老故園，索居情味更堪論。',64,'全唐诗/poet.song.136000.json','["白首歸來老故園，索居情味更堪論。", "關河悠邈夢魂到，親舊凋零書札存。", "身病自憐詩思退，家貧客笑酒醅渾。", "昏昏只欲投床睡，兒勸孫扶强出門。"]'),
('47eb1800-2f51-4442-9131-3f0ca89a2415','東窗遣興三首  其一','陸游','宋','宋诗','song-poetry','','[]','巷陌過從少，園林景物新。',48,'全唐诗/poet.song.136000.json','["巷陌過從少，園林景物新。", "群魚時戲藻，馴雉每依人。", "映戶槐陰密，堆盤麥餌珍。", "殘春又陳迹，撫事一傷神。"]'),
('8c058b35-3c91-4502-af19-f1ecb32b3479','東窗遣興三首  其二','陸游','宋','宋诗','song-poetry','','[]','巾屨長閑客，簾櫳薄暑天。',48,'全唐诗/poet.song.136000.json','["巾屨長閑客，簾櫳薄暑天。", "巢空重乳燕，葉密未鳴蟬。", "壺箭看多算，圖書理斷編。", "悠然已日夕，却上采菱船。"]'),
('fe92c939-465e-4bfe-9ad9-0c161a00acf4','東窗遣興三首  其三','陸游','宋','宋诗','song-poetry','','[]','夏淺清陰滿，村深白日長。',48,'全唐诗/poet.song.136000.json','["夏淺清陰滿，村深白日長。", "言多思寂默，酒醒悔猖狂。", "老馬漫知路，鈍錐寧出囊。", "此翁真耄矣，懶放亦何傷。"]'),
('36be7308-86b2-4304-9cc9-6997d5c8c1b0','北窗','陸游','宋','宋诗','song-poetry','','[]','晏嬰長不滿五尺，淳于飲能至一石。',128,'全唐诗/poet.song.136000.json','["晏嬰長不滿五尺，淳于飲能至一石。", "老無功名未足嘆，滑稽玩世亦非昔。", "當年交友傾一時，誰料蓬門今寂寂。", "陳山李石千載士，早死當爲天下惜。", "斯文顯晦端有命，道悠運促非人力。", "我今稽山一老農，百歲不死知何益。", "後生可畏要有人，誰能隠若一敵國。", "狂言勿發心自驚，歸卧北窗還默默。"]'),
('0a35a24a-7d18-4909-82f9-1bea48d15ba9','小酌','陸游','宋','宋诗','song-poetry','','[]','偶向東園把一杯，不辭團坐掃蒼苔。',64,'全唐诗/poet.song.136000.json','["偶向東園把一杯，不辭團坐掃蒼苔。", "野花經雨自開落，山鳥穿林時去來。", "皂白正非天欲辨，青黄要與木爲災。", "今年秋後猶能健，剩乞梅栽與李栽。"]'),
('f7ce39bb-e6fb-4614-a82d-342f02d531a2','夏日十二首  其一','陸游','宋','宋诗','song-poetry','','[]','暑雨初晴晝漏遲，江鄉樂事有誰知。',32,'全唐诗/poet.song.136000.json','["暑雨初晴晝漏遲，江鄉樂事有誰知。", "村村壟麥登場後，戶戶吳蠶坼簇時。"]'),
('dce5d11a-3f03-4973-8a2e-2409862d5650','夏日十二首  其二','陸游','宋','宋诗','song-poetry','','[]','齒髮凋零奈爾何，年光暗裏易消磨。',32,'全唐诗/poet.song.136000.json','["齒髮凋零奈爾何，年光暗裏易消磨。", "街槐正喜清陰密，巷柳還驚蠹葉多。"]'),
('d3f45c7d-92f7-47e4-a59f-5a4bcb277553','夏日十二首  其三','陸游','宋','宋诗','song-poetry','','[]','竹根斷作眠雲枕，木癭刳成貯酒尊。',32,'全唐诗/poet.song.136000.json','["竹根斷作眠雲枕，木癭刳成貯酒尊。", "怪怪奇奇非著意，自無俗物到山村。"]'),
('fb4df2d1-4aff-4e60-b342-4205b903ca0a','夏日十二首  其四','陸游','宋','宋诗','song-poetry','','[]','動身尚懶那堪事，學古無成罷讀書。',32,'全唐诗/poet.song.136000.json','["動身尚懶那堪事，學古無成罷讀書。", "枕上側眠聽語燕，池邊小立看遊魚。"]'),
('029a08b5-e999-4314-a89d-0eb1179427e4','夏日十二首  其五','陸游','宋','宋诗','song-poetry','','[]','悶欲遠遊身苦懶，病思閑話客誰過。',32,'全唐诗/poet.song.136000.json','["悶欲遠遊身苦懶，病思閑話客誰過。", "北窗一枕差堪樂，無奈茶杯作祟何。"]'),
('28d48222-6bfa-44b4-8af0-67c3150ca560','夏日十二首  其六','陸游','宋','宋诗','song-poetry','','[]','黄葛蚊厨睡欲成，高槐陰轉暑風清。',32,'全唐诗/poet.song.136000.json','["黄葛蚊厨睡欲成，高槐陰轉暑風清。", "倚床奴子垂頭坐，搖手孫兒小步行。"]'),
('9ab7dee3-40db-4958-854a-17cd3c5c2bdb','夏日十二首  其七','陸游','宋','宋诗','song-poetry','','[]','斮取溪藤便作香，煉成崖蜜旋煎湯。',32,'全唐诗/poet.song.136000.json','["斮取溪藤便作香，煉成崖蜜旋煎湯。", "蕭然巾履茅堂上，不畏人間夏日長。"]'),
('2978175e-d9a3-4eb2-b2b6-1968b1f0cce6','夏日十二首  其八','陸游','宋','宋诗','song-poetry','','[]','謝客捐書日日閑，行穿密竹卧看山。',32,'全唐诗/poet.song.136000.json','["謝客捐書日日閑，行穿密竹卧看山。", "巖前恨欠煎茶地，安得茆茨一小間。"]'),
('93c83072-2f43-4bf4-a6be-fd610267bb19','夏日十二首  其九','陸游','宋','宋诗','song-poetry','','[]','蘋生洲渚微風起，梅熟園林細雨來。',32,'全唐诗/poet.song.136000.json','["蘋生洲渚微風起，梅熟園林細雨來。", "咫尺柴門常懶出，不教拄杖損蒼苔。"]'),
('b288697f-a28e-40ea-aa71-98d8b22bef9f','夏日十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','側卧橫眠百不知，軒窗寂寂雨絲絲。',32,'全唐诗/poet.song.136000.json','["側卧橫眠百不知，軒窗寂寂雨絲絲。", "豈無布襪青鞋興，過却梅天出未遲。"]'),
('cd170996-3dbc-4493-abbb-d17bbe413f75','夏日十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','幽花婭姹開還斂，小蝶翩翾去復留。',32,'全唐诗/poet.song.136000.json','["幽花婭姹開還斂，小蝶翩翾去復留。", "貪睡畸翁俱不領，被人錯喚作閑愁。"]'),
('8ce58eeb-a466-4f60-a39d-168a128354d4','夏日十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','山下柴荆晝不開，苔生古井暗楸槐。',32,'全唐诗/poet.song.136000.json','["山下柴荆晝不開，苔生古井暗楸槐。", "新詩哦罷閑無事，移取藤床睡去來。"]'),
('2aad7599-3eb4-4779-8618-a4383595d44d','睡起','陸游','宋','宋诗','song-poetry','','[]','不恨無人到野堂，惟將美睡答年光。',64,'全唐诗/poet.song.136000.json','["不恨無人到野堂，惟將美睡答年光。", "風經荷葉翻翻綠，雨溼松枝細細香。", "薄俗空成士龍笑，長歌未盡接輿狂。", "掬泉弄石翛然晚，又得今年一夏凉。"]'),
('12ca2a00-0983-4d2b-abdb-1f84f30e3783','雨中作','陸游','宋','宋诗','song-poetry','','[]','湖曲雨凄凄，茆簷觸額低。',48,'全唐诗/poet.song.136000.json','["湖曲雨凄凄，茆簷觸額低。", "衡門元少客，窮巷况多泥。", "解渴黄粱粥，嘗新白苣齏。", "吾生真自足，不恨老鉏犁。"]'),
('284a69ba-6c71-4a50-8a05-5d8a9610aea6','感物二首  其一','陸游','宋','宋诗','song-poetry','','[]','物情豈願歲時遒，一氣潜移不自由。',32,'全唐诗/poet.song.136000.json','["物情豈願歲時遒，一氣潜移不自由。", "日出鵓鴣還喚雨，夏初蟋蟀已吟秋。"]'),
('8ead805d-0c16-48d3-acf8-f1ed200c8d4c','感物二首  其二','陸游','宋','宋诗','song-poetry','','[]','小園清曉岸綸巾，物態年光日日新。',32,'全唐诗/poet.song.136000.json','["小園清曉岸綸巾，物態年光日日新。", "綠葉自生黄自落，不應秋至始愁人。"]'),
('8ce965f6-9769-4eb6-954b-f1d2e3719594','舟中有賦','陸游','宋','宋诗','song-poetry','','[]','一枝柔櫓聽咿啞，炊稻來依野老家。',64,'全唐诗/poet.song.136000.json','["一枝柔櫓聽咿啞，炊稻來依野老家。", "山寺日中齋鼓動，江樓風急酒旗斜。", "綠梢嫋嫋搖新竹，翠蔓離離熟早瓜。", "閑客去留隨所遇，不知何處送棲鴉。"]'),
('ed1ae2ef-e423-4ae4-878f-280d3ec0a899','晨起獨行綠陰間','陸游','宋','宋诗','song-poetry','','[]','楸槐陰裏漏朝暉，芳草離離露漸稀。',64,'全唐诗/poet.song.136000.json','["楸槐陰裏漏朝暉，芳草離離露漸稀。", "不恨過時嘗煮酒，且欣平旦著生衣。", "病逢鍼藥如差減，貧比簞瓢尚庶幾。", "惟是未能忘習氣，亂書隨日又成圍。"]'),
('2c0456f0-4513-4f0d-add7-8ee4e4340572','獨至遯庵避暑庵在大竹林中二首  其一','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵厭垢紛，竹林深處寄幽欣。',64,'全唐诗/poet.song.136000.json','["赤日黄塵厭垢紛，竹林深處寄幽欣。", "如聽嵩雒風前笛，似看瀟湘雨後雲。", "園鹿知時新解角，池魚得意自成群。", "悠然一笑誰能識，坐勝天魔百萬軍。"]'),
('3a4636f4-3247-4f2e-aff1-8b28303b1353','獨至遯庵避暑庵在大竹林中二首  其二','陸游','宋','宋诗','song-poetry','','[]','世俗元非不汝忘，汝歸安取醉爲鄉。',64,'全唐诗/poet.song.136000.json','["世俗元非不汝忘，汝歸安取醉爲鄉。", "藥苗野蔌山家味，柏子松房道室香。", "一卷隠書爲日課，數聲啼鳥謝年光。", "客來莫笑茆茨陋，占盡炎天一味凉。"]'),
('a338f1a5-6704-48a3-b817-6c0722efeeb0','短歌行','陸游','宋','宋诗','song-poetry','','[]','上樽不解散牢愁，靈藥安能扶死病。',100,'全唐诗/poet.song.136000.json','["上樽不解散牢愁，靈藥安能扶死病。", "千鈞强弩無自射虛空，六出奇計終難逃定命。", "人生斯世無別巧，要在遇物心不競。", "憂忘寢食怒裂眥，孰若憑高寄孤詠。", "炎天一葛冬一裘，藜羹飯糗勿豫謀。", "耳邊閑事有何極，正可付之風馬牛。"]'),
('0d0c65ed-38e4-47f9-8eb7-0c3289417afd','山寺','陸游','宋','宋诗','song-poetry','','[]','路盡初逢寺，行行獨叩扉。',48,'全唐诗/poet.song.136000.json','["路盡初逢寺，行行獨叩扉。", "民貧稀送供，僧老少完衣。", "日正樓鐘動，溪深藥草肥。", "吾衰亦久矣，捨此欲疇依。"]'),
('7f479ab2-d602-46eb-9fec-a1b0503be955','明日復欲出遊而雨再用前韵','陸游','宋','宋诗','song-poetry','','[]','小艇爭浮浦，幽人獨倚扉。',48,'全唐诗/poet.song.136000.json','["小艇爭浮浦，幽人獨倚扉。", "新泥添燕壘，細雨溼鶑衣。", "葚紫桑新暗，秧青水正肥。", "欣然語鄰父，投老得相依。"]'),
('69066703-d372-406c-99eb-e4653a069f3a','暇日登東岡','陸游','宋','宋诗','song-poetry','','[]','雙屨青芒滑，輕衫白苧凉。',48,'全唐诗/poet.song.136000.json','["雙屨青芒滑，輕衫白苧凉。", "雲生半巖潤，麝過一林香。", "童子持棋局，厨人饋粟漿。", "歸來更清絕，淡月滿林塘。"]'),
('6e637adc-ce17-400f-8501-a36a7f93b349','暴雨','陸游','宋','宋诗','song-poetry','','[]','黑雲如龍爪，白雨如博棋。',72,'全唐诗/poet.song.136000.json','["黑雲如龍爪，白雨如博棋。", "老屋處處漏，此夕將何之。", "豈惟移床避，殆欲懸釜炊。", "擾擾舍中人，具食不以時。", "兒女乃可憐，赤脚啼午饑。", "語兒姑少忍，開霽會有期。"]'),
('2e5ecd57-776e-48bb-8886-be7fa7d80a1f','幽事二首  其一','陸游','宋','宋诗','song-poetry','','[]','衰翁喜幽事，闖戶不升堂。',48,'全唐诗/poet.song.136000.json','["衰翁喜幽事，闖戶不升堂。", "酒僅三蕉葉，琴纔一履霜。", "好遊力不給，愛客病相妨。", "獨有詩情在，年來亦漸忘。"]'),
('842cf20c-431f-4257-92af-5e5e1a0cc894','幽事二首  其二','陸游','宋','宋诗','song-poetry','','[]','野館多幽事，畸人無俗情。',48,'全唐诗/poet.song.136000.json','["野館多幽事，畸人無俗情。", "靜分書句讀，戲習酒章程。", "藥褚藏難見，棋枰算未成。", "悠然寄孤嘯，吾豈固逃名。"]'),
('e0f84ed3-efb0-4988-8ff5-2a226a97083f','病起雜言','陸游','宋','宋诗','song-poetry','','[]','國不可以無菑眚，身不可以無疢疾。',154,'全唐诗/poet.song.136000.json','["國不可以無菑眚，身不可以無疢疾。", "無菑之國亂或更速，無疾之身死或無日。", "昆夷玁狁無害於周之王，闢土富國無救于隋之亡。", "壯夫一卧多不起，速死未必皆羸尪。", "古來惡疾棄空谷，往往更得度世方。", "我年九十理不長，况復三日病在床。", "天公念之亦已至，儆戒不使須臾忘。", "起居飲食每自省，常若嚴師畏友在我傍。", "躋民仁壽則非職，且爲老憊鍼膏肓。"]'),
('1d6bb3f8-2536-4c1e-bce3-228fe1663de2','雨後二首  其一','陸游','宋','宋诗','song-poetry','','[]','小築濤江外，微凉暑雨餘。',48,'全唐诗/poet.song.136000.json','["小築濤江外，微凉暑雨餘。", "傾囊致歡伯，信脚到華胥。", "芳草翩翩蝶，清池潑潑魚。", "此翁雖耄矣，作計未全疏。"]'),
('c23347c0-3e15-4fd0-8c5f-4d120a29fb2f','雨後二首  其二','陸游','宋','宋诗','song-poetry','','[]','一夜茅簷雨，晨興乃爾凉。',48,'全唐诗/poet.song.136000.json','["一夜茅簷雨，晨興乃爾凉。", "禽魚皆遂性，草木自吹香。", "微潤生琴薦，纖塵避筆床。", "悠然北窗興，真欲傲羲皇。"]'),
('44c62e04-644d-4674-8e21-cc5e02f6ba77','示客','陸游','宋','宋诗','song-poetry','','[]','久泛烟波不問津，騰騰且復養吾真。',64,'全唐诗/poet.song.136000.json','["久泛烟波不問津，騰騰且復養吾真。", "每持杯酒呼江月，殊勝征衣化路塵。", "半枕何人遊蟻垤，立談爲汝脫狐身。", "挂帆莫恨瀟湘遠，是處相逢一笑新。"]'),
('5a441b6d-c510-4d5e-b220-76d75bb9b229','蒸溽作雨排悶','陸游','宋','宋诗','song-poetry','','[]','柱礎生微潤，簾櫳轉薄陰。',48,'全唐诗/poet.song.136000.json','["柱礎生微潤，簾櫳轉薄陰。", "蟻遷都邑改，鳩逐怨恩深。", "菡萏新離水，芭蕉半展心。", "掩屏惟熟睡，誰與續愁吟。"]'),
('78401f86-2eaa-4ff6-9ae6-61042d337dc7','夏中雜興六首  其一','陸游','宋','宋诗','song-poetry','','[]','梳髮高舂後，投床甲夜初。',48,'全唐诗/poet.song.136000.json','["梳髮高舂後，投床甲夜初。", "語艱愁對客，手倦怕催書。", "美睡那思覺，甘餐不願餘。", "更應慚造化，無事到幽居。"]'),
('9aa4cb5f-7810-4d3f-a419-b8ed8f9ba32a','夏中雜興六首  其二','陸游','宋','宋诗','song-poetry','','[]','小響風吹葉，微痕雨點池。',48,'全唐诗/poet.song.136000.json','["小響風吹葉，微痕雨點池。", "興來閑弄笛，客散自收棋。", "忽忽尋殘夢，時時足小詩。", "出門俄已暮，忘却野人期。"]'),
('0456636e-7b58-4419-92cf-7446f846e34a','夏中雜興六首  其三','陸游','宋','宋诗','song-poetry','','[]','出赴盟鷗社，歸尋夢蝶床。',48,'全唐诗/poet.song.136000.json','["出赴盟鷗社，歸尋夢蝶床。", "愚爲度世術，閑是養生方。", "休歇書中癖，消磨酒後狂。", "遠遊亦已矣，不復解輕裝。"]'),
('aab62067-3378-4115-b55d-4abfd9d9ac61','夏中雜興六首  其四','陸游','宋','宋诗','song-poetry','','[]','處世如灰冷，持心似砥平。',48,'全唐诗/poet.song.136000.json','["處世如灰冷，持心似砥平。", "盤餐無宿戒，香火有常程。", "樵父供藜杖，陶人售瓦檠。", "經旬常苦雨，嘯傲送餘生。"]'),
('39b26642-5c55-4705-8d56-e7eccecd62f0','夏中雜興六首  其五','陸游','宋','宋诗','song-poetry','','[]','心慕羲農世，躬行黄老言。',48,'全唐诗/poet.song.136000.json','["心慕羲農世，躬行黄老言。", "采椽聊築舍，橫木即爲門。", "短髮冠龜屋，空床枕竹根。", "從來薄世味，染指肯嘗黿。"]'),
('bbb5aa21-bf65-4e90-ae87-d8dae2e42ad7','夏中雜興六首  其六','陸游','宋','宋诗','song-poetry','','[]','遣信邀鄰父，隨宜具小餐。',48,'全唐诗/poet.song.136000.json','["遣信邀鄰父，隨宜具小餐。", "草燔豚肉美，甕壓酒醅渾。", "易致商山皓，難招楚澤魂。", "嗟予亦衰矣，心事與誰論。"]'),
('226c8edc-6bc7-4a9e-a7d7-2e4e23110b57','即事八首  其一','陸游','宋','宋诗','song-poetry','','[]','翁自析薪兒負薪，一生不似此年貧。',32,'全唐诗/poet.song.136000.json','["翁自析薪兒負薪，一生不似此年貧。", "折除却得常强健，天定方知果勝人。"]'),
('7ee5085d-a7d9-4f76-8e43-0e6b70649051','即事八首  其二','陸游','宋','宋诗','song-poetry','','[]','楸垂落索槐吐花，溪女採蓮童抱瓜。',32,'全唐诗/poet.song.136000.json','["楸垂落索槐吐花，溪女採蓮童抱瓜。", "一年光景又將半，愈老愈知生有涯。"]'),
('880bf972-b560-4e04-b48d-30d5c7342afd','即事八首  其三','陸游','宋','宋诗','song-poetry','','[]','烟雨凄迷晚不收，疏簾曲几寄悠悠。',32,'全唐诗/poet.song.136000.json','["烟雨凄迷晚不收，疏簾曲几寄悠悠。", "一雙蛺蝶來何許，點盡青青百草頭。"]'),
('def2a538-97df-4dfb-ba44-917591c6cbc4','即事八首  其四','陸游','宋','宋诗','song-poetry','','[]','生來骨相本酸寒，天遣沙頭把釣竿。',32,'全唐诗/poet.song.136000.json','["生來骨相本酸寒，天遣沙頭把釣竿。", "但稱山人擫耳帽，敢希楚客切雲冠。"]'),
('d8ea777e-f926-4b81-967a-11eb70654716','即事八首  其五','陸游','宋','宋诗','song-poetry','','[]','魚鰌群出天將雨，蛙黽爭鳴草滿庭。',32,'全唐诗/poet.song.136000.json','["魚鰌群出天將雨，蛙黽爭鳴草滿庭。", "莫道歸休便無事，時時襏襫伴園丁。"]'),
('4c067162-cc9a-4379-beb8-15b4d7450dc8','即事八首  其六','陸游','宋','宋诗','song-poetry','','[]','幽鳥飛鳴翠木陰，小魚游泳綠波心。',32,'全唐诗/poet.song.136000.json','["幽鳥飛鳴翠木陰，小魚游泳綠波心。", "滿前好句無人領，堪笑寒窗費苦吟。"]'),
('66836ec6-22f7-4e8a-8356-082f5fd48b29','即事八首  其七','陸游','宋','宋诗','song-poetry','','[]','小閣憑欄望遠空，天河橫貫斗牛中。',32,'全唐诗/poet.song.136000.json','["小閣憑欄望遠空，天河橫貫斗牛中。", "他年鼓角榆關路，馬上遥看與此同。"]'),
('7061ba7c-41fb-4492-bd64-026e9d3f4e80','即事八首  其八','陸游','宋','宋诗','song-poetry','','[]','幽鳥呼人出睡鄉，層層露葉漏朝陽。',32,'全唐诗/poet.song.136000.json','["幽鳥呼人出睡鄉，層層露葉漏朝陽。", "臨池只欲消殘醉，無奈鵝兒似酒黄。"]'),
('cb2b0c6a-ccc9-49b3-91b9-44dd8325427a','夏日幽居','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵一點無，負山臨水是幽居。',64,'全唐诗/poet.song.136000.json','["赤日黄塵一點無，負山臨水是幽居。", "爽如瑞露零仙掌，清似寒冰貯玉壺。", "孤艇過時驚宿鷺，溼烟深處亂風蒲。", "翛然欲棄人間去，天際聯翩誰與俱。"]'),
('3113b75b-559f-4f6d-9343-88cea5ad5853','枕上','陸游','宋','宋诗','song-poetry','','[]','小疾知閑樂，微凉與睡宜。',48,'全唐诗/poet.song.136000.json','["小疾知閑樂，微凉與睡宜。", "瞢騰如欲覺，展轉復多時。", "四壁人聲寂，疏簾日影移。", "詩囊與藥裹，一步不相離。"]'),
('74ece981-bc60-433b-80fb-168119c37efb','題望海亭亭在卧龍絕頂','陸游','宋','宋诗','song-poetry','','[]','瑞龍千丈何蜿蜒，蒼鱗翠鬣翔江邊。',192,'全唐诗/poet.song.136000.json','["瑞龍千丈何蜿蜒，蒼鱗翠鬣翔江邊。", "路逢鏡湖乃下駐，玩珠不去知何年。", "七州元帥擁畫戟，全家終日樓居仙。", "霜笳一曲入銀漢，碧瓦萬疊浮嵐烟。", "其間望海最傑觀，疏豁坐占蓬萊先。", "風雲變化几席上，蛟鼉出沒闌干前。", "手捫心房倚北斗，眼中萬象俱森然。", "尚書喚客共領略，遠坊十里聞管弦。", "從容賦詩出妙思，超絕欲拍微之肩。", "坐中有客垂九十，追逐無路空自憐。", "夜闌客散公歸院，笙歌隠隠在半天。", "向來老客今何處，菱唱三更起釣船。"]'),
('a504ed9c-3e48-44dc-8c43-0087c7db1273','露坐小飲','陸游','宋','宋诗','song-poetry','','[]','寂寂柴門閉嫩苔，門前有路走天台。',64,'全唐诗/poet.song.136000.json','["寂寂柴門閉嫩苔，門前有路走天台。", "近秋河漢西南落，欲雨風雲東北來。", "旋摘甘瓜青带蔓，新篘玉醴冷傳杯。", "亦知野外無供給，且復相逢笑口開。"]'),
('3e301995-524b-4397-b4f7-47f57da36902','小憩卧龍山亭','陸游','宋','宋诗','song-poetry','','[]','山高風浩浩，堂豁海冥冥。',48,'全唐诗/poet.song.136000.json','["山高風浩浩，堂豁海冥冥。", "綠李分猿嗛，蒼苔墮鶴翎。", "松寒詩思健，茶爽醉魂醒。", "安得丹青手，傳摹入素屏。"]'),
('c6f06347-db0b-4660-83c2-7f7ad35ee680','晚凉','陸游','宋','宋诗','song-poetry','','[]','笛簟平鋪八尺床，脫巾高卧對疏篁。',32,'全唐诗/poet.song.136000.json','["笛簟平鋪八尺床，脫巾高卧對疏篁。", "近村得雨知何處，此地無風亦自凉。"]'),
('4abea3a5-25e9-44e6-80cb-9ac6cd3a375b','夏日六言四首  其一','陸游','宋','宋诗','song-poetry','','[]','退士自應客少，幽居不厭椽低。',28,'全唐诗/poet.song.136000.json','["退士自應客少，幽居不厭椽低。", "未說盤堆玉膾，且看臼搗金齏。"]'),
('9d59ff5e-082c-4818-b820-ada281da205a','夏日六言四首  其二','陸游','宋','宋诗','song-poetry','','[]','醉面貪承夕露，釣竿喜近秋風。',28,'全唐诗/poet.song.136000.json','["醉面貪承夕露，釣竿喜近秋風。", "借問孤舟何處，深入芙蕖浦中。"]'),
('cf0c190e-6b68-4db5-8c0f-e33760882bf6','夏日六言四首  其三','陸游','宋','宋诗','song-poetry','','[]','溪漲清風拂面，月落繁星滿天。',28,'全唐诗/poet.song.136000.json','["溪漲清風拂面，月落繁星滿天。", "數隻船橫浦口，一聲笛起山前。"]'),
('79000183-bcb2-423c-8100-9d54035ab7d1','夏日六言四首  其四','陸游','宋','宋诗','song-poetry','','[]','我是百年遺老，掃空一夢浮名。',28,'全唐诗/poet.song.136000.json','["我是百年遺老，掃空一夢浮名。", "未到終南二華，且入天台四明。"]'),
('03e858b8-a352-4418-ae2b-2cdd3bcf52ad','招客看山','陸游','宋','宋诗','song-poetry','','[]','今日清明宜看山，約君來上釣魚船。',32,'全唐诗/poet.song.136000.json','["今日清明宜看山，約君來上釣魚船。", "微雲點破尚堪恨，何况城中塵漲天。"]'),
('0ea89610-a9d4-4a9e-a814-5517b8f389d3','舟中作','陸游','宋','宋诗','song-poetry','','[]','平生剩有烟波興，釣瀨時時小艇橫。',64,'全唐诗/poet.song.136000.json','["平生剩有烟波興，釣瀨時時小艇橫。", "欲暮山光先慘淡，未秋河漢已分明。", "捕魚時見連江網，迎荻遥聞過埭聲。", "想得今宵清絕夢，又携猿鶴上青城。"]'),
('8139c5e8-6ee9-4a98-bff1-b7772c722f10','清暑','陸游','宋','宋诗','song-poetry','','[]','穿竹清我魂，散髮吹我頂。',96,'全唐诗/poet.song.136000.json','["穿竹清我魂，散髮吹我頂。", "虛窗聽鳴蟬，小檻看汲井。", "掃地長物空，漱泉齒頰冷。", "厨人具漿粉，童子煮山茗。", "微雲未必雨，且喜收樹影。", "殘書置不視，樂此清晝永。", "既夕即榜舟，門外綠千頃。", "世事何足論，平生慕箕潁。"]'),
('1d55c203-140b-4db2-9818-52c01e755001','五月下旬大熱晦日夜得雨明旦凉甚','陸游','宋','宋诗','song-poetry','','[]','一雨蕭然洗睡昏，清晨屣履自開門。',64,'全唐诗/poet.song.136000.json','["一雨蕭然洗睡昏，清晨屣履自開門。", "豈惟爽氣生山袂，坐覺凉颸入髮根。", "浦口魚多來野鶴，林梢果熟下山猿。", "吾廬清絕君知否，釣雪寒江不足言。"]'),
('2d849faa-bcf0-45f8-81c0-46ea027ce7f4','黄氏沖和堂','陸游','宋','宋诗','song-poetry','','[]','沖和堂中和氣襲，堆笏滿床群從集。',96,'全唐诗/poet.song.136000.json','["沖和堂中和氣襲，堆笏滿床群從集。", "宜州太史一紙書，百年筆墨猶山立。", "使君所學何超然，要是胸中不負天。", "王畿奉使纔廿日，忠厚風流天下傳。", "國家多事民力困，正要設施先百郡。", "但令一念與天通，河南南陽亦可問。"]'),
('8403ad19-093d-484b-bd8a-5d73043d68ed','暴雨','陸游','宋','宋诗','song-poetry','','[]','蒼龍挂東南，夭矯拏萬仞。',96,'全唐诗/poet.song.136000.json','["蒼龍挂東南，夭矯拏萬仞。", "雖然雜雲氣，爪尾略可認。", "明日暴雨來，繼以雷大震。", "平地成江河，吞卷纔一瞬。", "吾廬久傾壞，不壓真堇堇。", "所欣憔悴中，一飽天不吝。", "餘功到場圃，草木皆綠潤。", "蕭然岸角巾，三嘆撫庭楯。"]'),
('3faaf9c8-3a0c-4b7d-8264-04452b6951de','書意三首  其一','陸游','宋','宋诗','song-poetry','','[]','策蹇若華駟，啜漓如上尊。',48,'全唐诗/poet.song.136000.json','["策蹇若華駟，啜漓如上尊。", "人皆可堯舜，身自有乾坤。", "逢客亦共語，無人還閉門。", "千年道術裂，誰復見全渾。"]'),
('c02fa3b5-d2dc-4bad-9931-b561aa1cd85d','書意三首  其二','陸游','宋','宋诗','song-poetry','','[]','養生慕黄老，爲治法唐虞。',48,'全唐诗/poet.song.136000.json','["養生慕黄老，爲治法唐虞。", "耆壽緣憂懼，危亡坐燕娛。", "大川宜利涉，蔓草戒難圖。", "退士惟身慮，銘膺豈敢無。"]'),
('f8187303-5a10-41f4-96d9-965805eddcda','書意三首  其三','陸游','宋','宋诗','song-poetry','','[]','委順天知我，經營鬼笑人。',48,'全唐诗/poet.song.136000.json','["委順天知我，經營鬼笑人。", "定知窮至死，敢恨病經旬。", "愛酒陶元亮，還鄉賀季真。", "扁舟吾事畢，遺世亦遺身。"]'),
('ff400927-ec52-436f-895a-c5e7e1578ea9','浴罷','陸游','宋','宋诗','song-poetry','','[]','浴罷淡無事，出門隨意行。',48,'全唐诗/poet.song.136000.json','["浴罷淡無事，出門隨意行。", "相如知渴減，叔寶覺神清。", "新月參差影，殘蟬斷續聲。", "躊躕遂忘去，風露欲三更。"]'),
('fdc54577-b351-49ef-9f2e-acd13059c7ce','水鄉泛舟二首  其一','陸游','宋','宋诗','song-poetry','','[]','終朝流汗浹衣褠，悵望何時枕簟秋。',64,'全唐诗/poet.song.136000.json','["終朝流汗浹衣褠，悵望何時枕簟秋。", "作雨未成徒益熱，舉杯不醉更添愁。", "悲歌易水輕燕俠，對泣新亭笑楚囚。", "別有生涯君會否，烟波無際弄孤舟。"]'),
('b5bbdceb-3000-466e-90cb-988f668e533a','水鄉泛舟二首  其二','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵不自聊，泛溪且用沃枯焦。',64,'全唐诗/poet.song.136000.json','["赤日黄塵不自聊，泛溪且用沃枯焦。", "隔林犬吠村墟近，掠面風來酒力消。", "遠火微茫知夜績，長歌斷續認歸樵。", "扁舟不盡凌風興，却著青鞋踏野橋。"]'),
('f9f496e6-a3ca-4b9c-84da-013317060a8e','閑詠','陸游','宋','宋诗','song-poetry','','[]','平生到處足間關，天遣殘年樂故山。',64,'全唐诗/poet.song.136000.json','["平生到處足間關，天遣殘年樂故山。", "社日連村饜酒肉，豐年無盜伏茆菅。", "秋來梁燕將雛去，雨過林鳩喚婦還。", "我亦葛衣新浴罷，爲君滿意說清閑。"]'),
('4425f5b5-3932-4dc3-b7f9-985c6970a73d','江樓夜望','陸游','宋','宋诗','song-poetry','','[]','江樓百尺倚高寒，上盡危梯宇宙寬。',64,'全唐诗/poet.song.136000.json','["江樓百尺倚高寒，上盡危梯宇宙寬。", "秋近漸看河落角，天回更覺斗闌干。", "茫茫浦口烟帆遠，坎坎城頭漏鼓殘。", "要得故人同躡屐，一尊相屬話悲歡。"]'),
('a6bf4f61-1e7b-403e-926a-74df4909b7cf','連日作雨苦熱','陸游','宋','宋诗','song-poetry','','[]','天地一氣爾，陰陽司闔開。',72,'全唐诗/poet.song.136000.json','["天地一氣爾，陰陽司闔開。", "鬰蒸以爲雨，回薄以爲雷。", "久鬰無所泄，造化安在哉。", "方其欲雨時，雖天不能回。", "此豈降自天，其實有自來。", "所以屈宋輩，千載有餘哀。"]'),
('16592dfa-c1fe-4add-844d-b3cb1c094806','門外追凉','陸游','宋','宋诗','song-poetry','','[]','羽扇綸巾一味凉，曠懷非醉亦非狂。',64,'全唐诗/poet.song.136000.json','["羽扇綸巾一味凉，曠懷非醉亦非狂。", "橫林點點暮鴉集，平壟離離新稻香。", "山月出時閑弄影，水風清處旋移床。", "學仙到此無餘說，更覺金丹墮粃糠。"]'),
('3b2d949a-7f0e-4de3-901b-7dce00bd30d7','夏夜泛溪至南莊復回湖桑歸','陸游','宋','宋诗','song-poetry','','[]','不求奇骨可封侯，但喜枯腸不貯愁。',64,'全唐诗/poet.song.136000.json','["不求奇骨可封侯，但喜枯腸不貯愁。", "數點殘燈沽酒市，一聲柔櫓採菱舟。", "元知澤國偏宜夜，已就天公探借秋。", "歸過三更風露重，紗巾剩覺髮颼飀。"]'),
('a27eb7c5-df19-4703-a73e-fa017c5942e4','雨後殊有秋意','陸游','宋','宋诗','song-poetry','','[]','天地新秋入苦吟，詩書萬古付孤斟。',64,'全唐诗/poet.song.136000.json','["天地新秋入苦吟，詩書萬古付孤斟。", "愛君憂國孤臣泪，臨水登山節士心。", "只嘆鼻端無妙斲，豈知弦外有遺音。", "剡中勝踐今猶昔，安得高人支道林。"]'),
('05146b5d-3646-4843-a2b3-1e08236688b7','寓規三首  其一','陸游','宋','宋诗','song-poetry','','[]','百疾皆有源，雖愚猶自知。',48,'全唐诗/poet.song.136000.json','["百疾皆有源，雖愚猶自知。", "惟其忽不念，所以悔莫追。", "微隙爲無傷，一壞誰能支。", "宴安比鴆毒，先民不吾欺。"]'),
('64c625ef-61fc-472f-8816-b6d58ab3ab23','寓規三首  其二','陸游','宋','宋诗','song-poetry','','[]','分量各有窮，升龠不受斗。',48,'全唐诗/poet.song.136000.json','["分量各有窮，升龠不受斗。", "滿盈靡懷懼，覆敗乃自取。", "衣笥無復褌，食案有三韭。", "貧狹雖可嗤，比汝差耐久。"]'),
('e793691f-83b5-4a0e-9c6a-0370e89a138c','寓規三首  其三','陸游','宋','宋诗','song-poetry','','[]','人生孰無疾，治疾惟欲瘳。',48,'全唐诗/poet.song.136000.json','["人生孰無疾，治疾惟欲瘳。", "疾瘳藥不止，乃有過劑憂。", "節食戒屬饜，養氣常致柔。", "金丹無此功，往哉勤自修。"]'),
('47faf285-d826-4aab-ba12-704327e4df39','新凉二首  其一','陸游','宋','宋诗','song-poetry','','[]','儘道新凉好，無如晝漏長。',48,'全唐诗/poet.song.136000.json','["儘道新凉好，無如晝漏長。", "奇文窺楚屈，妙理玩蒙莊。", "靜卧貧猶樂，高歌醒亦狂。", "翩翩雙蝶子，也似惜年光。"]'),
('379af7f8-48ba-4743-962e-2c61f52bd295','新凉二首  其二','陸游','宋','宋诗','song-poetry','','[]','月入楸梧徑，風生蘆荻林。',48,'全唐诗/poet.song.136000.json','["月入楸梧徑，風生蘆荻林。", "脫巾凉入髮，臨水爽披襟。", "寒暑推移久，江湖感慨深。", "功名雖已矣，猶得寓孤吟。"]'),
('40ef43b8-2d31-407c-bf4a-f7bf88cffd73','追凉至安隠寺前','陸游','宋','宋诗','song-poetry','','[]','枕石何妨更漱流，一凉之外豈他求。',64,'全唐诗/poet.song.136000.json','["枕石何妨更漱流，一凉之外豈他求。", "寺樓無影月卓午，橋樹有聲風變秋。", "殘曆半空心悄愴，岸巾徐步髮颼飀。", "定知從此清宵夢，常在沙邊伴白鷗。"]'),
('ac007c69-4023-4fda-9f4d-1ed39a98b88a','湖上夜賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','冉冉秋將至，沉沉夜向晨。',48,'全唐诗/poet.song.136000.json','["冉冉秋將至，沉沉夜向晨。", "河隨天漸轉，露洗月如新。", "瘦竹過眉杖，輕紗折角巾。", "漁歌四面起，烟水浩無津。"]'),
('8b84cfa1-bf71-4dfc-811e-82fcf91727bb','湖上夜賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','清絕追凉地，平生得未曾。',48,'全唐诗/poet.song.136000.json','["清絕追凉地，平生得未曾。", "似嘗仙掌露，如嚼玉壺冰。", "狂學菱舟曲，閑尋竹院僧。", "更思生羽翼，散髮醉巴陵。"]'),
('79b2d00a-e614-4663-a572-6ca052159b0b','書適','陸游','宋','宋诗','song-poetry','','[]','萬事罷經營，悠然心太平。',48,'全唐诗/poet.song.136000.json','["萬事罷經營，悠然心太平。", "甘餐隨日足，美睡等閑成。", "處處佳風月，人人好弟兄。", "神仙不須學，券內有長生。"]'),
('e2baf355-2808-45be-8640-8a73dc35cd5e','羸老','陸游','宋','宋诗','song-poetry','','[]','羸老幸未死，敢嗟生理微。',48,'全唐诗/poet.song.136000.json','["羸老幸未死，敢嗟生理微。", "牛閑牧童卧，犬吠市船歸。", "月落見收網，燈青聞踏機。", "時時語鄰里，井臼幸相依。"]'),
('e9f57a64-5bb5-44f6-853b-a921b10694de','即事','陸游','宋','宋诗','song-poetry','','[]','皋夔無近用，芝朮少奇功。',48,'全唐诗/poet.song.136000.json','["皋夔無近用，芝朮少奇功。", "上壽當徐致，沉疴忌力攻。", "醫傳三世久，事歷百年中。", "畏與庸人說，終身托病聾。"]'),
('f56e6bf8-0965-4297-974e-a90a7e12d12b','晚興','陸游','宋','宋诗','song-poetry','','[]','並簷幽鳥語璁瓏，一榻蕭然四面風。',64,'全唐诗/poet.song.136000.json','["並簷幽鳥語璁瓏，一榻蕭然四面風。", "客散茶甘留舌本，睡餘書味在胸中。", "浮雲變態吾何與，腐骨成塵論自公。", "剩欲與君談此事，少須明月出溪東。"]'),
('46a95232-5d6d-4b2b-bab8-a206ab7e8d0b','郊行','陸游','宋','宋诗','song-poetry','','[]','凄風吹雨過江城，緩策羸驂並水行。',64,'全唐诗/poet.song.136000.json','["凄風吹雨過江城，緩策羸驂並水行。", "古路初驚秋葉墮，荒郊已放候蟲鳴。", "壯心耿耿人誰識，往事悠悠恨未平。", "斜日半竿羌笛怨，西陵寂寞又潮生。"]'),
('d6ed6885-63e9-45e6-9ffe-cb00ed4f8fc6','喜雨','陸游','宋','宋诗','song-poetry','','[]','雨氣侵人暮不休，雨聲逼枕冷颼颼。',64,'全唐诗/poet.song.136000.json','["雨氣侵人暮不休，雨聲逼枕冷颼颼。", "方欣草木有生意，已報溝池無涸流。", "避溼入簷憐病鶴，爭巢逐婦嘆鳴鳩。", "老農自喜知時節，夜半呼兒起飯牛。"]'),
('474c592f-e532-4532-a093-a7473114d565','劉道士贈小葫蘆四首  其一','陸游','宋','宋诗','song-poetry','','[]','葫蘆雖小藏天地，伴我雲山萬里身。',32,'全唐诗/poet.song.136000.json','["葫蘆雖小藏天地，伴我雲山萬里身。", "收起鬼神窺不見，用時能與物爲春。"]'),
('e18a9007-1d0c-4202-9d68-481d88481718','劉道士贈小葫蘆四首  其二','陸游','宋','宋诗','song-poetry','','[]','貴人玉带佩金魚，憂畏何曾頃刻無。',32,'全唐诗/poet.song.136000.json','["貴人玉带佩金魚，憂畏何曾頃刻無。", "色似栗黄形似繭，恨渠不識小葫蘆。"]'),
('874a7be7-311b-4f47-a754-6e41107dbd88','劉道士贈小葫蘆四首  其三','陸游','宋','宋诗','song-poetry','','[]','短袍楚製未爲非，况得藥瓢相發揮。',32,'全唐诗/poet.song.136000.json','["短袍楚製未爲非，况得藥瓢相發揮。", "行過山村傾社看，絕勝小劍壓戎衣。"]'),
('c96deb41-fdf2-4623-b875-678afa5cd6ed','劉道士贈小葫蘆四首  其四','陸游','宋','宋诗','song-poetry','','[]','箇中一物著不得，建立森然却有餘。',32,'全唐诗/poet.song.136000.json','["箇中一物著不得，建立森然却有餘。", "盡底語君君豈信，試來跳入看何如。"]'),
('f9123dd1-2a28-4c26-8dcb-56de67359c0e','自儆','陸游','宋','宋诗','song-poetry','','[]','學當盡力去浮華，從事文辭但可嗟。',32,'全唐诗/poet.song.136000.json','["學當盡力去浮華，從事文辭但可嗟。", "造道淺深看應物，修身勤惰驗齊家。"]'),
('e05a075c-9f49-4c14-a502-262c212da68c','雨中','陸游','宋','宋诗','song-poetry','','[]','孤村風雨連三日，秋暑如焚一洗空。',32,'全唐诗/poet.song.136000.json','["孤村風雨連三日，秋暑如焚一洗空。", "睡覺房櫳燈漸暗，却尋殘夢雨聲中。"]'),
('4c53f1b1-16aa-4a3f-b88b-5fc8ca15cb28','書嘆二首  其一','陸游','宋','宋诗','song-poetry','','[]','遺蝗出境樂秋成，多稼登場喜雨晴。',32,'全唐诗/poet.song.136000.json','["遺蝗出境樂秋成，多稼登場喜雨晴。", "暗笑衰翁不解事，猶懷萬里玉關情。"]'),
('d90153b3-2801-4a3b-83ae-de5148c9af81','書嘆二首  其二','陸游','宋','宋诗','song-poetry','','[]','雨夜孤舟宿鏡湖，秋聲蕭瑟滿菰蒲。',32,'全唐诗/poet.song.136000.json','["雨夜孤舟宿鏡湖，秋聲蕭瑟滿菰蒲。", "書生有泪無揮處，尋見祥符九域圖。"]'),
('f8834175-1a80-4e37-acae-6706b5195b36','題畫薄荷扇二首  其一','陸游','宋','宋诗','song-poetry','','[]','薄荷花開蝶翅翻，風枝露葉弄秋妍。',32,'全唐诗/poet.song.136000.json','["薄荷花開蝶翅翻，風枝露葉弄秋妍。", "自憐不及狸奴黠，爛醉籬邊不用錢。"]'),
('f3f8032c-f959-4044-be76-f08cc1e6262c','題畫薄荷扇二首  其二','陸游','宋','宋诗','song-poetry','','[]','一枝香草出幽叢，雙蝶飛飛戲晚風。',32,'全唐诗/poet.song.136000.json','["一枝香草出幽叢，雙蝶飛飛戲晚風。", "莫恨村居相識晚，知名元向楚辭中。"]'),
('8741f163-d173-4502-9f3c-7f4148caaab8','秋興四首  其一','陸游','宋','宋诗','song-poetry','','[]','誰敢輕他萬戶侯，一生賦分在滄洲。',64,'全唐诗/poet.song.136000.json','["誰敢輕他萬戶侯，一生賦分在滄洲。", "屋穿况值雨騎月，路惡更堪風打頭。", "此世極知同逆旅，吾身亦自是懸疣。", "乞錢買取青芒屨，爛醉三條二華秋。"]'),
('3c39cefe-51f6-4ec4-9738-1b96d276ff86','秋興四首  其二','陸游','宋','宋诗','song-poetry','','[]','斂盡殘雲見夕陽，門前䆉䅉漸登場。',64,'全唐诗/poet.song.136000.json','["斂盡殘雲見夕陽，門前䆉䅉漸登場。", "經年都得幾回醉，一雨頓驚如許凉。", "耐事尚能心似鐵，放歌仍忘髮成霜。", "頤生底用從人問，此是山翁肘後方。"]'),
('9d713fc1-74f1-4255-a990-8d1f0f038856','秋興四首  其三','陸游','宋','宋诗','song-poetry','','[]','五十年來住鏡湖，白頭仍是一臞儒。',64,'全唐诗/poet.song.136000.json','["五十年來住鏡湖，白頭仍是一臞儒。", "朝眠每恨妨書課，秋穫先令入酒逋。", "江路伶俜形吊影，草庵寂默我忘吾。", "雨窗忽有高談興，筮叟醫翁亦可呼。"]'),
('51a89ab8-881a-4a7d-9123-607eebd8bdce','秋興四首  其四','陸游','宋','宋诗','song-poetry','','[]','世事何曾挂齒牙，只將放浪作生涯。',64,'全唐诗/poet.song.136000.json','["世事何曾挂齒牙，只將放浪作生涯。", "有時掬米引馴鹿，到處入林求野花。", "鄰父築場收早稼，溪姑負籠賣秋茶。", "等閑一日還過却，又倚柴扉數暮鴉。"]'),
('8cdcb28f-5daf-4231-9f6c-4c4f6b14b706','晝睡','陸游','宋','宋诗','song-poetry','','[]','體中小不佳，惟睡可以休。',72,'全唐诗/poet.song.136000.json','["體中小不佳，惟睡可以休。", "睡美自成夢，去爲萬里遊。", "萬里遊尚可，乃復有得喪。", "漂搖一葉舟，掀舞千重浪。", "午鷄忽驚起，向夢安在哉。", "童子解原夢，篝火具茶杯。"]'),
('c7a1ecab-dc5c-4d17-8c61-08e4105d7100','得子虡濠上書','陸游','宋','宋诗','song-poetry','','[]','日暮坐柴門，懷抱方煩紆。',72,'全唐诗/poet.song.136000.json','["日暮坐柴門，懷抱方煩紆。", "鈴聲從西來，忽得濠州書。", "開緘讀未半，喜極涕泗俱。", "父子老惜別，况經患難餘。", "羈旅易生疾，霜露行載塗。", "思歸雖甚苦，且復忍須臾。"]'),
('2b4efd23-0bd0-4de2-b83a-6d3cb33a31e9','庭草','陸游','宋','宋诗','song-poetry','','[]','階前西風搖百草，鬰鬰逢秋殊未槁。',96,'全唐诗/poet.song.136000.json','["階前西風搖百草，鬰鬰逢秋殊未槁。", "雪霜要當次第來，恰似人生怕衰老。", "百草榮悴則有時，人於養生當自知。", "金丹九轉儻未辦，簡斂沖默真吾師。", "攝調小失豈遽死，二豎眉端先溢喜。", "但令神氣常守形，莫畏夢中呼起起。"]'),
('72ad42b1-44d3-43b9-a99f-1631c469eff6','文章','陸游','宋','宋诗','song-poetry','','["\u54f2\u7406"]','文章本天成，妙手偶得之。',72,'全唐诗/poet.song.136000.json','["文章本天成，妙手偶得之。", "粹然無疵瑕，豈復須人爲。", "君看古彝器，巧拙兩無施。", "漢最近先秦，固已殊淳漓。", "胡部何爲者，豪竹雜哀絲。", "后夔不復作，千載誰與期。"]'),
('25d9b6bf-a324-401a-84e6-95472f5251ad','秋日遣懷八首  其一','陸游','宋','宋诗','song-poetry','','[]','離離上藥苗，鬰鬰靈芝榮。',48,'全唐诗/poet.song.136000.json','["離離上藥苗，鬰鬰靈芝榮。", "我昔逢異人，瑣細皆能名。", "擊石以取火，薪桂持煎烹。", "五雲夜覆鼎，談笑得長生。"]'),
('387f926e-fff6-4af2-b88b-a5eb8c23f520','秋日遣懷八首  其二','陸游','宋','宋诗','song-poetry','','[]','胸中何所有，世界如河沙。',48,'全唐诗/poet.song.136000.json','["胸中何所有，世界如河沙。", "區區吞雲夢，何至爲客誇。", "初見賣苑冰，青門已無瓜。", "天河正不遠，秋風乘客槎。"]'),
('faa8d665-4e03-41aa-98cf-38d96c378928','秋日遣懷八首  其三','陸游','宋','宋诗','song-poetry','','[]','西來浮濤江，東眺俯鏡湖。',48,'全唐诗/poet.song.136000.json','["西來浮濤江，東眺俯鏡湖。", "其中綿千里，鬰鬰桑麻區。", "禹葬有遺窆，粵亡無故墟。", "秋風吹短褐，望古空躊躇。"]'),
('56c255d4-5fef-4e63-baf3-1870ab01346e','秋日遣懷八首  其四','陸游','宋','宋诗','song-poetry','','[]','野風聲如潮，溪水色可染。',48,'全唐诗/poet.song.136000.json','["野風聲如潮，溪水色可染。", "浮雲時翳日，亦作雨數點。", "行歌雖放浪，未至越繩檢。", "蕭然茅三間，送老此山崦。"]'),
('b08a0335-ac79-4c30-b639-2aac37479e27','秋日遣懷八首  其五','陸游','宋','宋诗','song-poetry','','[]','秋夜坐東窗，殘雨時一滴。',48,'全唐诗/poet.song.136000.json','["秋夜坐東窗，殘雨時一滴。", "四壁無人聲，心境兩虛寂。", "吾方遊物初，超然謝形役。", "一毫儻未盡，何往非勍敵。"]'),
('1f80a8a2-7f1a-4787-8279-e80c625e123c','秋日遣懷八首  其六','陸游','宋','宋诗','song-poetry','','[]','自我歸故山，不知歲月徂。',48,'全唐诗/poet.song.136000.json','["自我歸故山，不知歲月徂。", "念雖迫霜露，憂國猶區區。", "老不能上疏，泰階陳六符。", "安得子元子，同歌于蒍于。"]'),
('bcca7063-76d9-4f48-a65b-f164266ec400','秋日遣懷八首  其七','陸游','宋','宋诗','song-poetry','','[]','今年秋氣早，風露應時令。',48,'全唐诗/poet.song.136000.json','["今年秋氣早，風露應時令。", "晨起換熟衣，殘暑已退聽。", "松聲滿庭戶，蕭然失衰病。", "人衆何足言，天固不可勝。"]'),
('60ad2b89-381f-4dea-9252-cbc896d69b6d','秋日遣懷八首  其八','陸游','宋','宋诗','song-poetry','','[]','晨几手作墨，午窗身磑茶。',48,'全唐诗/poet.song.136000.json','["晨几手作墨，午窗身磑茶。", "豈惟要小勞，亦以禦百邪。", "兒童不解此，傾心逐紛華。", "君看如山禍，萌在一念差。"]'),
('6e97e096-901a-4c31-9d75-64e2bad7a1c2','自儆二首  其一','陸游','宋','宋诗','song-poetry','','[]','惡石從來豈汝仇，安居無患却堪憂。',32,'全唐诗/poet.song.136000.json','["惡石從來豈汝仇，安居無患却堪憂。", "不須更守庚申夜，留取三彭儆惰偷。"]'),
('7128987e-0b07-4804-95ee-00fe87cd8628','自儆二首  其二','陸游','宋','宋诗','song-poetry','','[]','世事如雲日日新，瓦盆黍酒却關身。',32,'全唐诗/poet.song.136000.json','["世事如雲日日新，瓦盆黍酒却關身。", "細思只有窮居好，寄語玄翁莫逐貧。"]'),
('5f46c820-9efe-48ff-9084-e5bdb7604cc2','生世','陸游','宋','宋诗','song-poetry','','[]','乾坤成毀由來事，生世真同黍一炊。',32,'全唐诗/poet.song.136000.json','["乾坤成毀由來事，生世真同黍一炊。", "嗟我已過三萬日，餘年有幾自應知。"]'),
('40fcb621-9c86-41e0-816b-4ac538a7da05','秋雨','陸游','宋','宋诗','song-poetry','','[]','山深草木久已荒，晝昏風雨殊未止。',96,'全唐诗/poet.song.136000.json','["山深草木久已荒，晝昏風雨殊未止。", "看書不覺向壁卧，煎茶欲罷推枕起。", "清心正付竹罏香，漱齒每挹巖泉水。", "與世不諧元有命，閉門自適差可喜。", "少年癡絕晚乃悟，束縛珠襦均一死。", "悠然袖手倚蒲團，洗盡玉關心萬里。"]'),
('89d29bda-4dcd-4c33-9689-cafbe09076d9','思蜀','陸游','宋','宋诗','song-poetry','','[]','西遊陳迹浩無窮，回首真同一夢中。',64,'全唐诗/poet.song.136000.json','["西遊陳迹浩無窮，回首真同一夢中。", "柳拂驛牆思鳳集，鼓喧市裏憶蠶叢。", "故人丘壟秋蕪碧，舊隠園林夕照紅。", "自閔未能忘感慨，浩歌彈劍送飛鴻。"]'),
('96b9550c-34c5-427f-809c-1e4169061c4d','病思','陸游','宋','宋诗','song-poetry','','[]','短髮蕭蕭不滿簪，更堪衰疾日侵尋。',64,'全唐诗/poet.song.136000.json','["短髮蕭蕭不滿簪，更堪衰疾日侵尋。", "數匙淡飯支殘息，一篆清香印本心。", "小徑古苔遺鶴毳，空堂壞甃有蟲吟。", "悠然更起扁舟興，秋水門前五尺深。"]'),
('5d4df3e9-63a2-45ba-9206-fccaadfaa7fa','術家言予今歲畏四孟月而秋尤甚自初秋小疾屢作戲題長句','陸游','宋','宋诗','song-poetry','','[]','一生强半卧窮閻，糲飯藜羹似蜜甜。',64,'全唐诗/poet.song.136000.json','["一生强半卧窮閻，糲飯藜羹似蜜甜。", "耄齒覺衰嗟已晚，孟秋屬疾信如占。", "危途本自難安步，惡石何妨更痛砭。", "堅忍莫爲秋雨嘆，牽蘿猶足補茅苫。"]'),
('cbd69e06-0c53-4784-aa90-a50117e06c72','秋夕書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','垂老雖堪嘆，爲謀亦未疏。',48,'全唐诗/poet.song.136000.json','["垂老雖堪嘆，爲謀亦未疏。", "悶賒鄰巷酒，閑讀後身書。", "大嚼寧須肉，徐行可當車。", "秋來歡喜事，菽粟有新儲。"]'),
('ab7d8f5f-2532-4ee6-a9b1-879d3a540080','秋夕書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','點點秋燈晚，翻翻宿鳥還。',48,'全唐诗/poet.song.136000.json','["點點秋燈晚，翻翻宿鳥還。", "雨添羈枕睡，書伴小窗閑。", "僧閣荒寒外，漁村縹緲間。", "畫工今代少，誰爲寫家山。"]'),
('b753f3e5-bbf0-425f-ac88-17939cf3bbe1','小疾三首  其一','陸游','宋','宋诗','song-poetry','','[]','小疾有根柢，忽之當日深。',48,'全唐诗/poet.song.136000.json','["小疾有根柢，忽之當日深。", "養苗先去草，省事在清心。", "蟻夢能看破，狐妖可坐擒。", "一杯藜粥罷，聽雨擁秋衾。"]'),
('1b800a39-8a6a-4da0-abf6-edc094bf4fa8','小疾三首  其二','陸游','宋','宋诗','song-poetry','','[]','老不禁當病，經旬卧一床。',48,'全唐诗/poet.song.136000.json','["老不禁當病，經旬卧一床。", "亦知非疥癬，幸未至膏肓。", "水落灘初出，秋深草漸黄。", "非關畏人事，晚歲合深藏。"]'),
('4549595a-dc86-4b80-bbbc-ed288b4cf9b8','小疾三首  其三','陸游','宋','宋诗','song-poetry','','[]','避人便小疾，省事喜閑身。',48,'全唐诗/poet.song.136000.json','["避人便小疾，省事喜閑身。", "並海魚鹽聚，入秋風雨頻。", "元知器苦窳，空有膽輪囷。", "轑飯聊同飽，知君不笑貧。"]'),
('f6b6a2d5-b4fb-45c8-bc8a-a9c5ad68f5c6','病中作','陸游','宋','宋诗','song-poetry','','[]','此事明明在默存，一身元有一乾坤。',64,'全唐诗/poet.song.136000.json','["此事明明在默存，一身元有一乾坤。", "不憂豎子居肓上，已見真人出面門。", "力守誰能發底火，深潜自足美靈根。", "用功若到無功處，千載乘雲不足言。"]'),
('f51925a4-2fe7-4c92-92db-f03da2bea343','縱筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','天下本無事，吾生行且休。',48,'全唐诗/poet.song.136000.json','["天下本無事，吾生行且休。", "關心惟酒盞，入眼獨漁舟。", "雁過三湘曉，雲開二華秋。", "殷勤驛樓柱，小草記曾遊。"]'),
('8d5ede7f-573d-4706-9018-773abd741538','縱筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','相馬失之瘦，知人良獨難。',48,'全唐诗/poet.song.136000.json','["相馬失之瘦，知人良獨難。", "雖居環堵室，未廢切雲冠。", "暮雨潼關暗，秋風渭水寒。", "深蕪埋壯士，千古爲悲歡。"]'),
('7757d738-e0e6-46fd-910a-9f2b940af10c','自立秋前病過白露猶未平遣懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','門冷荒車轍，囊空別醉鄉。',48,'全唐诗/poet.song.136000.json','["門冷荒車轍，囊空別醉鄉。", "懶行眠亦好，倦話默何傷。", "野叟占幽夢，山僧送秘方。", "病懷雖忽忽，隨事答年光。"]'),
('bf083464-f397-47f7-8cf4-b339cd9ac756','自立秋前病過白露猶未平遣懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','饑能堅志節，病可養精神。',48,'全唐诗/poet.song.136000.json','["饑能堅志節，病可養精神。", "不動成羆卧，微勞學鳥伸。", "功名知幻境，憂患笑前身。", "藥裹吾何厭，秋燈作夢新。"]'),
('85de89a2-3a30-4cb7-82ab-bd3595bdb334','聖門','陸游','宋','宋诗','song-poetry','','[]','聖門妙處不容思，千古茫茫欲語誰。',64,'全唐诗/poet.song.136000.json','["聖門妙處不容思，千古茫茫欲語誰。", "晞髮庭中新沐後，舞雩沂上詠歸時。", "研求豈足窺微指，博約何由遇碩師。", "小疾掃空身尚健，蓬窗更作數年期。"]'),
('5674f7ff-0344-45b7-8d78-ea3ed6b6fcd8','書齋壁','陸游','宋','宋诗','song-poetry','','[]','幅巾短褐野人裝，洗盡黄塵早暮忙。',64,'全唐诗/poet.song.136000.json','["幅巾短褐野人裝，洗盡黄塵早暮忙。", "地僻漁扉常隠翳，身閑靈府自清凉。", "雨中鬰鬰垣衣綠，澗底纖纖石髮長。", "老憊只思眠蹋壁，一尊到手又成狂。"]'),
('c7536be1-69b8-405e-abdd-8fdd0249dcc1','病後小健戲題','陸游','宋','宋诗','song-poetry','','[]','行年九十未龍鍾，慚愧天公久見容。',32,'全唐诗/poet.song.136000.json','["行年九十未龍鍾，慚愧天公久見容。", "醉解病人詩解瘦，不如世世作春農。"]'),
('a5518fb0-299e-41f1-a4f0-c1f2331c576e','新晴','陸游','宋','宋诗','song-poetry','','[]','雨葉玲瓏曉日明，經旬風雨得初晴。',32,'全唐诗/poet.song.136000.json','["雨葉玲瓏曉日明，經旬風雨得初晴。", "欹眠歇盡人間念，時聽幽禽一兩聲。"]'),
('a619311a-751a-4a3a-a6d8-8686833deb54','夢中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','征途遇秋雨，數士集郵亭。',48,'全唐诗/poet.song.136000.json','["征途遇秋雨，數士集郵亭。", "酒拆官壺綠，山圍草市青。", "劇談猶激烈，瘦影各伶俜。", "四海皆兄弟，悠然共醉醒。"]'),
('b87a5707-ed3b-41f2-9e24-7bd6b724fa47','夢中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','一客若蜀士，相逢意氣豪。',48,'全唐诗/poet.song.136000.json','["一客若蜀士，相逢意氣豪。", "偶談唐夾寨，遂及楚成皋。", "頓洗風塵惡，都忘箠轡勞。", "蟬嘶笑餘子，辛苦學離騷。"]'),
('9df75dcc-ebc0-4e60-b958-959578ddd08d','疾小愈縱筆作短章','陸游','宋','宋诗','song-poetry','','[]','治疾如治盜，要使復其常。',120,'全唐诗/poet.song.136000.json','["治疾如治盜，要使復其常。", "藉曰用戈矛，全之寧欲傷。", "彼盜皆吾民，初非若胡羌。", "奈何一朝忿，直欲事歐攘。", "歐攘雖快心，少忍理則長。", "華佗古神醫，煎浣到肺腸。", "取效雖卓犖，去死真毫芒。", "君審欲除盜，惟當法龔黄。", "撫摩倘有道，四境皆耕桑。", "我亦以治疾，不減玉函方。"]'),
('13605fa1-8233-40cc-b0d5-1952feee065b','病少愈偶作二首  其一','陸游','宋','宋诗','song-poetry','','[]','蕭條白髮卧蓬廬，虛讀人間萬卷書。',64,'全唐诗/poet.song.136000.json','["蕭條白髮卧蓬廬，虛讀人間萬卷書。", "遇事始知聞道晚，抱疴方悔養生疏。", "高門赫赫何關我，薄俗紛紛莫問渠。", "羸疾少蘇思一出，夕陽門巷駕柴車。"]'),
('4cdc8e03-0932-4747-9b5d-389bf4ba651c','病少愈偶作二首  其二','陸游','宋','宋诗','song-poetry','','[]','病入秋來不可當，便從此逝亦何傷。',64,'全唐诗/poet.song.136000.json','["病入秋來不可當，便從此逝亦何傷。", "百錢布被斂首足，三寸桐棺埋澗崗。", "但恨著書終草草，不嫌徂歲去堂堂。", "今朝生意纔絲髮，便擬街頭醉放狂。"]'),
('13fa6c39-3836-4164-9d0f-c31905cba66b','書生','陸游','宋','宋诗','song-poetry','','[]','書生事業苦難成，點檢常憂害至誠。',64,'全唐诗/poet.song.136000.json','["書生事業苦難成，點檢常憂害至誠。", "夢寐未能除小忿，文辭猶欲事虛名。", "聖言甚遠當深考，古義雖聞要力行。", "漢世陋儒吾所斥，若爲青紫勝歸耕。"]'),
('83843508-6710-42f4-9d2f-784a45a80712','古驛','陸游','宋','宋诗','song-poetry','','[]','古驛橋邊艇子橫，每因羈旅愜幽情。',64,'全唐诗/poet.song.136000.json','["古驛橋邊艇子橫，每因羈旅愜幽情。", "窗間月落無花影，枕上潮來有櫓聲。", "舊友凋零歸夢想，新詩邂逅得天成。", "今朝有喜君知否，秋雨晴時小疾平。"]'),
('4536b282-3871-44e6-8f64-e7159fa6a472','夜讀劉伯倫傳戲作','陸游','宋','宋诗','song-poetry','','[]','生本無心死可知，徐徐掩骨未爲遲。',32,'全唐诗/poet.song.136000.json','["生本無心死可知，徐徐掩骨未爲遲。", "一奴僅可供薪水，那得閑人荷鍤隨。"]'),
('71715e00-40da-4676-a1e4-cbd76fce153b','湖上晚望','陸游','宋','宋诗','song-poetry','','[]','閑人無處破除閑，待得漁舟一一還。',32,'全唐诗/poet.song.136000.json','["閑人無處破除閑，待得漁舟一一還。", "峰頂夕陽烟際水，分明六幅巨然山。"]'),
('9e692fe0-4408-4fba-9442-2ab95b90fc02','村居即事三首  其一','陸游','宋','宋诗','song-poetry','','[]','西成東作常無事，婦饁夫耕萬里同。',32,'全唐诗/poet.song.136000.json','["西成東作常無事，婦饁夫耕萬里同。", "但願清平好官府，眼中歷歷見豳風。"]'),
('43e38b9a-412d-4541-86e5-cd81736bcb14','村居即事三首  其二','陸游','宋','宋诗','song-poetry','','[]','炊甑生塵榻長苔，柴門日晏未曾開。',32,'全唐诗/poet.song.136000.json','["炊甑生塵榻長苔，柴門日晏未曾開。", "載醪問字今牢落，猶有鄰翁裹飯來。"]'),
('0bbc4374-b13b-4aa7-bfc4-a3aa04a6ce7f','村居即事三首  其三','陸游','宋','宋诗','song-poetry','','[]','長笛圜鼙曲調新，東家西舍送迎神。',32,'全唐诗/poet.song.136000.json','["長笛圜鼙曲調新，東家西舍送迎神。", "不因豐歲人情樂，淡殺溪頭老病人。"]'),
('548f40d5-fc4f-4b8b-b687-1cc935fc4af6','夜興','陸游','宋','宋诗','song-poetry','','[]','夜闌扶策繞中庭，雲罅三三兩兩星。',32,'全唐诗/poet.song.136000.json','["夜闌扶策繞中庭，雲罅三三兩兩星。", "安得南風卷雲盡，爛然河白映天青。"]'),
('c87582da-6d23-49ed-82c6-aeb316884ef8','夢華山','陸游','宋','宋诗','song-poetry','','[]','路入河潼喜著鞭，華山忽到帽裙邊。',64,'全唐诗/poet.song.136000.json','["路入河潼喜著鞭，華山忽到帽裙邊。", "洗頭盆上雲生壁，腰带鞓前月滿川。", "丹竈故基誰復識，白馿遺迹但相傳。", "夢魂妄想君無笑，尚擬今生得地仙。"]'),
('2a8a7d1e-e49b-4246-a8de-628537518a93','寓嘆四首  其一','陸游','宋','宋诗','song-poetry','','[]','窮居諳世故，了了不如昏。',48,'全唐诗/poet.song.136000.json','["窮居諳世故，了了不如昏。", "萬事慵挂眼，終年思杜門。", "雲閑忘出岫，葉落喜歸根。", "熟計惟當醉，寧論社甕渾。"]'),
('f6316df9-bd2c-4c18-acff-1068ada58250','寓嘆四首  其二','陸游','宋','宋诗','song-poetry','','[]','小隠終非隠，休官尚是官。',48,'全唐诗/poet.song.136000.json','["小隠終非隠，休官尚是官。", "早知農圃樂，不見道途難。", "故國鷄豚社，貧家菽水歡。", "至今清夜夢，猶覺畏濤瀾。"]'),
('8f7df795-71eb-4a87-b5ec-1d7d22f089ea','寓嘆四首  其三','陸游','宋','宋诗','song-poetry','','[]','事外癡頑老，人中剩長身。',48,'全唐诗/poet.song.136000.json','["事外癡頑老，人中剩長身。", "開顔時頼酒，閉口不言貧。", "淡話常終夕，閑遊動歷旬。", "漁翁偶相遇，疑是武陵人。"]'),
('f89117d6-d8dd-4ee6-959f-831d5de4eab3','寓嘆四首  其四','陸游','宋','宋诗','song-poetry','','[]','老閲市朝久，紛紛常厭看。',48,'全唐诗/poet.song.136000.json','["老閲市朝久，紛紛常厭看。", "人紆綬紫艾，家擁轂朱丹。", "不羨官曹熱，惟憐眼境寒。", "東塗與西抹，感舊一長嘆。"]'),
('4e40754c-e5f5-4d2b-ae33-66be342ec38f','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其一','陸游','宋','宋诗','song-poetry','','[]','獨立溪橋看落暉，殘蕪漠漠蝶飛飛。',32,'全唐诗/poet.song.136000.json','["獨立溪橋看落暉，殘蕪漠漠蝶飛飛。", "從來澤國秋常晚，嘆息衰翁已衲衣。"]'),
('48205ab5-f7c8-4015-a562-cb45b70e4267','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其二','陸游','宋','宋诗','song-poetry','','[]','今年病老遂難禁，二豎奔逃豈易尋。',32,'全唐诗/poet.song.136000.json','["今年病老遂難禁，二豎奔逃豈易尋。", "風雨三更僮僕睡，自持殘燭檢千金。"]'),
('54c9e3be-8e04-49fe-93ac-e19da246b025','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其三','陸游','宋','宋诗','song-poetry','','[]','窮銷壯歲功名志，病過新秋賞詠時。',32,'全唐诗/poet.song.136000.json','["窮銷壯歲功名志，病過新秋賞詠時。", "自古世間如意少，天公寧肯爲君私。"]'),
('01bec1db-c61e-43f5-9460-2e15aaef1b3f','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其四','陸游','宋','宋诗','song-poetry','','[]','小詩苦思憑誰賞，綠酒盈尊每獨傾。',32,'全唐诗/poet.song.136000.json','["小詩苦思憑誰賞，綠酒盈尊每獨傾。", "老境情悰例如此，不須惆悵感餘生。"]'),
('e1edbda4-7931-4951-a206-1c93b26be70b','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其五','陸游','宋','宋诗','song-poetry','','[]','一枕鳥聲殘曉夢，半窗竹影弄新晴。',32,'全唐诗/poet.song.136000.json','["一枕鳥聲殘曉夢，半窗竹影弄新晴。", "屏深室暖秋垂老，粥美蔬香疾漸平。"]'),
('b78740bf-6cfd-4e2f-94ed-584ad5d4aa63','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其六','陸游','宋','宋诗','song-poetry','','[]','半饑半飽隨時過，無客無書盡日閑。',32,'全唐诗/poet.song.136000.json','["半饑半飽隨時過，無客無書盡日閑。", "童子貪眠呼不省，狸奴戀暖去仍還。"]'),
('f203a884-a23e-4bc1-be2a-e7d463f86a30','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其七','陸游','宋','宋诗','song-poetry','','[]','粥香可愛貧方覺，睡味無窮老始知。',32,'全唐诗/poet.song.136000.json','["粥香可愛貧方覺，睡味無窮老始知。", "要識放翁真受用，大冠長劍只成癡。"]'),
('eb36d0d6-c1ad-4241-9e0d-06bed279f937','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其八','陸游','宋','宋诗','song-poetry','','[]','小詩閑淡如秋水，病後殊勝未病時。',32,'全唐诗/poet.song.136000.json','["小詩閑淡如秋水，病後殊勝未病時。", "自翦矮箋謄斷稿，不嫌墨淺字傾欹。"]'),
('13b4221d-447b-4e23-8482-b9f4fa210594','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其九','陸游','宋','宋诗','song-poetry','','[]','八月吳中風露秋，子鵝可炙酒新篘。',32,'全唐诗/poet.song.136000.json','["八月吳中風露秋，子鵝可炙酒新篘。", "老人病愈鄉閭喜，處處邀迎共獻酬。"]'),
('a1480a0c-6ed5-421b-bae9-3a4d7fe1e96d','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','清泉白米山家有，鹽酪猶從小市求。',32,'全唐诗/poet.song.136000.json','["清泉白米山家有，鹽酪猶從小市求。", "寸步須扶本常事，細書妨讀却閑愁。"]'),
('8aca4807-cb8d-49aa-a819-de41cacbb0ea','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','束書不觀萬事休，誰令識字惹閑愁。',32,'全唐诗/poet.song.136000.json','["束書不觀萬事休，誰令識字惹閑愁。", "胸中作祟知何物，不是當年老督郵。"]'),
('3a81123f-e391-425a-a811-5731ff59be6f','嘉定己巳立秋得膈上疾近寒露乃小愈十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','客疾無根莫浪憂，今朝掃盡不容留。',32,'全唐诗/poet.song.136000.json','["客疾無根莫浪憂，今朝掃盡不容留。", "飯囊酒甕非吾事，只貯千巖萬壑秋。"]'),
('33541912-0dfd-4b93-aed2-4b700cf0a45d','病中卧聞舂聲二首  其一','陸游','宋','宋诗','song-poetry','','[]','丘嫂羹存先戛釜，山僧齋竟始鳴鐘。',32,'全唐诗/poet.song.136000.json','["丘嫂羹存先戛釜，山僧齋竟始鳴鐘。", "孰知造物獨憐我，一日未嘗無夕舂。"]'),
('36c67ff4-53b1-496c-9a2a-022b4897ffb3','病中卧聞舂聲二首  其二','陸游','宋','宋诗','song-poetry','','[]','妄想說梅猶止渴，真聞舂米固忘饑。',32,'全唐诗/poet.song.136000.json','["妄想說梅猶止渴，真聞舂米固忘饑。", "未論炊熟香生甑，已覺抄來雪滿匙。"]'),
('c16cfb5d-88ef-4a53-8de1-22980b289711','病小減復作三首  其一','陸游','宋','宋诗','song-poetry','','[]','一身真剩長，兩月抱沉綿。',48,'全唐诗/poet.song.136000.json','["一身真剩長，兩月抱沉綿。", "吟作楚人語，聳成山字肩。", "災從季主卜，藥欠宋清錢。", "彌老彌堪笑，藜羹且信緣。"]'),
('96e94949-f15d-42af-b6da-08cf1175f4ea','病小減復作三首  其二','陸游','宋','宋诗','song-poetry','','[]','衛養元無術，衰殘只自悲。',48,'全唐诗/poet.song.136000.json','["衛養元無術，衰殘只自悲。", "扶行十步地，强坐一炊時。", "枕藉漆園語，呻吟栗里詩。", "災年未易過，那敢望期頤。"]'),
('76b4c319-4be0-4a51-bbf3-858253cca39e','病小減復作三首  其三','陸游','宋','宋诗','song-poetry','','[]','晨粥半茶碗，秋衣一布裘。',48,'全唐诗/poet.song.136000.json','["晨粥半茶碗，秋衣一布裘。", "酒惟詩裏見，山向夢中遊。", "卜繇兒能測，藥方僧爲求。", "重陽無半月，尚泥菊花不。"]'),
('b2bfc171-22a1-49c7-a5ee-39591d18a659','病思六首  其一','陸游','宋','宋诗','song-poetry','','[]','水碓舂粳滑勝珠，地爐燔芋軟如酥。',32,'全唐诗/poet.song.136000.json','["水碓舂粳滑勝珠，地爐燔芋軟如酥。", "老來自愛盤餐美，安得高人共破除。"]'),
('020d9c32-bcb9-458e-a717-dcde5997cf83','病思六首  其二','陸游','宋','宋诗','song-poetry','','[]','殺物求君舌本肥，是非豈復待深思。',32,'全唐诗/poet.song.136000.json','["殺物求君舌本肥，是非豈復待深思。", "即今不足何時足，小甑香粳日兩炊。"]'),
('b524e127-7d60-4c01-870c-9a372598f5cb','病思六首  其三','陸游','宋','宋诗','song-poetry','','[]','江上秋風蘆荻聲，魚蝦日日厭煎烹。',32,'全唐诗/poet.song.136000.json','["江上秋風蘆荻聲，魚蝦日日厭煎烹。", "病來作意停鮮食，留得青錢買放生。"]'),
('02e9085e-4f00-4823-adce-0baa2acea942','病思六首  其四','陸游','宋','宋诗','song-poetry','','[]','行携馴鹿寄消搖，共飽山蔬與藥苗。',32,'全唐诗/poet.song.136000.json','["行携馴鹿寄消搖，共飽山蔬與藥苗。", "本自入山緣服玉，不應忘味待聞韶。"]'),
('58190201-24ca-4f05-b4d5-e98fc2d18854','病思六首  其五','陸游','宋','宋诗','song-poetry','','[]','西山雪外巢松客，南岳巖前洗鉢僧。',32,'全唐诗/poet.song.136000.json','["西山雪外巢松客，南岳巖前洗鉢僧。", "平日寄懷常在此，秋風剩欲辦行縢。"]'),
('16b9c860-74dd-429f-a39c-25b8d4f8411c','病思六首  其六','陸游','宋','宋诗','song-poetry','','[]','窗扉寂寂秋將晚，燈火昏昏夜向闌。',32,'全唐诗/poet.song.136000.json','["窗扉寂寂秋將晚，燈火昏昏夜向闌。", "不是暮年能耐病，道人心地本來寬。"]'),
('c04ea7a9-024f-4cb2-8d86-a1a38951f983','病中自遣三首  其一','陸游','宋','宋诗','song-poetry','','[]','孤燈如露螢，熠熠北窗下。',72,'全唐诗/poet.song.136000.json','["孤燈如露螢，熠熠北窗下。", "我亦氣僅屬，厭厭迫衰謝。", "平生更事熟，生死等晝夜。", "行年八十五，八十九已化。", "雖云病惱侵，處此亦閑暇。", "人扶時出門，清溪带茆舍。"]'),
('7336707d-f448-4833-b425-d80c662cd538','病中自遣三首  其二','陸游','宋','宋诗','song-poetry','','[]','一鴉振羽鳴，窗色忽已縞。',72,'全唐诗/poet.song.136000.json','["一鴉振羽鳴，窗色忽已縞。", "衆鳥次第來，各矜語言好。", "病夫正擁被，宛若兒在褓。", "跣婢職衣襦，丫童謹除掃。", "紅日已入簾，吾豈尚恨早。", "悠然一杯粥，頑鈍聊自保。"]'),
('8b89e57a-2d9d-4c92-9fd1-6466141d6365','病中自遣三首  其三','陸游','宋','宋诗','song-poetry','','[]','少時揣無才，一意守貧賤。',72,'全唐诗/poet.song.136000.json','["少時揣無才，一意守貧賤。", "窮閻依馬磨，小石寫馿券。", "中年更可笑，憔悴客異縣。", "何曾得一飽，塵土空滿面。", "即今况已病，百衰相俱見。", "雖然亦自重，未忍悲秋扇。"]'),
('1529722b-709b-454e-bef3-994b96351cfd','八月二十三夜夢中作','陸游','宋','宋诗','song-poetry','','[]','道士上天鶴一隻，老僧住庵雲半間。',64,'全唐诗/poet.song.136000.json','["道士上天鶴一隻，老僧住庵雲半間。", "去來盡向無心得，癡黠相除到處閑。", "江山千里互明晦，魚鳥十年相往還。", "高巖縹緲人不到，醉中爲子題其顔。"]'),
('8022d40e-fdc9-49cb-ae21-cf49fba17198','病少間作','陸游','宋','宋诗','song-poetry','','[]','身如水有漚，病如雲無根。',120,'全唐诗/poet.song.136000.json','["身如水有漚，病如雲無根。", "方其未散間，妄謂有我存。", "漚壞水渺然，雲滅寧遺痕。", "回首乃可笑，妄想生怨恩。", "念我曩昔時，一笏朝帝閽。", "既老復何爲，釣魚石帆村。", "今年病卧久，慘痛不可言。", "一念忽超詣，二豎皆忙奔。", "吾居本廣大，談笑决其藩。", "還持一尊酒，往酹湘水魂。"]'),
('1602a3d9-7584-485b-a448-f58c6eb802f1','秋晚幽居','陸游','宋','宋诗','song-poetry','','[]','吳中秋晚氣猶和，疾豎其如此老何。',64,'全唐诗/poet.song.136000.json','["吳中秋晚氣猶和，疾豎其如此老何。", "鳥語漸稀人睡美，木陰初薄夕陽多。", "掃園日日成幽趣，撫枕時時亦浩歌。", "車轍久空君勿嘆，文殊自解問維摩。"]'),
('00ce565a-fb91-4911-b07e-c0a96da7412d','病中思出遊','陸游','宋','宋诗','song-poetry','','[]','病境雖猶在，秋天已自清。',48,'全唐诗/poet.song.136000.json','["病境雖猶在，秋天已自清。", "閑思尋酒伴，懶畏主詩盟。", "烟艇桐江去，籃輿剡縣行。", "會心隨處住，便足了餘生。"]'),
('40251a2e-1e83-4da3-b242-6805a69b5e59','九月初作','陸游','宋','宋诗','song-poetry','','[]','莫笑衡茆陋，幽情得細論。',48,'全唐诗/poet.song.136000.json','["莫笑衡茆陋，幽情得細論。", "客疏慚啜醢，僧熟認敲門。", "杳杳烟中剎，昏昏雨外村。", "登高負今歲，老病易消魂。"]'),
('8c30ddef-755b-405c-aff8-c12cc5f2ab27','四日夜鷄未鳴起作','陸游','宋','宋诗','song-poetry','','[]','放翁病過秋，忽起作醉墨。',48,'全唐诗/poet.song.136000.json','["放翁病過秋，忽起作醉墨。", "正如久蟄龍，青天飛霹靂。", "雖云墮怪奇，要勝常憫默。", "一朝此翁死，千金求不得。"]'),
('2a1558b1-7a9c-4f12-9a33-3de3e0222de7','卧病雜題五首  其一','陸游','宋','宋诗','song-poetry','','[]','㕮咀初成藥，咿啞半掩扉。',48,'全唐诗/poet.song.136000.json','["㕮咀初成藥，咿啞半掩扉。", "病知身健樂，閑覺宦遊非。", "小澗看猿飲，枯筇擁鶴歸。", "今朝更堪喜，書札得淮淝。"]'),
('bedf518c-2c7d-46b7-9177-2ee3aac5bd54','卧病雜題五首  其二','陸游','宋','宋诗','song-poetry','','[]','鷗鷺馴亭沼，琴書悅性靈。',48,'全唐诗/poet.song.136000.json','["鷗鷺馴亭沼，琴書悅性靈。", "身叨鄉祭酒，孫爲國添丁。", "烟浦收菰菜，秋山斸茯苓。", "虛名吾所薄，未應少微星。"]'),
('5a2a587b-e586-4089-a181-c9595cb87679','卧病雜題五首  其三','陸游','宋','宋诗','song-poetry','','[]','陋室施床迮，窮閻問疾疏。',48,'全唐诗/poet.song.136000.json','["陋室施床迮，窮閻問疾疏。", "加餐惟是粥，弄筆不成書。", "盎盎新篘酒，青青小摘蔬。", "客來邀褫带，聊示小勤渠。"]'),
('9a5b67d2-f1ed-4042-a610-2a2a0a7e66d4','卧病雜題五首  其四','陸游','宋','宋诗','song-poetry','','[]','終日常辭客，經秋半在床。',48,'全唐诗/poet.song.136000.json','["終日常辭客，經秋半在床。", "愛窮留作伴，諳病與相忘。", "竈婢工烹粥，園丁習寫方。", "今朝有奇事，久雨得窗光。"]'),
('0d21ae52-71cd-421b-89c1-efb346c1a49a','卧病雜題五首  其五','陸游','宋','宋诗','song-poetry','','[]','人間跛男子，物外病維摩。',48,'全唐诗/poet.song.136000.json','["人間跛男子，物外病維摩。", "但可妨趨拜，何因廢嘯歌。", "菜羹醯醤薄，村巷棘茨多。", "舉手謝鄰父，非君誰肯過。"]'),
('997843be-f0dc-43ca-b0e0-109e487a3c0f','讀華佗傳','陸游','宋','宋诗','song-poetry','','[]','六籍雖殘聖道醇，中更秦火不成塵。',32,'全唐诗/poet.song.136000.json','["六籍雖殘聖道醇，中更秦火不成塵。", "華佗老黠徒驚俗，吾豈無書可活人。"]'),
('fc17fa1b-7b5d-4e21-83bb-8140f7e9d93d','家山','陸游','宋','宋诗','song-poetry','','[]','鹿食苹時猶命侶，鶴沖霄後尚思歸。',32,'全唐诗/poet.song.136000.json','["鹿食苹時猶命侶，鶴沖霄後尚思歸。", "家山不忍何山隠，稽首虛空懺昨非。"]'),
('9b77168b-6ffe-4ee0-91b6-d64a1bae09b3','九月十一日疾小間夜賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','清夜房櫳燈火微，此心病起更依依。',64,'全唐诗/poet.song.136000.json','["清夜房櫳燈火微，此心病起更依依。", "空驚床下莎蟲語，不見梁間巢燕歸。", "蒼硯有池殘墨在，白頭不櫛亂書圍。", "可憐未遽忘風月，猶夢華觴插羽飛。"]'),
('1d9ed769-fb49-41f5-ab5c-0d60b314ceb4','九月十一日疾小間夜賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','病後衣巾盡覺寬，挈提裘領喟然嘆。',64,'全唐诗/poet.song.136000.json','["病後衣巾盡覺寬，挈提裘領喟然嘆。", "孤燈不焰熒熒碧，小雨無聲慘慘寒。", "只道清心災自退，豈知非意病相干。", "平生最愛秋搖落，惆悵今年怯倚欄。"]'),
('df9c2ebc-4c4d-4896-a639-9f0ec91a0dd9','一病七十日','陸游','宋','宋诗','song-poetry','','[]','一病七十日，共疑無復生。',48,'全唐诗/poet.song.136000.json','["一病七十日，共疑無復生。", "堤全河漸復，師濟寇將平。", "縹緲香雲散，颼飀藥鼎鳴。", "庭前有殘菊，自笑尚關情。"]'),
('c33d9a90-a792-4b42-acc4-912d9e2576cc','西郊','陸游','宋','宋诗','song-poetry','','[]','七十辭北闕，五畝寄西郊。',48,'全唐诗/poet.song.136000.json','["七十辭北闕，五畝寄西郊。", "泳水魚依藻，摩雲鶴結巢。", "丐僧時問疾，卜叟或論交。", "社櫟天全汝，寧當嘆繫匏。"]'),
('aa3bfd1c-e567-4fdc-957d-7b1a02f2a72a','蔬食','陸游','宋','宋诗','song-poetry','','[]','肉食從來意自疑，齋盂况與病相宜。',64,'全唐诗/poet.song.136000.json','["肉食從來意自疑，齋盂况與病相宜。", "老羝昔作春蔬祟，斷稿今無晚釣詩。", "陌上烟苕誰采采，牆陰風葉正離離。", "人生饑飽初何校，一斛檳榔笑汝癡。"]'),
('f23587a2-194a-4098-b2ba-5704587340b4','乙巳秋暮獨酌四首  其一','陸游','宋','宋诗','song-poetry','','[]','孤雲繫不定，野鶴籠難馴。',72,'全唐诗/poet.song.136000.json','["孤雲繫不定，野鶴籠難馴。", "賣藥句曲秋，沽酒天台春。", "中原幾流血，四海一閑人。", "邀月對我影，折花插我巾。", "花月成三友，江海爲四鄰。", "何敢忘吾君，巢由稱外臣。"]'),
('9e511295-4d05-43be-a4da-60d2555bb8e9','乙巳秋暮獨酌四首  其二','陸游','宋','宋诗','song-poetry','','[]','安期與羨門，秦漢迹已陳。',60,'全唐诗/poet.song.136000.json','["安期與羨門，秦漢迹已陳。", "不如東平公，一劍隠紅塵。", "醉歌題市樓，墨色粲如新。", "叱吒興風雲，約束山川神。", "從我者誰歟，夜渡黄鶴津。"]'),
('7f27b434-b35e-4048-9bb2-d758f9f1c2ed','乙巳秋暮獨酌四首  其三','陸游','宋','宋诗','song-poetry','','[]','山陰老道士，寄情魚鳥中。',48,'全唐诗/poet.song.136000.json','["山陰老道士，寄情魚鳥中。", "幽戶綠蘿月，孤舟白蘋風。", "豈無小甕熟，尊杓誰與同。", "邂逅得知心，一見嘆猶龍。"]'),
('c079659f-f1f2-450d-a5e9-3d3465586770','乙巳秋暮獨酌四首  其四','陸游','宋','宋诗','song-poetry','','[]','湖中有隠士，或謂千歲人。',48,'全唐诗/poet.song.136000.json','["湖中有隠士，或謂千歲人。", "大兒嚴子陵，小兒賀季真。", "姓名莫能知，况可得疏親。", "有竿不釣魚，秋晚香粳新。"]'),
('994952c4-72ab-41df-bb7e-49e7fccefbbb','秋晚','陸游','宋','宋诗','song-poetry','','[]','春將愁並至，秋與病相終。',48,'全唐诗/poet.song.136000.json','["春將愁並至，秋與病相終。", "過望猶賒死，扶衰又入冬。", "撥香開社甕，带睡聽晨鐘。", "懶放君無誚，天公儘見容。"]'),
('e02d3a5e-1fff-4d5f-a410-e429fc5e24be','病中遣懷六首  其一','陸游','宋','宋诗','song-poetry','','[]','人生長短無百歲，八十五年行九分。',32,'全唐诗/poet.song.136000.json','["人生長短無百歲，八十五年行九分。", "堪笑癡翁作黠計，欲將繩子繫浮雲。"]'),
('1b8406f6-9d12-4e44-9e6f-dcf3ee15c275','病中遣懷六首  其二','陸游','宋','宋诗','song-poetry','','[]','放生何足爲愛物，施藥因行聊結緣。',32,'全唐诗/poet.song.136000.json','["放生何足爲愛物，施藥因行聊結緣。", "山舍老翁無事業，只將閑事占流年。"]'),
('acf06994-873c-4411-8e1b-17e38a867d9c','病中遣懷六首  其三','陸游','宋','宋诗','song-poetry','','[]','鮮肥莫事膚寸舌，蕭散何辜七尺軀。',32,'全唐诗/poet.song.136000.json','["鮮肥莫事膚寸舌，蕭散何辜七尺軀。", "山路豈無孤店宿，渡頭亦有小舟呼。"]'),
('dcb2fef8-6352-40b3-92dd-6d4bd78dfee8','病中遣懷六首  其四','陸游','宋','宋诗','song-poetry','','[]','家貧不與身添業，病久寧非天儆予。',32,'全唐诗/poet.song.136000.json','["家貧不與身添業，病久寧非天儆予。", "掃盡世間閑忿慾，小園烟雨種春蔬。"]'),
('f6a1e1a1-59aa-43f3-841e-b233deb0eadb','病中遣懷六首  其五','陸游','宋','宋诗','song-poetry','','[]','菘芥煮羹甘勝蜜，稻粱炊飯滑如珠。',32,'全唐诗/poet.song.136000.json','["菘芥煮羹甘勝蜜，稻粱炊飯滑如珠。", "上方香積寧過此，慚愧天公養病夫。"]'),
('32f55ac8-c32c-4263-bc94-5d6678c2b496','病中遣懷六首  其六','陸游','宋','宋诗','song-poetry','','[]','開皺紫栗如拳大，带葉黄柑染袖香。',32,'全唐诗/poet.song.136000.json','["開皺紫栗如拳大，带葉黄柑染袖香。", "天與山家講鄰好，江天昨夜有新霜。"]'),
('77875696-fc02-4c7a-9884-0c254618e4d4','六言二首  其一','陸游','宋','宋诗','song-poetry','','[]','滿帽秋風入剡，半帆寒日遊吳。',28,'全唐诗/poet.song.136000.json','["滿帽秋風入剡，半帆寒日遊吳。", "問子行裝何在，带間笑指葫蘆。"]'),
('2b2c410e-3878-4b77-894f-ed746acd1d2b','六言二首  其二','陸游','宋','宋诗','song-poetry','','[]','不慕生爲柱國，何須死向揚州。',28,'全唐诗/poet.song.136000.json','["不慕生爲柱國，何須死向揚州。", "但願此身無病，天台剡縣閑遊。"]'),
('9866c0e3-c36a-4b6a-b1b2-0c753c57dd35','野興','陸游','宋','宋诗','song-poetry','','[]','蓍草晨占大易爻，松肪夜借隠書抄。',64,'全唐诗/poet.song.136000.json','["蓍草晨占大易爻，松肪夜借隠書抄。", "饑時每就猿分果，宿處時從鶴寄巢。", "旋賣荆薪持取醉，偶逢野叟即論交。", "頹然坐閲人間事，耐辱禁愁却自嘲。"]'),
('76e5adf5-b1bf-464a-8ae5-f0b6c22ffc88','遠遊','陸游','宋','宋诗','song-poetry','','[]','壯年不作故山歸，老去方知浪走非。',64,'全唐诗/poet.song.136000.json','["壯年不作故山歸，老去方知浪走非。", "挂日片帆吳赤壁，嘶風疋馬蜀青衣。", "交遊雖廣知心少，香火徒勤願力微。", "堪笑只今成底事，青燈無恙且相依。"]'),
('0acc5906-001d-4d0b-bfb9-dc1e396f8f7e','反遠遊','陸游','宋','宋诗','song-poetry','','[]','賣却貂裘買釣舟，久將身世付悠悠。',64,'全唐诗/poet.song.136000.json','["賣却貂裘買釣舟，久將身世付悠悠。", "行歌西郭紅橋路，爛醉東關白塔秋。", "夜泊驛亭觀月上，曉登僧閣聽猿愁。", "一生身屬官倉米，剩喜殘年得自由。"]'),
('950cea9b-efa1-4843-af19-4c3c296c2a06','病著','陸游','宋','宋诗','song-poetry','','[]','病著今年劇，衰來次第新。',48,'全唐诗/poet.song.136000.json','["病著今年劇，衰來次第新。", "茅茨安久處，芻豢罷前陳。", "零落閑邊句，逍遥事外身。", "村東褚草蕈，一笑得常珍。"]'),
('4cc7d424-db63-470f-85a2-7b9b7d8e1c9f','梅市','陸游','宋','宋诗','song-poetry','','[]','小雨長堤古寺西，不容羸馬惜障泥。',64,'全唐诗/poet.song.136000.json','["小雨長堤古寺西，不容羸馬惜障泥。", "時平道路鈴聲少，歲樂坊場酒價低。", "烟樹淺深山驛近，野歌斷續客魂迷。", "殘軀不料重來此，一首清詩手自題。"]'),
('05ee4b3e-244d-4ba1-abb1-6f715c312e22','梅市書事','陸游','宋','宋诗','song-poetry','','[]','羸馬孤愁不可勝，小詩未忍付瞢騰。',32,'全唐诗/poet.song.136000.json','["羸馬孤愁不可勝，小詩未忍付瞢騰。", "一聲客枕江頭雁，數點商船雨外燈。"]'),
('a4ddc4aa-69db-44db-9e4f-63ba44d431c1','病減','陸游','宋','宋诗','song-poetry','','[]','病減停湯熨，身衰頼按摩。',48,'全唐诗/poet.song.136000.json','["病減停湯熨，身衰頼按摩。", "書虧平日課，睡比故年多。", "龜卜占休泰，醫方校闕訛。", "有時還一笑，隔浦起漁歌。"]'),
('3ca059ff-163d-4379-a55e-849c7bd5a1c8','幽居即事二首  其一','陸游','宋','宋诗','song-poetry','','[]','山崦可伐薪，稻隴可負耒。',72,'全唐诗/poet.song.136000.json','["山崦可伐薪，稻隴可負耒。", "但令二事集，一飽已有在。", "霜林兩株橘，春圃數畦菜。", "仁哉造物心，乞我曾不愛。", "炊烹付樵青，鉏灌頼阿對。", "乃翁亦自爲，高枕聽晨碓。"]'),
('9757d39e-cd32-415b-af69-6b71fdb825eb','幽居即事二首  其二','陸游','宋','宋诗','song-poetry','','[]','書几積流塵，硯池漬淺墨。',72,'全唐诗/poet.song.136000.json','["書几積流塵，硯池漬淺墨。", "老夫自省事，童子豈不力。", "人生適可爾，過計亦何得。", "胡爲棄梨棗，日夜長荆棘。", "洗汝侈汰心，去汝驕吝色。", "一菜飽有餘，奚取萬錢食。"]'),
('0e9920dd-5309-449b-8636-cd82db2f06d1','羸疾','陸游','宋','宋诗','song-poetry','','[]','羸疾止還作，已過秋暮時。',48,'全唐诗/poet.song.136000.json','["羸疾止還作，已過秋暮時。", "但當名百藥，那更謁三醫。", "强飯幸如昨，清遊元有期。", "新霜宜野店，行矣不須疑。"]'),
('0817c315-4744-4e44-ba7a-5150ec360ae1','九月二十五日鷄鳴前起待旦','陸游','宋','宋诗','song-poetry','','[]','堪笑枯腸漸畏茶，夜闌坐起聽城笳。',64,'全唐诗/poet.song.136000.json','["堪笑枯腸漸畏茶，夜闌坐起聽城笳。", "爐溫自撥深培火，燈暗猶垂半結花。", "斷夢不妨尋枕上，孤愁還似客天涯。", "掃塵拾得殘詩稿，滿紙風鴉字半斜。"]'),
('29e6ba71-9701-4a47-9cdc-97bda821f693','秋夕排悶十韵','陸游','宋','宋诗','song-poetry','','[]','湖海雙歸棹，蓬蒿一病翁。',120,'全唐诗/poet.song.136000.json','["湖海雙歸棹，蓬蒿一病翁。", "幽居天鏡北，別墅石帆東。", "雲岫翩孤鶴，烟汀渺斷鴻。", "一從生白髮，幾見落丹楓。", "獨立中庭月，欹眠滿院蛩。", "藜羹晨糝白，葑火夜爐紅。", "物外緣雖薄，塵中念已空。", "放魚從長者，累塔伴群童。", "野寺觀冬懺，叢祠禱歲豐。", "行歌與坐睡，處處現神通。"]'),
('7c2b2afe-980c-4725-9e7b-ae7bc4d83a9d','宴坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','氣住即存神，心安自保身。',48,'全唐诗/poet.song.136000.json','["氣住即存神，心安自保身。", "誰歟二豎子，卓爾一真人。", "氣泝如潮上，津流若酒醇。", "幽居幸無事，莫玩物華新。"]'),
('0dcd67ec-2645-45b7-8124-c6e26634baee','宴坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','周流惟一氣，天地與人同。',48,'全唐诗/poet.song.136000.json','["周流惟一氣，天地與人同。", "天道故不息，人爲斯有窮。", "蛟龍上雲雨，魚鳥困池籠。", "宴坐觀茲理，吾其若發蒙。"]'),
('4268a466-4683-4c99-86c7-7db6ee46f669','小室','陸游','宋','宋诗','song-poetry','','[]','術淺難醫忘，文疏不送窮。',48,'全唐诗/poet.song.136000.json','["術淺難醫忘，文疏不送窮。", "詩囊逢厄運，藥裹少新功。", "小室香凝碧，明窗日射紅。", "鄰翁來問疾，少話莫匆匆。"]'),
('ee570132-6cf4-44bc-a2f1-dfc4396a93dd','舟次浦口','陸游','宋','宋诗','song-poetry','','[]','吾孽本自作，此生元有涯。',48,'全唐诗/poet.song.136000.json','["吾孽本自作，此生元有涯。", "三江去浩蕩，一櫓任嘔啞。", "賣藥村村市，炊粳處處家。", "相逢喜亡恙，不敢厭喧譁。"]'),
('c3fe68f9-12af-463f-bf6b-e2bf453fd38b','開爐','陸游','宋','宋诗','song-poetry','','[]','餘疾三分在，閑愁一點無。',48,'全唐诗/poet.song.136000.json','["餘疾三分在，閑愁一點無。", "書能伴孫讀，身欲却人扶。", "霽日鴉鳴樂，清霜草蔓枯。", "南山送僧炭，隨事且開爐。"]'),
('df8c794e-b3d8-4c35-895e-bb934c4f2728','散懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','東行西行一日過，深酌淺酌萬事休。',32,'全唐诗/poet.song.136000.json','["東行西行一日過，深酌淺酌萬事休。", "亦知衣食將不繼，老甚安能懷百憂。"]'),
('5327b813-d458-435a-b740-fffb69aa49d1','散懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','中年絕慾不復念，今日肉食夫何難。',32,'全唐诗/poet.song.136000.json','["中年絕慾不復念，今日肉食夫何難。", "天公賦與本來薄，一概掃空方少安。"]'),
('29910aee-9411-47ac-85ca-32d6380b216e','子虡當以十月離淝上喜而有作','陸游','宋','宋诗','song-poetry','','[]','十月霜侵客子衣，片帆計已發淮淝。',64,'全唐诗/poet.song.136000.json','["十月霜侵客子衣，片帆計已發淮淝。", "山林獨往我何敢，州縣徒勞兒未非。", "傳舍方寒索調護，里門終日待來歸。", "解裝且共燈前語，萬事真當付一欷。"]'),
('72f561ef-44c7-4ed5-9155-cac9c67171bc','病來','陸游','宋','宋诗','song-poetry','','[]','抱疴雖可驗，應接每安徐。',48,'全唐诗/poet.song.136000.json','["抱疴雖可驗，應接每安徐。", "正使須彈塞，寧當快掃除。", "寡言方禍始，省事養災餘。", "一飽吾何欠，香粳薦美蔬。"]'),
('2f28267b-713d-4d9b-a722-7d91b608e723','舟中晨起','陸游','宋','宋诗','song-poetry','','[]','天宇清寒病體輕，烟波聊復事宵征。',64,'全唐诗/poet.song.136000.json','["天宇清寒病體輕，烟波聊復事宵征。", "櫓橫舟尾霜如抹，犬走籬根葉有聲。", "蕭尹威名空赫赫，班侯智略本平平。", "不如歸結迎神社，長笛圜鼙送此生。"]'),
('724998d3-2293-419d-a9c4-c19553828ef7','江村','陸游','宋','宋诗','song-poetry','','[]','江村連夜有飛霜，柿正丹時橘半黄。',64,'全唐诗/poet.song.136000.json','["江村連夜有飛霜，柿正丹時橘半黄。", "轉枕却尋驚斷夢，撥爐偶見爇殘香。", "醫無絕藝空三易，死與浮生已兩忘。", "拈得一書還懶看，卧聽孫子誦琅琅。"]'),
('115ed333-58b4-4801-aece-e25d96221d8d','兀兀','陸游','宋','宋诗','song-poetry','','[]','兀兀心非睡，惺惺口不言。',48,'全唐诗/poet.song.136000.json','["兀兀心非睡，惺惺口不言。", "齒津生頰舌，鼻息撼牆垣。", "書愧兒童問，年叨里巷尊。", "貧家有喜事，黍酒带醅渾。"]'),
('21648743-fc0e-406a-97b4-3319e37bdf94','道懷','陸游','宋','宋诗','song-poetry','','[]','織罷化吾梭，棋終爛汝柯。',48,'全唐诗/poet.song.136000.json','["織罷化吾梭，棋終爛汝柯。", "藥靈刀匕足，語妙立談多。", "楂浦吹橫笛，桐江買短蓑。", "白鷗真可友，萬里渺烟波。"]'),
('6054d0dd-adf3-482d-8383-e9988a0f336f','柯山道上作','陸游','宋','宋诗','song-poetry','','[]','道路如繩直，郊園似砥平。',48,'全唐诗/poet.song.136000.json','["道路如繩直，郊園似砥平。", "山爲翠螺踊，橋作彩虹明。", "午酌金丸橘，晨炊玉粒粇。", "江村好時節，及我疾初平。"]'),
('5f3dda01-b555-4a54-bc83-ba25049776a4','病後自詠','陸游','宋','宋诗','song-poetry','','[]','狂豪掃去得衰殘，數啜芳醪興亦闌。',64,'全唐诗/poet.song.136000.json','["狂豪掃去得衰殘，數啜芳醪興亦闌。", "閉戶交朋疏索盡，捐書日月破除難。", "盤除鮮食生蔬美，衣聳吟肩束带寬。", "頼有一條差自慰，高眠常到日三竿。"]'),
('a7bf145d-4750-404f-b6b1-c18e302e46bc','十月九日','陸游','宋','宋诗','song-poetry','','[]','酒開甕面撲人香，菊折霜餘滿把黄。',32,'全唐诗/poet.song.136000.json','["酒開甕面撲人香，菊折霜餘滿把黄。", "我是化工君信否，放遲一月作重陽。"]'),
('db356c77-433d-4192-8071-9e3e98d8f2f8','三三孫十月九日生日翁翁爲賦詩爲壽','陸游','宋','宋诗','song-poetry','','[]','正過重陽一月時，龜堂歡喜抱孫枝。',64,'全唐诗/poet.song.136000.json','["正過重陽一月時，龜堂歡喜抱孫枝。", "棄襦已足驚關吏，堆笏寧惟取世資。", "落筆千言猶細事，讀書萬卷要深期。", "汝翁豪傑非今士，不用擔簦更覓師。"]'),
('f41c76a2-46e0-4d10-999b-606b69a56561','江路','陸游','宋','宋诗','song-poetry','','[]','江路最初程，飄然兩屨輕。',48,'全唐诗/poet.song.136000.json','["江路最初程，飄然兩屨輕。", "少留雲際宿，徐待月明行。", "雁起平沙影，泉輕斷岸聲。", "誰知遊剡興，不減上青城。"]'),
('52f15a5e-87a0-45c3-a047-014f75f5f1e2','初冬二首  其一','陸游','宋','宋诗','song-poetry','','[]','落葉紛紛十月時，今年霜比去年遲。',64,'全唐诗/poet.song.136000.json','["落葉紛紛十月時，今年霜比去年遲。", "山猿引子飲幽澗，野鵲結巢爭墮枝。", "嶺北片雲生峭絕，橋東殘水漾淪漪。", "病衰自怪詩情盡，造物撩人乃爾奇。"]'),
('3449dea0-8b69-4eb1-be85-50ecd5612db8','初冬二首  其二','陸游','宋','宋诗','song-poetry','','[]','落葉窗前已作堆，地爐微火撥殘灰。',64,'全唐诗/poet.song.136000.json','["落葉窗前已作堆，地爐微火撥殘灰。", "夢中無祟敗蔬圃，飯後有歌誇芋魁。", "裊裊清笳催日晚，蕭蕭新雁带寒來。", "更寬十日可閑出，會挈一壺尋早梅。"]'),
('ae34ea41-68f7-4c24-a18d-8b1e1fe847ec','夜坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','餠餌支遥夜，薪烝禦早寒。',48,'全唐诗/poet.song.136000.json','["餠餌支遥夜，薪烝禦早寒。", "卧聞風浩蕩，起視斗闌干。", "鷄怯飛霜重，鴉驚出月殘。", "挑燈搔短髮，顧影發吾嘆。"]'),
('0e595df7-232c-4e4d-aa57-fbab68b93183','夜坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','藥裹關心處，篝燈照影時。',48,'全唐诗/poet.song.136000.json','["藥裹關心處，篝燈照影時。", "文書用遮眼，棗栗可無饑。", "素業存農圃，頹齡迫耄期。", "蓋棺萬事已，唯負國恩私。"]'),
('6e886a45-13a0-48bd-b366-a7b9a2b49ec5','殘菊','陸游','宋','宋诗','song-poetry','','[]','殘菊一枝香未殘，夜窗拈起百回看。',32,'全唐诗/poet.song.136000.json','["殘菊一枝香未殘，夜窗拈起百回看。", "過時只恐難相笑，我是三朝舊史官。"]'),
('4cc47297-8029-4f7e-9303-a8910c0f75ab','久病','陸游','宋','宋诗','song-poetry','','[]','卧疾閲三時，冥冥不自持。',48,'全唐诗/poet.song.136000.json','["卧疾閲三時，冥冥不自持。", "婢諳曾製藥，犬識舊迎醫。", "質貸交親厭，呻吟里巷知。", "有時推枕起，清嘯尚能奇。"]'),
('77ca663c-f328-4ea1-a95b-361c413331fb','病小愈喜晴','陸游','宋','宋诗','song-poetry','','[]','雲邊采藥喜身輕，燈下觀書覺眼明。',64,'全唐诗/poet.song.136000.json','["雲邊采藥喜身輕，燈下觀書覺眼明。", "擾擾已空浮世事，依依還作苦吟聲。", "又爲天地幾年客，頓覺軒窗三日晴。", "深愧山童憐寂寞，風爐傳法煮蕪菁。"]'),
('0788efcf-dd1d-42e3-b242-f2b0f41fb3ee','租稅','陸游','宋','宋诗','song-poetry','','[]','占星起飯犢，待月出輸租。',48,'全唐诗/poet.song.136000.json','["占星起飯犢，待月出輸租。", "遇嶮頻呼侶，扶轅數戒奴。", "畏饑懷餠餌，愁雪備薪樗。", "意象今誰識，當年賦兩都。"]'),
('e220dc91-a352-40a2-97dc-f56dbb5c2f69','初寒','陸游','宋','宋诗','song-poetry','','[]','雨霽林猶滴，泥新路易乾。',48,'全唐诗/poet.song.136000.json','["雨霽林猶滴，泥新路易乾。", "蕭條山步晚，憔悴客衣單。", "小女收魚笱，童兒放鴨欄。", "初寒豈不好，衰病自無歡。"]'),
('a9d01fd2-be70-4912-a757-a89285208fe9','呻吟','陸游','宋','宋诗','song-poetry','','[]','呻吟半歲掩柴扉，性命惟存氣力微。',64,'全唐诗/poet.song.136000.json','["呻吟半歲掩柴扉，性命惟存氣力微。", "夙業豈能逃馬麥，窮居頼是慣牛衣。", "濁清且復分賢聖，今昨誰能論是非。", "一段光明君記取，要知無念是真歸。"]'),
('c1037f26-0da2-4c57-a298-51816fb172ac','山墅','陸游','宋','宋诗','song-poetry','','[]','烟水烟林老結廬，人間用短更誰如。',64,'全唐诗/poet.song.136000.json','["烟水烟林老結廬，人間用短更誰如。", "軟蒲穩背供危坐，小幟障燈便細書。", "莫欺衰病歸山墅，曾領諸儒上石渠。", "貞觀開元嗟已遠，爲君試說紹興初。"]'),
('2b0011c6-241d-45d4-aaeb-7b7a7712fdd8','十月二十四日夜夢中送廬山道人歸山','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生不到三公府，晚歲歸來五老庵。',64,'全唐诗/poet.song.136000.json','["平生不到三公府，晚歲歸來五老庵。", "夙士極知成殿後，吾曹所頼作司南。", "孤舟夜泊灘聲惡，小甕晨香雪意酣。", "笑語床隅拄杖子，即今惟汝是同參。"]'),
('abaa8e6a-b8d1-4e3e-b3dc-e52d72f1f5f5','病後晨興食粥戲書','陸游','宋','宋诗','song-poetry','','[]','蝴蝶莊周安在哉，達人聊借作嘲詼。',32,'全唐诗/poet.song.136000.json','["蝴蝶莊周安在哉，達人聊借作嘲詼。", "不知此自隨緣住，更把晨窗粥幾杯。"]'),
('2d50f16b-d8f7-4dc0-bbf2-2c20ee35368a','贈僧二首  其一','陸游','宋','宋诗','song-poetry','','[]','松間數語淡交成，不喜將身世上行。',32,'全唐诗/poet.song.136000.json','["松間數語淡交成，不喜將身世上行。", "安得北窗風雪夜，地爐相對煮蕪菁。"]'),
('0d73afb3-9020-4b1b-a6f3-ddc90a74f878','贈僧二首  其二','陸游','宋','宋诗','song-poetry','','[]','長明燈下三更雨，旦過寮前萬里身。',32,'全唐诗/poet.song.136000.json','["長明燈下三更雨，旦過寮前萬里身。", "正使未能超佛祖，也應小勝市朝人。"]'),
('e66c5c5d-5c79-46b5-a445-622de432f9b3','遊山三首  其一','陸游','宋','宋诗','song-poetry','','[]','一生萬里著行縢，抖擻塵埃尚未能。',64,'全唐诗/poet.song.136000.json','["一生萬里著行縢，抖擻塵埃尚未能。", "不怕語音時带剡，敢辭生計略如僧。", "疏梅漸動清溪曲，霽雪遥看古塔層。", "喚起故年清絕夢，數聲柔櫓下巴陵。"]'),
('84569716-b50c-44f0-87f3-9bf2207fc660','遊山三首  其二','陸游','宋','宋诗','song-poetry','','[]','蕭然破帽伴枯藤，逢著青山不厭憎。',64,'全唐诗/poet.song.136000.json','["蕭然破帽伴枯藤，逢著青山不厭憎。", "家似江淮歸業戶，身如湖嶺罷參僧。", "煨柴夜宿寒爐火，洗釜晨敲古澗冰。", "果向此中能得趣，宦途捷徑不須曾。"]'),
('5c805c43-8201-4d96-b1e2-18a7c9cd85bc','遊山三首  其三','陸游','宋','宋诗','song-poetry','','[]','九十衰翁心尚孩，幅巾隨處一悠哉。',64,'全唐诗/poet.song.136000.json','["九十衰翁心尚孩，幅巾隨處一悠哉。", "偶扶拄杖登山去，却喚孤舟過渡來。", "酒市擁途觀嵬峨，僧廬借榻寄咍臺。", "吾生清絕煩君看，不枉人間夢一回。"]'),
('7e095c8f-99bc-4706-89c0-535337b815bb','農圃歌','陸游','宋','宋诗','song-poetry','','[]','我不如老農，占地畝一鍾。',144,'全唐诗/poet.song.136000.json','["我不如老農，占地畝一鍾。", "東作雖有時，力耕在茲冬。", "張燈觀夜織，高枕聽晨舂。", "時時喚鄰里，旨蓄亦可供。", "我不如老圃，父子日相從。", "一鉏萬事足，不求定遠封。", "春泥剪綠韭，秋雨畦青菘。", "放筯有餘味，豈不烹噞喁。", "乃者半年病，清鏡滿衰容。", "塵生一䩫屐，壁倚一枝筇。", "惟有呻吟聲，和合床下蛩。", "青燈照兀兀，布衲聊自縫。"]'),
('0bb9e6b0-c92b-4d8c-a8ce-5c683c8b276e','贈拄杖','陸游','宋','宋诗','song-poetry','','[]','歷險橫空捷有神，得來元自剡溪濱。',64,'全唐诗/poet.song.136000.json','["歷險橫空捷有神，得來元自剡溪濱。", "同爲萬里江湖客，共見三生風月身。", "不怕雲中伴鳬舄，只愁雨後長龍鱗。", "何妨更悟無生理，露柱燈籠一話新。"]'),
('865dc550-9028-4c97-a804-b8a1fc7a55d9','贈貓','陸游','宋','宋诗','song-poetry','','[]','執鼠無功元不劾，一簞魚飯以時來。',32,'全唐诗/poet.song.136000.json','["執鼠無功元不劾，一簞魚飯以時來。", "看君終日常安卧，何事紛紛去又回。"]'),
('8043c274-22eb-447f-a7d6-617fab791c32','宮詞','陸游','宋','宋诗','song-poetry','','[]','秋露蕭蕭洗秋月，夢斷陳宮白銀闕。',32,'全唐诗/poet.song.136000.json','["秋露蕭蕭洗秋月，夢斷陳宮白銀闕。", "臨春結綺底處所，回首已成狐兔穴。"]'),
('a5467809-306c-48a6-8e42-0c067b9b22b5','病中雜詠十首  其一','陸游','宋','宋诗','song-poetry','','[]','半年不讀書，顧影疑非我。',48,'全唐诗/poet.song.136000.json','["半年不讀書，顧影疑非我。", "乃知百年中，如此過亦可。", "書能作汝祟，識字果非福。", "明年倘未死，樂哉駕黄犢。"]'),
('fae34142-2a50-49fb-9f9c-d92a13c3e3d5','病中雜詠十首  其二','陸游','宋','宋诗','song-poetry','','[]','伐性無蛾眉，腐腸無旨酒。',48,'全唐诗/poet.song.136000.json','["伐性無蛾眉，腐腸無旨酒。", "齋居亦得疾，果無第一手。", "才不如嵇康，疏懶則過之。", "雖有絕交書，不作幽憤詩。"]'),
('798cbba5-dba0-4577-b150-fb33fb359a5f','病中雜詠十首  其三','陸游','宋','宋诗','song-poetry','','[]','華佗囊書久已焚，思邈玉函秘不聞。',64,'全唐诗/poet.song.136000.json','["華佗囊書久已焚，思邈玉函秘不聞。", "從醫火攻固下策，遣化飯香方普熏。", "觸人正自坐愚直，學道今當輸拙勤。", "勿言將智耄已及，後死或可與斯文。"]'),
('a89e5a8e-548e-4eba-9ad5-e04013fafee8','病中雜詠十首  其四','陸游','宋','宋诗','song-poetry','','[]','擊壤林間送此生，欣欣東作到西成。',64,'全唐诗/poet.song.136000.json','["擊壤林間送此生，欣欣東作到西成。", "泥深宿麥苗初長，葉落柔桑眼已生。", "枹鼓無聲盜衰息，文書簡出吏清平。", "西遊携得蹲鴟種，且共山家玉糝羹。"]'),
('0ffbb299-03b5-4ac4-970a-bde0f6ab34d8','病中雜詠十首  其五','陸游','宋','宋诗','song-poetry','','[]','身是人間一老樵，城南烟水寄迢迢。',64,'全唐诗/poet.song.136000.json','["身是人間一老樵，城南烟水寄迢迢。", "尋人偶到金家畯，取米時經杜浦橋。", "小市孤村鷄喔喔，斷山幽谷雨蕭蕭。", "吾曹自養無能爾，楚客應無隠可招。"]'),
('a09ea256-fbb8-4a5d-93f1-74536dc8bdf0','病中雜詠十首  其六','陸游','宋','宋诗','song-poetry','','[]','身似頭陀不出家，杜陵歸老有桑麻。',64,'全唐诗/poet.song.136000.json','["身似頭陀不出家，杜陵歸老有桑麻。", "茶煎小鼎初翻浪，燈映寒窗自結花。", "殘藥漸離愁境界，亂書重理淡生涯。", "等閑一事還超俗，斷紙題詩字亂斜。"]'),
('9f64c971-d3b9-4d68-89da-d3b98fa642c3','病中雜詠十首  其七','陸游','宋','宋诗','song-poetry','','[]','天遠不可問，將如此老何。',48,'全唐诗/poet.song.136000.json','["天遠不可問，將如此老何。", "老驚詩思退，貧欠藥錢多。", "剡縣尋僧宿，桐江買酒歌。", "市橋新柳色，又是一年過。"]'),
('edad0cfd-b84d-4136-ab5e-1ef24fbafc93','病中雜詠十首  其八','陸游','宋','宋诗','song-poetry','','[]','半黄半綠柳滿城，欲開未開梅有情。',32,'全唐诗/poet.song.136000.json','["半黄半綠柳滿城，欲開未開梅有情。", "放翁一病又百日，回視新春如隔生。"]'),
('944cf1c7-8c1f-4f5d-8cc0-f18f06c566fc','病中雜詠十首  其九','陸游','宋','宋诗','song-poetry','','[]','久病身猶困，閑遊性已成。',48,'全唐诗/poet.song.136000.json','["久病身猶困，閑遊性已成。", "未停湯熨事，即理水雲程。", "投宿忘街陌，論交失姓名。", "醉憐花塢好，恐是牡丹坪。"]'),
('55340588-c35f-4b3e-aa9b-a9c597886578','病中雜詠十首  其一○','陸游','宋','宋诗','song-poetry','','[]','自我居湖曲，漁樵日往來。',48,'全唐诗/poet.song.136000.json','["自我居湖曲，漁樵日往來。", "只知年屢改，不覺老相催。", "小浦潮痕長，長堤草色回。", "逢春心自在，莫道已成灰。"]'),
('6c032811-f563-4517-8a58-34a5f1697a21','雪','陸游','宋','宋诗','song-poetry','','[]','一夕山陰道，真成白玉京。',24,'全唐诗/poet.song.136000.json','["一夕山陰道，真成白玉京。", "衰殘失壯觀，擁被聽窗聲。"]'),
('c828f05e-3cae-4f2f-a23f-d6571346b0fb','自笑','陸游','宋','宋诗','song-poetry','','[]','左車第二牙辭去，團坐無生話又新。',32,'全唐诗/poet.song.136000.json','["左車第二牙辭去，團坐無生話又新。", "堪笑按摩并洗沐，未忘貪愛夢中身。"]'),
('4c597b9e-431f-4565-a88e-edc4fca1b3b5','絕句','陸游','宋','宋诗','song-poetry','','[]','山遮水隔重重堠，雨練風柔處處花。',32,'全唐诗/poet.song.136000.json','["山遮水隔重重堠，雨練風柔處處花。", "一病半年能不死，又將此恨醉天涯。"]'),
('62cc39a0-32c4-4c35-bd80-049a80653995','題藥囊','陸游','宋','宋诗','song-poetry','','[]','殘暑纔屬爾，新春還及茲。',48,'全唐诗/poet.song.136000.json','["殘暑纔屬爾，新春還及茲。", "真當名百藥，何止謁三醫。", "半夜暾朝日，晨興飲上池。", "金丹有門戶，草木爾何知。"]'),
('c38e500c-2487-495f-a13d-3eb4374b5fcd','末題二首  其一','陸游','宋','宋诗','song-poetry','','[]','平日尤閑老更閑，一毫世事豈相關。',64,'全唐诗/poet.song.136000.json','["平日尤閑老更閑，一毫世事豈相關。", "孤雲不散來歸岫，細水無聲自出山。", "支徑過僧纔百步，小樓藏藥可三間。", "客來不肯通名姓，熟視吾廬爲破顔。"]'),
('7ad2e5a4-6960-4406-9ce5-4714dcc99031','末題二首  其二','陸游','宋','宋诗','song-poetry','','[]','一身只付鷄棲上，萬卷真藏椰子中。',32,'全唐诗/poet.song.136000.json','["一身只付鷄棲上，萬卷真藏椰子中。", "嘉定三年正月後，不知幾度醉春風。"]'),
('acc8f18e-7adc-4ba8-9b18-5c867d3d68db','病中示兒輩','陸游','宋','宋诗','song-poetry','','[]','去去生方遠，冥冥死即休。',48,'全唐诗/poet.song.136000.json','["去去生方遠，冥冥死即休。", "狂思攘鬼手，危至服丹頭。", "有劍知誰與，無香可得留。", "惟應勤學謹，事事鑒恬侯。"]'),
('457ed84b-bbc2-4761-91a1-dd098a2c1cb2','夢中行荷花萬頃中','陸游','宋','宋诗','song-poetry','','[]','天風無際路茫茫，老作月王風露郎。',32,'全唐诗/poet.song.136000.json','["天風無際路茫茫，老作月王風露郎。", "只把千尊爲月俸，爲嫌銅臭雜花香。"]'),
('785fbae0-bf51-4ad6-adf1-b74a69a32d81','示兒','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u5fe7\u56fd\u5fe7\u6c11", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','死去元知萬事空，但悲不見九州同。',32,'全唐诗/poet.song.136000.json','["死去元知萬事空，但悲不見九州同。", "王師北定中原日，家祭無忘告乃翁。"]'),
('ca2bdb34-53f7-4860-b892-c67e950e16fd','送李舍人赴闕','陸游','宋','宋诗','song-poetry','','[]','執簡曾聞侍玉螭，謫仙才調盡推奇。',64,'全唐诗/poet.song.136000.json','["執簡曾聞侍玉螭，謫仙才調盡推奇。", "能將苦語康時病，更遣丹誠動主思。", "北闕親朋瞻舊德，東吳山水入新詩。", "知公自有經綸術，會見飛翔集鳳池。"]'),
('576ffab6-a56c-44c3-a5cc-8eb0a16174ff','大溪灘折柁  其一','陸游','宋','宋诗','song-poetry','','[]','溪流亂石似牛毛，雨過狂瀾勢轉豪。',32,'全唐诗/poet.song.136000.json','["溪流亂石似牛毛，雨過狂瀾勢轉豪。", "寄語河公莫作戲，從來忠信任風濤。"]'),
('ca6844d0-c22c-43ef-8a4f-391f024ac787','大溪灘折柁  其二','陸游','宋','宋诗','song-poetry','','[]','暮江初漲浪翻狂，一葉輕舟泛渺茫。',32,'全唐诗/poet.song.136000.json','["暮江初漲浪翻狂，一葉輕舟泛渺茫。", "我愧人非跛男子，安能與世作津梁。"]'),
('3865c59c-332b-474a-9889-ac8267e66d17','羅山平雲閣','陸游','宋','宋诗','song-poetry','','[]','上方高閣與雲齊，蠟屐穿雲步步躋。',64,'全唐诗/poet.song.136000.json','["上方高閣與雲齊，蠟屐穿雲步步躋。", "却恐此身生羽翼，不從平地作階梯。", "九門路接青霄近，四望山連碧海低。", "徙倚闌干重回首，疏林烟暝野猿啼。"]'),
('efac16ec-5e8b-4394-b065-3b6c3d270fc7','中閣','陸游','宋','宋诗','song-poetry','','[]','萬仞仙山插太空，山腰依約見蓮宮。',64,'全唐诗/poet.song.136000.json','["萬仞仙山插太空，山腰依約見蓮宮。", "人寰隔絕無人到，洞府深沉有路通。", "石隙生雲埋柱礎，海光浮日映簾櫳。", "野僧齋罷憑闌久，千里秋毫入望中。"]'),
('80c09fa8-92f7-4313-a565-148946b5e83f','沖虛宮','陸游','宋','宋诗','song-poetry','','[]','林館松門白晝扃，參鸞人去已千齡。',64,'全唐诗/poet.song.136000.json','["林館松門白晝扃，參鸞人去已千齡。", "基存舊宅樓臺古，地有遺丹草木靈。", "滿洞曉雲春釀雨，一池秋水夜涵星。", "麻姑仙馭今何在，檻外孤峰晚更青。"]'),
('91737424-5193-4fe8-b3b2-21b9b287c4e1','羅浮山','陸游','宋','宋诗','song-poetry','','[]','十里山光翠障開，重遊何事意徘徊。',64,'全唐诗/poet.song.136000.json','["十里山光翠障開，重遊何事意徘徊。", "石樓自向雲中見，仙島誰知海上來。", "丹竈尚能含日月，龍潭還解起風雷。", "天涯爲郡空華髮，十二年間到兩回。"]'),
('a957153b-9172-467a-a233-a63f9038c732','寶積寺','陸游','宋','宋诗','song-poetry','','[]','偶來遊古寺，景逐眼前生。',48,'全唐诗/poet.song.136000.json','["偶來遊古寺，景逐眼前生。", "巖上高僧坐，林間野客行。", "望窮滄海遠，吟久暮雲平。", "此境真難到，登臨暫適情。"]'),
('dbc88e6b-ea17-4f82-845c-4ac4c3f78805','祈雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','折腰爲米顔常靦，負耒躬耕意自甘。',32,'全唐诗/poet.song.136000.json','["折腰爲米顔常靦，負耒躬耕意自甘。", "積谷千牛多骨相，年年禱雨到雲庵。"]'),
('94e2a30b-c634-491e-80fd-d43b9462f6fd','祈雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','至德無私不我欺，精祈未效莫輕疑。',32,'全唐诗/poet.song.136000.json','["至德無私不我欺，精祈未效莫輕疑。", "但令葵藿勤傾向，會有風雲感會時。"]'),
('45cd3875-34af-4a13-b299-e5ce44ed326a','秋日山居 晏起','陸游','宋','宋诗','song-poetry','','[]','年年睡債苦相關，好夢長隨苦角殘。',32,'全唐诗/poet.song.136000.json','["年年睡債苦相關，好夢長隨苦角殘。", "作意歸來償宿負，透窗遮莫已三竿。"]'),
('927035e4-b8cf-4214-bd26-450dc585c8b7','秋日山居 野步','陸游','宋','宋诗','song-poetry','','[]','漠漠秋園暮景孤，綸巾羽服從奚奴。',32,'全唐诗/poet.song.136000.json','["漠漠秋園暮景孤，綸巾羽服從奚奴。", "風流畫手無摩詰，寫作龍山野步圖。"]'),
('5a23e544-abe7-4192-8e96-39821558028f','秋日山居 午枕','陸游','宋','宋诗','song-poetry','','[]','茗碗兵休戒老兵，客來剝啄急須應。',32,'全唐诗/poet.song.136000.json','["茗碗兵休戒老兵，客來剝啄急須應。", "爲言余正理公事，半落烏紗枕曲肱。"]'),
('fc51858a-d157-45e8-84bd-67e06a6fed2d','秋日山居 夜坐','陸游','宋','宋诗','song-poetry','','[]','老懶開編早欠伸，强搔短髮照青熒。',32,'全唐诗/poet.song.136000.json','["老懶開編早欠伸，强搔短髮照青熒。", "齏鹽二十年前夢，尚想長廊撼夜鈴。"]'),
('c886e670-5496-48ca-bbbb-81aaddecf5dc','戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','颼颼松韵生魚眼，洶洶雲濤湧兔毫。',32,'全唐诗/poet.song.136000.json','["颼颼松韵生魚眼，洶洶雲濤湧兔毫。", "促膝細論同此味，絕勝痛飲讀離騷。"]'),
('ed06cbe9-26b7-4ee1-9a02-65bf09872b92','戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','束書舊隠棋巖下，慣碾春風傲北窗。',32,'全唐诗/poet.song.136000.json','["束書舊隠棋巖下，慣碾春風傲北窗。", "喚起□生塵土夢，頼君圭璧一雙雙。"]'),
('b7fa513f-36ba-48df-91f7-ba3460453bc5','戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','建苑誇豪如貴胄，棋巖晦迹類臞仙。',32,'全唐诗/poet.song.136000.json','["建苑誇豪如貴胄，棋巖晦迹類臞仙。", "倘憑閥閲定人物，耕野釣溪難自賢。"]'),
('d838eaf6-70c4-4624-92b9-af26eef44fe4','余邦英惠小山新芽作小詩三首以謝  其一','陸游','宋','宋诗','song-poetry','','[]','家園破社得鷹爪，舌本初參便到眉。',32,'全唐诗/poet.song.136000.json','["家園破社得鷹爪，舌本初參便到眉。", "忽喜雲腴來建苑，坐令渴肺生華滋。"]'),
('e77269cf-5fb6-4825-ad3b-8cad7b129b8c','余邦英惠小山新芽作小詩三首以謝  其二','陸游','宋','宋诗','song-poetry','','[]','正焙如觀詩大雅，小山當似變風論。',32,'全唐诗/poet.song.136000.json','["正焙如觀詩大雅，小山當似變風論。", "脫今風格不類古，終有先王禮義存。"]'),
('f0ea3055-5c69-4da4-9fd0-a7d0ee02d30c','余邦英惠小山新芽作小詩三首以謝  其三','陸游','宋','宋诗','song-poetry','','[]','平時共語不成些，癡坐空彫藜莧腸。',32,'全唐诗/poet.song.136000.json','["平時共語不成些，癡坐空彫藜莧腸。", "誰遣春風入牙頰，詩成忽带小山香。"]'),
('9412b4f3-4d4e-4646-8fac-304ded4a833f','寄彥成','陸游','宋','宋诗','song-poetry','','[]','交舊天涯曉宿稀，年來獨子付心期。',64,'全唐诗/poet.song.136000.json','["交舊天涯曉宿稀，年來獨子付心期。", "滿床文史對談處，萬里風霜並轡時。", "雨滴空階憐夜榻，吟牽芳草夢春池。", "合沙橋下東流水，雙鯉何時上釣絲。"]'),
('65b73c89-99f1-4cc8-9080-6f799d2b650b','榮歸','陸游','宋','宋诗','song-poetry','','[]','車馬填門撥不開，吾宗得雋凱歌回。',64,'全唐诗/poet.song.136000.json','["車馬填門撥不開，吾宗得雋凱歌回。", "折將蟾苑一枝桂，泛入萱堂百歲杯。", "雅望素欽山竦岳，芳名中占斗中魁。", "先登頼子光邦族，繼踵行看衮衮來。"]'),
('0262b35b-c97f-46d8-9421-e27f241cda96','翠微堂','陸游','宋','宋诗','song-poetry','','[]','萬頃青山只一溪，此中聊欲效真栖。',64,'全唐诗/poet.song.136000.json','["萬頃青山只一溪，此中聊欲效真栖。", "尋深巧被閑雲到，破靜時聞幽鳥啼。", "羞有卑功追管晏，慚無高節比夷齊。", "困眠饑食真吾事，寶篆香殘日又西。"]'),
('759057ef-3d1e-4423-9202-001728469d08','閑居七首  其一','陸游','宋','宋诗','song-poetry','','[]','小隠輕華屋，深山自結茅。',48,'全唐诗/poet.song.136000.json','["小隠輕華屋，深山自結茅。", "亂苔侵石磴，疏竹映花梢。", "泉瀨含清韵，風來慰淡交。", "閉門燒柏子，好把道書抄。"]'),
('754919ef-4db3-4d04-b3b0-644fd8ba6e23','閑居七首  其二','陸游','宋','宋诗','song-poetry','','[]','溪透桃源路，門連小華峰。',48,'全唐诗/poet.song.136000.json','["溪透桃源路，門連小華峰。", "虹霓橫水檻，羽蓋偃巖松。", "日月詩魂迥，烟霞道氣濃。", "欲尋鍾呂去，世外說從容。"]'),
('e088e082-788f-420d-b648-3ecdfb2e814d','閑居七首  其三','陸游','宋','宋诗','song-poetry','','[]','厨給胡麻粒，山供鹿脯盤。',48,'全唐诗/poet.song.136000.json','["厨給胡麻粒，山供鹿脯盤。", "掃門遲客至，入郭借書看。", "種竹添風韵，留松老歲寒。", "一生無別事，鷄犬戀劉安。"]'),
('3aeb1e50-59e2-4f2a-ab0d-bb7efd3c4799','閑居七首  其四','陸游','宋','宋诗','song-poetry','','[]','自得窮通樂，而無寵辱驚。',48,'全唐诗/poet.song.136000.json','["自得窮通樂，而無寵辱驚。", "韜光聊混俗，去知默陶情。", "毛竹蒼龍瘦，雲衣白鶴輕。", "時敲朝斗磬，林外玉聲清。"]'),
('8f50cc0b-6d69-489c-bd4f-a8bd4701931e','閑居七首  其五','陸游','宋','宋诗','song-poetry','','[]','野水明窗几，通渠繞屋流。',48,'全唐诗/poet.song.136000.json','["野水明窗几，通渠繞屋流。", "鷺衝烟織素，魚避月沉鈎。", "草閙蚊虻市，林昏蝙蝠秋。", "開懷覺清曠，萬象入冥搜。"]'),
('0e208b35-2f32-4b08-82ca-02673a969973','閑居七首  其六','陸游','宋','宋诗','song-poetry','','[]','生計淡無味，終焉樂有餘。',48,'全唐诗/poet.song.136000.json','["生計淡無味，終焉樂有餘。", "灌畦親抱甕，種秫學拈鋤。", "擇木翔歸鳥，臨淵聚戲魚。", "地偏心更遠，靖節愛吾廬。"]'),
('0afa96bf-c8b5-4e3d-be26-85603209eb43','閑居七首  其七','陸游','宋','宋诗','song-poetry','','[]','剪葉霜風勁，關門謝遠遊。',48,'全唐诗/poet.song.136000.json','["剪葉霜風勁，關門謝遠遊。", "深村梅映雪，前浦水明樓。", "蜜熟蜂衙放，羶殘蟻陣收。", "地爐無獸炭，炙背補衣裘。"]'),
('969abe89-25cc-4146-845b-73563ee9c3fd','夜坐','陸游','宋','宋诗','song-poetry','','[]','懷抱何蕭爽，凉風掃鬰蒸。',48,'全唐诗/poet.song.136000.json','["懷抱何蕭爽，凉風掃鬰蒸。", "寒蛩喧敗草，饑鼠囓枯藤。", "蝶入誰家夢，花殘半夜燈。", "無人論道德，長嘯愧孫登。"]'),
('28ef2883-43ff-413a-864a-d2fc4bddd3c1','新秋晚歸','陸游','宋','宋诗','song-poetry','','[]','玉粒嘗新稻，金風作好秋。',48,'全唐诗/poet.song.136000.json','["玉粒嘗新稻，金風作好秋。", "雁回沙漠信，蟬噪夕陽愁。", "立久雲生岫，歸遲月滿樓。", "吟餘露華冷，砧杵起江頭。"]'),
('4c54d2ae-ed3f-4ca8-9a40-abdbc7034d42','懷王美','陸游','宋','宋诗','song-poetry','','[]','理髮侵霜白，酡顔借酒紅。',48,'全唐诗/poet.song.136000.json','["理髮侵霜白，酡顔借酒紅。", "故人千里別，何日一樽同。", "魂夢徒勞蝶，音書不見鴻。", "抱琴雖有意，無語倚西風。"]'),
('84efe128-f076-4881-ad44-0ad0f2250122','感事','陸游','宋','宋诗','song-poetry','','[]','今古成何事，興亡迹已陳。',48,'全唐诗/poet.song.136000.json','["今古成何事，興亡迹已陳。", "干時無上策，避世且全真。", "就日思明主，看雲憶老親。", "到頭垂白早，徑醉曲生春。"]'),
('7d28638a-94c1-40fe-943d-793840ce78a6','客舍對梅','陸游','宋','宋诗','song-poetry','','[]','野迥林寒一水傍，密如疏蕊正商量。',64,'全唐诗/poet.song.136000.json','["野迥林寒一水傍，密如疏蕊正商量。", "半霜半雪相仍白，無蝶無蜂自在香。", "月過曉窗移影瘦，風傳殘角引聲長。", "還憐客路龍山下，未折一枝先斷腸。"]'),
('dcef0ffa-acd3-42b8-a43c-8a1bade7e452','春日','陸游','宋','宋诗','song-poetry','','[]','平生過眼萬芳菲，晚景收心與世違。',32,'全唐诗/poet.song.136000.json','["平生過眼萬芳菲，晚景收心與世違。", "枯槁形骸元自瘦，膏腴田土爲誰肥。"]'),
('7a95c400-2c64-447f-b831-39e36b9277aa','聞婆餠焦','陸游','宋','宋诗','song-poetry','','[]','黄泥嶺，松森森，幽鳥穿枝時一吟。',44,'全唐诗/poet.song.136000.json','["黄泥嶺，松森森，幽鳥穿枝時一吟。", "汝聲一何悲，汝語惻我心。", "連村麥熟餠餌香，我母九泉那得嘗。"]'),
('4ada2c33-d5a0-4d9b-afa4-645255a8bef6','種桑','陸游','宋','宋诗','song-poetry','','[]','孔明百畝桑，景略十具牛。',96,'全唐诗/poet.song.136000.json','["孔明百畝桑，景略十具牛。", "豈無子孫念，飽暖自可休。", "種桑吾廬西，微徑出南陌。", "三月葉暗園，四月葚可摘。", "戴勝枝上鳴，倉庚葉間飛。", "飛鳴各自得，人生胡不歸。", "歸家力農桑，慎莫愁貧賤。", "婚嫁就比鄰，死生長相見。"]'),
('7b97a58a-95f8-4946-89a9-39e1be8a207a','夜聞櫓聲','陸游','宋','宋诗','song-poetry','','[]','咿啞雙櫓聲，凄切遊子情。',36,'全唐诗/poet.song.136000.json','["咿啞雙櫓聲，凄切遊子情。", "豈無一杯酒，孤舟誰與傾。", "清愁不可耐，霜月照潮平。"]'),
('3c427fa1-279b-4297-8850-9160d35baecf','離家示妻子','陸游','宋','宋诗','song-poetry','','[]','明日當北征，竟夕起復眠。',120,'全唐诗/poet.song.136000.json','["明日當北征，竟夕起復眠。", "悲蟲號我傍，青燈照我前。", "婦憂衣裳薄，紉綫重敷綿。", "兒爲檢藥籠，桂薑手炮煎。", "墩堠默可數，一念已酸然。", "使憂能傷人，我得復長年。", "同生天壤間，人誰無一廛。", "傷哉獨何辜，皇皇長可憐。", "破屋不得住，風雨走道邊。", "呼天得聞否，賦與何其偏。"]'),
('1843d07c-cd08-4688-8196-2f15b2b3672b','黄山塔','陸游','宋','宋诗','song-poetry','','[]','風吹旗脚西南開，挂帆槌鼓何快哉。',64,'全唐诗/poet.song.136000.json','["風吹旗脚西南開，挂帆槌鼓何快哉。", "轉頭已失望夫石，黄山孤塔迎人來。", "黄山勸汝一杯酒，送往迎來殊耐久。", "明年我作故鄉歸，還對黄山一搔首。"]'),
('77124da1-e695-476d-af5b-fc672f64113d','送三兄赴奏邸','陸游','宋','宋诗','song-poetry','','[]','兄年十七弟始生，弟今白髮森千莖。',128,'全唐诗/poet.song.136000.json','["兄年十七弟始生，弟今白髮森千莖。", "所期相就畢此世，一尊濁酒得共傾。", "往年雖窮猶半菽，兩年糠覈苦不足。", "書生志欲及天下，貧賤不得收骨肉。", "過悲復恐兄意傷，忍涕不覺涕已滂。", "早朝霜露戒衣薄，願書此語歡或忘。", "閉門病衰百無用，日望兄歸有餘俸。", "早從丞相乞湖州，莫待異時思少游。"]'),
('7cbd4d9f-a4cc-4c14-8150-f5270f37224b','聞角','陸游','宋','宋诗','song-poetry','','[]','小閣柴門近，黄昏畫角聲。',48,'全唐诗/poet.song.136000.json','["小閣柴門近，黄昏畫角聲。", "時時逐風散，嫋嫋伴愁生。", "天地清秋暮，關河殘月明。", "湖南賊未破，獨立久含情。"]'),
('7d637393-d0af-4cfc-8941-623181f2d450','寄楊濟伯','陸游','宋','宋诗','song-poetry','','[]','聞道皇華使，來從萬里回。',48,'全唐诗/poet.song.136000.json','["聞道皇華使，來從萬里回。", "五溪春薺老，三峽暮猿哀。", "昔日文昌省，頻年灧澦堆。", "問君何地險，斟酌寄聲來。"]'),
('d97be8c0-eb5c-4fa5-954f-218d3adfb548','幽事','陸游','宋','宋诗','song-poetry','','[]','日日營幽事，時時有好懷。',48,'全唐诗/poet.song.136000.json','["日日營幽事，時時有好懷。", "雨園殘竹粉，風砌落松釵。", "伴蝶行花徑，聽蛙傍水涯。", "窮通了無謂，不必更安排。"]'),
('b39c56cc-8fef-4127-8ce1-1311515adc62','葺圃','陸游','宋','宋诗','song-poetry','','[]','種樹書頻讀，齊民術屢窺。',48,'全唐诗/poet.song.136000.json','["種樹書頻讀，齊民術屢窺。", "曾求竹醉日，更問柳眠時。", "盧橘初非橘，蒲葵不是葵。", "因而辨名物，甘作老樊遲。"]'),
('e7221940-1f03-496d-aed5-6aa0b8eebc71','幽事','陸游','宋','宋诗','song-poetry','','[]','幽事春來早，晨興即啟閽。',48,'全唐诗/poet.song.136000.json','["幽事春來早，晨興即啟閽。", "掃梁迎燕子，插楥護龍孫。", "數日招賓友，先期辦酒尊。", "淋漓衣袖濕，不管漬春痕。"]'),
('90104690-baf3-4f3f-95ee-835f2d8edfd8','北檻','陸游','宋','宋诗','song-poetry','','[]','北檻近中堂，緣階物自芳。',48,'全唐诗/poet.song.136000.json','["北檻近中堂，緣階物自芳。", "晨清花拱露，地僻蘚侵廊。", "坐久時開卷，吟餘或炷香。", "終朝無客至，一枕到羲皇。"]'),
('466f4a39-a6f2-41cd-9e47-0abc4d5562a4','寄姜梅山雷字詩','陸游','宋','宋诗','song-poetry','','[]','章臺官柳應宮槐，寶馬蹄輕不動埃。',64,'全唐诗/poet.song.136000.json','["章臺官柳應宮槐，寶馬蹄輕不動埃。", "只怪好詩無與敵，誰知古學有從來。", "江山常逐客帆遠，歲月不禁衙鼓催。", "剩約東林投凈社，高情千載有宗雷。"]'),
('16e28eec-7bb2-499a-af47-03480d9260be','采菊','陸游','宋','宋诗','song-poetry','','[]','秋花莫插鬢，雖好亦凄凉。',24,'全唐诗/poet.song.136000.json','["秋花莫插鬢，雖好亦凄凉。", "采菊還挼却，空餘滿袖香。"]'),
('9c30b364-9129-4b4d-9d9e-7eea0134e30c','吳娃曲  其一','陸游','宋','宋诗','song-poetry','','[]','滿地花陰不閉門，琵琶抱恨立黄昏。',32,'全唐诗/poet.song.136000.json','["滿地花陰不閉門，琵琶抱恨立黄昏。", "妾身不似天邊月，此夜此時重見君。"]'),
('c8a3ea76-cc16-467f-87f3-40994b7ce6ef','吳娃曲  其二','陸游','宋','宋诗','song-poetry','','[]','忘憂石榴深淺紅，草花紅紫亦成叢。',32,'全唐诗/poet.song.136000.json','["忘憂石榴深淺紅，草花紅紫亦成叢。", "明年開時不望見，只望郎君憶著儂。"]'),
('f62b250a-79b9-4b8d-bc10-b3b3940f141c','吳娃曲  其三','陸游','宋','宋诗','song-poetry','','[]','二月鏡湖水拍天，禹王廟下鬭龍船。',32,'全唐诗/poet.song.136000.json','["二月鏡湖水拍天，禹王廟下鬭龍船。", "龍船相似年年好，人自今年異去年。"]'),
('96ad4b0a-aaef-4c80-bc66-a6fe4589a9db','吳娃曲  其四','陸游','宋','宋诗','song-poetry','','[]','臂上燒香拜佛前，願郎安穩過新年。',32,'全唐诗/poet.song.136000.json','["臂上燒香拜佛前，願郎安穩過新年。", "多情已是長多病，莫要留心在妾邊。"]'),
('682ce92e-1344-4ec1-8d69-4d479f7dde19','過江至蕭山縣驛東軒海棠已謝','陸游','宋','宋诗','song-poetry','','[]','星星兩鬢怯年華，幽館無人江月斜。',32,'全唐诗/poet.song.136000.json','["星星兩鬢怯年華，幽館無人江月斜。", "惆悵過江留一夕，曉風吹盡海棠花。"]'),
('1e0d51e4-2e97-4bf5-924b-7f871089fdd1','崔伯易畫像贊','陸游','宋','宋诗','song-poetry','','[]','古之君子，學以爲己。',80,'全唐诗/poet.song.136000.json','["古之君子，學以爲己。", "可行則行，可止則止。", "仕以行義，止以遠恥。", "世衰道微，豈復知此。", "蚩蚩始學，青紫思拾。", "萬馬並馳，孰能獨立。", "始雖弗急，後亦汲汲。", "我思崔公，涕泗橫集。"]'),
('3d5c5b66-99a1-49db-bbf1-73a87c6f0bf5','東坡像贊','陸游','宋','宋诗','song-poetry','','[]','我遊鈞天，帝之所都。',60,'全唐诗/poet.song.136000.json','["我遊鈞天，帝之所都。", "是老先生，玉色敷腴。", "顧我而歎，閔世垢濁。", "笑謂侍僊，畀以靈藥。", "稽首徑歸，萬里天風。", "碧山巉然，月墮江空。"]'),
('fb15c50f-32b0-4938-9d2a-a838d45b2468','鍾離真人贊','陸游','宋','宋诗','song-poetry','','[]','五季之亂，方酣於兵。',40,'全唐诗/poet.song.136000.json','["五季之亂，方酣於兵。", "叱嗟風雲，卓乎人英。", "功雖不成，氣則莫奪。", "煌煌金丹，粃糠陶葛。"]'),
('534fc2bf-a916-4caf-b2df-b973693c430c','呂真人贊二首','陸游','宋','宋诗','song-poetry','','[]','一粒之粟，有國有民。',72,'全唐诗/poet.song.136000.json','["一粒之粟，有國有民。", "二升之釜，浩渺嶙峋。", "我遊巴陵，始識公面。", "青蛇鑑然，求之不見。", "天下家家畫呂公，衣冠顔鬢了無同。", "勸君莫被丹青誤，那有長繩可繫風。"]'),
('ee58aa09-c5c4-495e-954e-ecd8d9380372','僧師源畫觀音贊','陸游','宋','宋诗','song-poetry','','[]','三世如來同一鬨，大士亦作補陀夢。',64,'全唐诗/poet.song.136000.json','["三世如來同一鬨，大士亦作補陀夢。", "佛子無財可修供，尺紙寸毫俱妙用。", "寶纓天冠儼四衆，長年造極筆愈縱。", "唯師魯公爲作頌，十方世界俱震動。"]'),
('0df95a54-6654-4bd5-b810-325957e32245','宏智禪師真贊','陸游','宋','宋诗','song-poetry','','[]','死諸葛走生仲達，死姚崇賣生張說。',32,'全唐诗/poet.song.136000.json','["死諸葛走生仲達，死姚崇賣生張說。", "看渠臨了一著子，諸方倒退三十里。"]'),
('797c792d-89a5-40a8-9626-86e7d73a4c61','大慧禪師真贊','陸游','宋','宋诗','song-poetry','','[]','平生嫌遮老子，說法口巴巴地。',28,'全唐诗/poet.song.136000.json','["平生嫌遮老子，說法口巴巴地。", "若是靈利阿師，參取畫底妙喜。"]'),
('c16d6f0f-e72d-4ebb-ad55-9b7e7e84b271','萬庵禪師真贊','陸游','宋','宋诗','song-poetry','','[]','灑灑落落五十年，一句不說祖師禪。',32,'全唐诗/poet.song.136000.json','["灑灑落落五十年，一句不說祖師禪。", "妙喜堂中正法眼，等閑滅在瞎馿邊。"]'),
('c2a0ae4f-2aac-4d48-a119-12ab6ab0693c','塗毒策禪師真贊二首  其一','陸游','宋','宋诗','song-poetry','','[]','骨相瓌奇，風神蕭散。',39,'全唐诗/poet.song.136000.json','["骨相瓌奇，風神蕭散。", "貌肅而和，語盡而簡。", "畫得者英氣逼人，畫不得者頂門上一隻眼。"]'),
('cfebf9ae-1922-4b3f-901e-31bd1d06fe80','塗毒策禪師真贊二首  其二','陸游','宋','宋诗','song-poetry','','[]','塗毒不自讚，留待三山老。',40,'全唐诗/poet.song.136000.json','["塗毒不自讚，留待三山老。", "試問卿上人，讚好莫讚好。", "海中忽起劫初風，北斗柄折須彌倒。"]'),
('cef6184a-78ec-481d-8b71-9e046296d7d9','佛照禪師真贊','陸游','宋','宋诗','song-poetry','','[]','名動三朝，話行四海。',34,'全唐诗/poet.song.136000.json','["名動三朝，話行四海。", "撒手歸來，雲山不改。", "人言大覺同龕，師云老僧掩彩。"]'),
('3a233107-059a-4bc8-84a0-54236a70e8fb','大洪禪師贊','陸游','宋','宋诗','song-poetry','','[]','髮長無心剃，衣破無心補。',44,'全唐诗/poet.song.136000.json','["髮長無心剃，衣破無心補。", "大洪山上有賊，大洪山下有虎。", "非但白刃殺盡兒孫，更能一口吞却佛祖。"]'),
('3ce41967-3e7f-4d68-aef7-f5fb166a7d93','中巖圜老像贊','陸游','宋','宋诗','song-poetry','','[]','我遊中巖，拜師於床。',80,'全唐诗/poet.song.136000.json','["我遊中巖，拜師於床。", "巍巍堂堂，鳳舉龍驤。", "公住無爲，訪我成都。", "雄辯縱橫，玉色敷腴。", "別未十日，梁木告摧。", "我如飛蓬，萬里南來。", "孰謂窮山，乃瞻儀形。", "牆壁說法，况此丹青。"]'),
('7ba8d9fc-50d1-4868-8d21-0efdc7a244c9','奉聖淳山主年八十有四放翁爲作真贊','陸游','宋','宋诗','song-poetry','','[]','兩住名山一老禪，目光如電照人天。',32,'全唐诗/poet.song.136000.json','["兩住名山一老禪，目光如電照人天。", "行藏不用占蓍草，卦氣全來二十年。"]'),
('f998ec26-9474-4658-82fa-19809324f975','芋庵宗慧禪師真贊','陸游','宋','宋诗','song-poetry','','[]','煨懶殘芋，打塗毒鼓。',20,'全唐诗/poet.song.136000.json','["煨懶殘芋，打塗毒鼓。", "舌本雷霆，毫端風雨。"]'),
('b7c86738-9eba-4a64-a192-2da155cc74df','廣慧法師贊','陸游','宋','宋诗','song-poetry','','[]','東土震旦，西方極樂。',20,'全唐诗/poet.song.136000.json','["東土震旦，西方極樂。", "一緉草鞋，到處行脚。"]'),
('d6771b2d-faaf-4523-9d30-910f79f38d9d','敷凈人求僧贊','陸游','宋','宋诗','song-poetry','','[]','光薙頭，凈洗鉢，頭頭拈起頭頭活。',66,'全唐诗/poet.song.136000.json','["光薙頭，凈洗鉢，頭頭拈起頭頭活。", "有時與，有時奪，受用現前活鱍鱍。", "敷道者，一短褐，欠箇什麽更要惡水潑。", "將錯就錯也不妨，只在檀那輕手撥。"]'),
('d784e9c7-f742-4f19-b423-e2347678e8e4','錢道人贊','陸游','宋','宋诗','song-poetry','','[]','栟櫚冠，青芒屩，上天下天不騎鶴。',40,'全唐诗/poet.song.136000.json','["栟櫚冠，青芒屩，上天下天不騎鶴。", "喚作神仙渠不肯，道是凡人我又錯，會稽城中且賣藥。"]'),
('22432246-ffbb-4166-9f41-835d029bb611','放翁自贊四首  其一','陸游','宋','宋诗','song-poetry','','[]','遺物以貴吾身，棄智以全吾真。',76,'全唐诗/poet.song.136000.json','["遺物以貴吾身，棄智以全吾真。", "劍外江南，飄然幅巾。", "野鶴駕九天之風，澗松傲萬木之春。", "或以爲跌宕湖海之士，或以爲枯槁隴畝之民。", "二者之論雖不同，而不我知則均也。"]'),
('6876b82a-d455-4573-8b9f-36f34aeb9049','放翁自贊四首  其二','陸游','宋','宋诗','song-poetry','','[]','名動高皇，語觸秦檜。',40,'全唐诗/poet.song.136000.json','["名動高皇，語觸秦檜。", "身老空山，文傳海外。", "五十年間，死盡流輩。", "老子無才，山僧不會。"]'),
('041b15ec-6983-470b-9665-f6d0b52211b5','放翁自贊四首  其三','陸游','宋','宋诗','song-poetry','','[]','皮葛其衣，巢穴其居。',92,'全唐诗/poet.song.136000.json','["皮葛其衣，巢穴其居。", "烹不糝之藜羹，駕禿尾之草馿。", "聞雞而起，則和甯戚之牛歌。", "戴星而耕，則稽氾勝之農書。", "謂之瘁則若腴，謂之澤則若癯。", "雖不能草泥金之檢以紀治功，其亦可挾兔園之冊以教鄉閭者乎。"]'),
('03f2afa8-fcc5-4c94-8ced-948de7393fd7','放翁自贊四首  其四','陸游','宋','宋诗','song-poetry','','[]','進無以顯於時，退不能隠於酒。',63,'全唐诗/poet.song.136000.json','["進無以顯於時，退不能隠於酒。", "事刀筆不如小吏，把鋤犁不如健婦。", "或問陳子何取而肖其像，曰是翁也。", "腹容王導輩數百，胸吞雲夢者八九也。"]'),
('f602179b-e693-437a-8503-afc02499bc98','天申節致語口號三首  其一','陸游','宋','宋诗','song-poetry','','[]','宮殿紅雲捧紫皇，河清電繞擁休祥。',64,'全唐诗/poet.song.136000.json','["宮殿紅雲捧紫皇，河清電繞擁休祥。", "壺中常占青春在，物外方知浩劫長。", "晝立龍旗風不動，曉開瓊笈遠飄香。", "堯年豈特封人祝，動地驩聲遍萬方。"]'),
('681db179-0dc5-40a1-8eca-e4464cf36318','天申節致語口號三首  其二','陸游','宋','宋诗','song-poetry','','[]','廣殿遥聞警蹕音，觚稜曉色尚沈沈。',64,'全唐诗/poet.song.136000.json','["廣殿遥聞警蹕音，觚稜曉色尚沈沈。", "半空瑞靄爐香馥，一點紅雲黼座深。", "夷夏驩聲歸羽舞，乾坤和氣入薰琴。", "欲知聖德齊堯舜，遡闕爭傾萬國心。"]'),
('14b417b2-1672-4106-af09-80acc45eb747','天申節致語口號三首  其三','陸游','宋','宋诗','song-poetry','','[]','嘉會千齡豈易逢，珮聲俱集未央宮。',64,'全唐诗/poet.song.136000.json','["嘉會千齡豈易逢，珮聲俱集未央宮。", "九重鳳闕曈曨日，百尺龍旗掩苒風。", "奇瑞屢書圖牒上，太平長在詠歌中。", "區區擊壤雖無取，意與生民既醉同。"]'),
('7844023d-2a45-4926-b028-2bb4fda1bef2','徐稚山給事慶八十樂語口號','陸游','宋','宋诗','song-poetry','','[]','欲知主聖本臣忠，傾盡嘉謨沃舜聰。',64,'全唐诗/poet.song.136000.json','["欲知主聖本臣忠，傾盡嘉謨沃舜聰。", "同載方如周呂尚，安車不數漢申公。", "日烘盎盎花光暖，燭映鱗鱗酒浪紅。", "白首同朝各强健，莫辭爛醉答春風。"]'),
('c9476e28-0d4f-4bee-af5e-31c758a82edc','致語口號二首  其一','陸游','宋','宋诗','song-poetry','','[]','曾立蛾眉禁省班，至今風采照金鑾。',64,'全唐诗/poet.song.136000.json','["曾立蛾眉禁省班，至今風采照金鑾。", "縱橫筆陣千人廢，浩蕩辭源萬頃寬。", "落紙烟雲紛態度，照人冰玉峙高寒。", "從容坐嘯香凝寢，說與賓僚拭目觀。"]'),
('ec42001a-7eec-4edb-a80a-9a9af173f278','致語口號二首  其二','陸游','宋','宋诗','song-poetry','','[]','凉月參差白露漙，請看賓主罄清歡。',64,'全唐诗/poet.song.136000.json','["凉月參差白露漙，請看賓主罄清歡。", "麟符玉節交相映，鳳竹鸞絲殊未闌。", "百穀方登倉庚足，七州無事里閭安。", "樽前莫惜山頹玉，四者能兼自古難。"]'),
('a1b31f9c-8ffa-4bf4-8dbc-4502a6bd00f1','奉送姜邦傑出關二首  其一','陸游','宋','宋诗','song-poetry','','[]','君似襄陽孟浩然，蹇馿風帽一癯仙。',32,'全唐诗/poet.song.136000.json','["君似襄陽孟浩然，蹇馿風帽一癯仙。", "清秋客路知無恨，滿箸鱸魚不值錢。"]'),
('cfa640cc-8cb4-4c92-83c4-0426b68ab92e','奉送姜邦傑出關二首  其二','陸游','宋','宋诗','song-poetry','','[]','十年好句滿人間，不欠詩名只欠閑。',32,'全唐诗/poet.song.136000.json','["十年好句滿人間，不欠詩名只欠閑。", "剩欲賀君君領否，新銜兩字是梅山。"]'),
('427586e2-ef38-420a-90c7-316ea4b6cb67','周洪道招食江西筍歸爲絕句','陸游','宋','宋诗','song-poetry','','[]','色如玉版貓頭筍，味抵駝峰牛尾貍。',32,'全唐诗/poet.song.136000.json','["色如玉版貓頭筍，味抵駝峰牛尾貍。", "歸向妻孥誇至夕，書生寒乞定難醫。"]'),
('7db3b065-78f1-4877-b35d-5311b32783cb','社日','陸游','宋','宋诗','song-poetry','','[]','坎坎迎神鼓，兒童喜欲顛。',24,'全唐诗/poet.song.136000.json','["坎坎迎神鼓，兒童喜欲顛。", "放翁無社酒，閉戶課殘編。"]'),
('65f32c5b-6a79-4dc8-a9ca-517f54f0afeb','樵夫','陸游','宋','宋诗','song-poetry','','[]','酸澀澗邊果，青紅巖際花。',24,'全唐诗/poet.song.136000.json','["酸澀澗邊果，青紅巖際花。", "貪隨狙狖去，風雨未還家。"]'),
('1853d0c0-8020-4505-9a24-17b1d5c936e2','致爽軒','陸游','宋','宋诗','song-poetry','','[]','黄塵赤日汗沾裾，竹裏煎茶喜有餘。',32,'全唐诗/poet.song.136000.json','["黄塵赤日汗沾裾，竹裏煎茶喜有餘。", "堪笑放翁窮意巧，就君池館讀君書。"]'),
('958f321a-091c-469f-b96d-ea74fb1d487e','奪錦軒','陸游','宋','宋诗','song-poetry','','[]','奪錦軒中醉倚欄，錦屏紫翠插雲端。',32,'全唐诗/poet.song.136000.json','["奪錦軒中醉倚欄，錦屏紫翠插雲端。", "平生不喜言爭奪，付與游人自在看。"]'),
('73ef8b7b-abff-4745-b0bd-01b0bf567671','海棠','陸游','宋','宋诗','song-poetry','','[]','月下看荼䕷，燭下看海棠。',48,'全唐诗/poet.song.136000.json','["月下看荼䕷，燭下看海棠。", "此是看花法，不可輕傳揚。", "荼䕷暗處看，紛紛滿架雪。", "海棠明處看，滴滴萬點血。"]'),
('d5a77bfa-f0a4-4f7c-a537-efd9b0555116','香爐','陸游','宋','宋诗','song-poetry','','[]','四座且莫喧，願聽歌一言。',96,'全唐诗/poet.song.136000.json','["四座且莫喧，願聽歌一言。", "請說銅香爐，崔巍象南山。", "上枝似松柏，下根據銅盤。", "雕文各異類，離婁自相連。", "誰能爲此器，公輸與魯般。", "朱火然其中，青烟颺其間。", "順入君懷裏，四座莫不歡。", "香風難久居，空令蕙草殘。"]'),
('e7d59bfb-393c-422a-a92b-7faf9abb3a59','贈王伯長主簿','陸游','宋','宋诗','song-poetry','','[]','學詩大略似參禪，且下功夫二十年。',64,'全唐诗/poet.song.136000.json','["學詩大略似參禪，且下功夫二十年。", "君要親嘗獅子吼，法須盡吐野狐涎。", "幾人錯會先師話，吾輩元齊古佛肩。", "天遣放翁窮不死，茶山鉢袋未曾傳。"]'),
('ff33b741-1a50-4ffc-afa9-ea5da8dbc8c8','詩一首','陸游','宋','宋诗','song-poetry','','[]','上重支三枕，趺寒踏兩裘。',24,'全唐诗/poet.song.136000.json','["上重支三枕，趺寒踏兩裘。", "悠悠煎藥水，常照夜深愁。"]'),
('4e1e9035-576b-445b-99d5-ace2613c8db3','出遊','陸游','宋','宋诗','song-poetry','','[]','儘道衰翁嬾，乘閑亦出門。',48,'全唐诗/poet.song.136000.json','["儘道衰翁嬾，乘閑亦出門。", "修琴來竹院，采藥宿山村。", "雪路鳴長耳，烟堤駕獨轅。", "殘年常自在，何以報君恩。"]'),
('c82c0ca9-b013-4830-9937-5c136f1062cf','出越城遊','陸游','宋','宋诗','song-poetry','','[]','出郊聊曠目，小艇受樵風。',48,'全唐诗/poet.song.136000.json','["出郊聊曠目，小艇受樵風。", "烟柳淺深綠，水花顛倒紅。", "秋光無遠近，晚興信西東。", "欲訪幽人宿，高旛古木中。"]'),
('478a2e81-ad7b-464f-9e81-4cb93c3bbfa3','石門','陸游','宋','宋诗','song-poetry','','[]','昔讀康樂詩，夢到石門山。',168,'全唐诗/poet.song.136000.json','["昔讀康樂詩，夢到石門山。", "中有醉道士，倒珮落其冠。", "來游一一是，嵌岩如屋寬。", "噴薄三百尺，萬珠落珊珊。", "峭壁天削成，磐石容投竿。", "摩挲蒼蘚字，喟發千載嘆。", "老洪夢中舊，兩臉依然丹。", "語我君小留，山瓢勿嫌酸。", "澗果四時有，收拾苦不難。", "旋炊胡麻飯，薦以枸杞槃。", "手摘石上茶，風爐煮甘寒。", "擾擾塵土中，未易得此歡。", "濯足山下潭，戲驚蛟龍蟠。", "醉面索吹醒，坐待風雷翻。"]'),
('0a590628-3845-4b92-a87c-8a91c8bb575b','鶑花亭','陸游','宋','宋诗','song-poetry','','[]','沙外春風柳十圍，綠陰依舊語黄鸝。',32,'全唐诗/poet.song.136000.json','["沙外春風柳十圍，綠陰依舊語黄鸝。", "故應留與行人恨，不見秦郎半醉時。"]'),
('376f555b-a7c7-4834-9af3-5af720b36817','郭氏山林十六詠 清曠亭','陸游','宋','宋诗','song-poetry','','[]','勝游謝車馬，從此始青鞵。',24,'全唐诗/poet.song.136000.json','["勝游謝車馬，從此始青鞵。", "俗士洗褊心，達人增曠懷。"]'),
('c15b6e1c-e7f8-4203-b2e4-984bce66977f','郭氏山林十六詠 桂壑','陸游','宋','宋诗','song-poetry','','[]','小山有桂枝，名自騷人傳。',24,'全唐诗/poet.song.136000.json','["小山有桂枝，名自騷人傳。", "我欲辨其族，衰病空慨然。"]'),
('34c31f0f-34b0-4821-ae3f-8e21ac7bcb1c','郭氏山林十六詠 月峽','陸游','宋','宋诗','song-poetry','','[]','我昔泝三峽，仰天如匹練。',24,'全唐诗/poet.song.136000.json','["我昔泝三峽，仰天如匹練。", "安得中天月，正用此時見。"]'),
('d27f4a3f-cb13-47b8-b455-abf12ebb0d55','郭氏山林十六詠 小爛柯','陸游','宋','宋诗','song-poetry','','[]','山中一枰棋，塵世底事無。',24,'全唐诗/poet.song.136000.json','["山中一枰棋，塵世底事無。", "若復計勝負，與彼亦何殊。"]'),
('3cc1b166-21be-4d50-b60a-8ec79dc42031','郭氏山林十六詠 傾月','陸游','宋','宋诗','song-poetry','','[]','種梧待鳳雛，此計乃可笑。',24,'全唐诗/poet.song.136000.json','["種梧待鳳雛，此計乃可笑。", "不如看月墮，與子舒清嘯。"]'),
('94ace3ee-4b8e-4efc-b1e6-dc017f381825','郭氏山林十六詠 高碧巖','陸游','宋','宋诗','song-poetry','','[]','我誦明逸詩，豹林不可到。',24,'全唐诗/poet.song.136000.json','["我誦明逸詩，豹林不可到。", "斯山幸不遠，何日欹紗帽。"]'),
('ad1eb145-d077-4555-9bad-fc49313097b9','郭氏山林十六詠 閟雲關','陸游','宋','宋诗','song-poetry','','[]','白雲如高人，擇友尚傲世。',24,'全唐诗/poet.song.136000.json','["白雲如高人，擇友尚傲世。", "朱門客三千，一點不可致。"]'),
('1233e69b-8844-4c68-a941-d79993108a6c','郭氏山林十六詠 壺天閣','陸游','宋','宋诗','song-poetry','','[]','吾廬在目中，日可理輕策。',24,'全唐诗/poet.song.136000.json','["吾廬在目中，日可理輕策。", "乃知壺中天，端勝縮地脈。"]'),
('ac134856-a639-4a16-9053-2228307778fb','郭氏山林十六詠 石井','陸游','宋','宋诗','song-poetry','','[]','酌泉咽冰玉，肺腑生慘凜。',24,'全唐诗/poet.song.136000.json','["酌泉咽冰玉，肺腑生慘凜。", "老夫桑苧家，頗欲續水品。"]'),
('3c941939-66d1-4d97-9ace-db76e299e35c','郭氏山林十六詠 玉泉','陸游','宋','宋诗','song-poetry','','[]','摘玉毀珠璣，蒙莊有深旨。',24,'全唐诗/poet.song.136000.json','["摘玉毀珠璣，蒙莊有深旨。", "向郭不能傳，千載付吾子。"]'),
('32939d56-4f73-4683-b9a7-f25506651348','郭氏山林十六詠 飛雪','陸游','宋','宋诗','song-poetry','','[]','我昔游青城，六月對雪山。',24,'全唐诗/poet.song.136000.json','["我昔游青城，六月對雪山。", "吳蜀渺萬里，安得在此間。"]'),
('62a51519-1f19-4fb0-afef-968e95f2b0e4','郭氏山林十六詠 玉佩','陸游','宋','宋诗','song-poetry','','[]','羣仙停鶴馭，玉佩搖空山。',24,'全唐诗/poet.song.136000.json','["羣仙停鶴馭，玉佩搖空山。", "金丹定分子，往綴通明班。"]'),
('203f50e1-a301-45fe-9de6-caf31d7003e8','郭氏山林十六詠 韞玉巖','陸游','宋','宋诗','song-poetry','','[]','蒼崖韞白璧，欲上渺無路。',24,'全唐诗/poet.song.136000.json','["蒼崖韞白璧，欲上渺無路。", "但照太史占，虹氣貫寶婺。"]'),
('427f5cc5-e782-4dea-a1e3-cd41a3efff82','郭氏山林十六詠 笙鶴亭','陸游','宋','宋诗','song-poetry','','[]','茲山多異域，飛仙亦稅駕。',24,'全唐诗/poet.song.136000.json','["茲山多異域，飛仙亦稅駕。", "勿遣俗客來，恐妨笙鶴下。"]'),
('48777047-e749-49fe-8805-30f7bfdccab8','郭氏山林十六詠 倚劍','陸游','宋','宋诗','song-poetry','','[]','懸瀑若劍立，空潭如鏡平。',24,'全唐诗/poet.song.136000.json','["懸瀑若劍立，空潭如鏡平。", "未能照魑魅，且用斬長鯨。"]'),
('2ad44353-8d32-4ac3-b2a4-c7cf30b0ae2a','郭氏山林十六詠 藥圃','陸游','宋','宋诗','song-poetry','','[]','采芝夏黄公，賣藥韓伯休。',24,'全唐诗/poet.song.136000.json','["采芝夏黄公，賣藥韓伯休。", "吾友子郭子，高趣可與侔。"]'),
('13710c85-55b7-4de9-b16a-e0d194fc9181','題卧龍山','陸游','宋','宋诗','song-poetry','','[]','涪翁幾日客，遺墨徧蒼崖。',48,'全唐诗/poet.song.136000.json','["涪翁幾日客，遺墨徧蒼崖。", "作吏今三月，偷閑始一來。", "雲歸就簷宿，江怒觸山迴。", "更欲窮幽賞，城頭疊鼓催。"]'),
('f9bd68c1-7da0-4c7c-92ff-2fa05be07d34','韓幹馬圖','陸游','宋','宋诗','song-poetry','','[]','唐人畫馬如相馬，□□不在驪與黄。',213,'全唐诗/poet.song.136000.json','["唐人畫馬如相馬，□□不在驪與黄。", "天機入神即揮灑，氣脫毫素先騰驤。", "昔年曾畫穆王游八極，八龍之駿雲五色。", "後來又寫越影超光脫丹碧，後來又寫漢武窮渥洼。", "復見神駒來漢家，勢走滅沒開風沙。", "壯哉此馬健且雄，玉花徧身雲滿鬉。", "首如渴烏眼如電，皎如疋練橫晴空。", "使之陷陣當破敵，萬馬不敢先秋風。", "如何解鞍脫其馽，縱爾俶儻如游龍。", "君不見四海罷征戰，九夷盡梯航。", "方將却爾宛水之西，歸爾華山之陽。", "幸逢韓供奉寫爾神，杜拾遺歌爾良。", "贈爾支道林，愛爾神駿懸高堂。"]'),
('b82b4ffe-32cc-4863-8675-91769f58ffae','訪僧支提寺','陸游','宋','宋诗','song-poetry','','[]','高名每慣習鑿齒，巨眼忽逢支道林。',64,'全唐诗/poet.song.136000.json','["高名每慣習鑿齒，巨眼忽逢支道林。", "共夜不知紅燭短，對床空嘆白雲深。", "滿前鐘鼓何曾忍，匝地毫光不用尋。", "欲識天冠真面目，鳥啼猿嘯總知音。"]'),
('1e4be563-975f-4a26-b422-593a61c0907c','南園四首  其一','陸游','宋','宋诗','song-poetry','','[]','曉鶑催繫柳邊舟，老陌東風拂面柔。',64,'全唐诗/poet.song.136000.json','["曉鶑催繫柳邊舟，老陌東風拂面柔。", "客裏又驚春事晚，夢中重續括蒼游。", "歡情飲量年年減，古寺名園處處留。", "却羨少年輕歲月，角聲如此不知愁。"]'),
('6cdf9426-b10e-4624-b359-657c6ddb017b','南園四首  其二','陸游','宋','宋诗','song-poetry','','[]','南游雲海嘆茫茫，又泛歸舟到括蒼。',64,'全唐诗/poet.song.136000.json','["南游雲海嘆茫茫，又泛歸舟到括蒼。", "城郭凄凉嘆遼鶴，鬢毛蕭颯點吳霜。", "酴醿可把春無幾，弦索初陳燕未央。", "樓下清溪三百里，溪流不似客愁長。"]'),
('f5d47a12-25f1-48f5-8fd6-d16d4ef6714e','南園四首  其三','陸游','宋','宋诗','song-poetry','','[]','安用移封向酒泉，醉鄉只擬乞南園。',32,'全唐诗/poet.song.136000.json','["安用移封向酒泉，醉鄉只擬乞南園。", "更添小閣臨灘石，一洗人間歌吹喧。"]'),
('34c5edce-ed90-473c-be29-f5e812502c24','南園四首  其四','陸游','宋','宋诗','song-poetry','','[]','春來歸路閲三州，是處跏趺懶出游。',32,'全唐诗/poet.song.136000.json','["春來歸路閲三州，是處跏趺懶出游。", "一到南園便忘返，亭邊綠浸琵琶洲。"]'),
('487d89d8-14be-4dd2-b52d-3c13bc31c41b','虎洞','陸游','宋','宋诗','song-poetry','','[]','空山秋高木葉黄，茫茫百草凋秋霜。',200,'全唐诗/poet.song.136000.json','["空山秋高木葉黄，茫茫百草凋秋霜。", "逶迤深谷白晝靜，群鴉競噪衆鳥翔。", "洞中有虎何猛烈，牙如利刀爪如鐵。", "奮髯掉尾初出穴，昂頭四顧吐其舌。", "雙睛忽動飛電迴，層崖長嘯陰風來。", "山中藜藿誰敢採，野外狐兔皆悲哀。", "嗟虎之猛有如此，自是貪殘日無已。", "豈無壯士裴將軍，彎弓射之殄其類。", "方今上有明聖君，廣愛民物懷深仁。", "推誠不但祝羅網，登用牧守需賢人。", "四郊無事民安靜，有若劉昆多善政。", "嗟虎雖猛當如何，胡爲飲泉卷之阿，明當負子東渡河。"]'),
('1f0e55c2-66d4-490b-92c9-1cea148ce1b9','古詩','陸游','宋','宋诗','song-poetry','','[]','能自得我心，無入不自得。',60,'全唐诗/poet.song.136000.json','["能自得我心，無入不自得。", "靈府長優閑，蕉鹿烏能惑。", "濁醪吞數升，浩氣漫漫塞。", "醉來隠几酣，屢到華胥國。", "人生貴適情，何當調語默。"]'),
('100e46f1-e0cc-446a-ae2f-b6b6137fa401','句  其一','陸游','宋','宋诗','song-poetry','','[]','南酒應憐未歸客。',8,'全唐诗/poet.song.136000.json','["南酒應憐未歸客。"]'),
('b78d38ba-33f6-42bf-b548-c6e2dbdfcc39','句  其二','陸游','宋','宋诗','song-poetry','','[]','更就高僧學白羹。',8,'全唐诗/poet.song.136000.json','["更就高僧學白羹。"]'),
('ab6cf4c2-d221-4054-be9e-ae8b480d8f27','句  其三','陸游','宋','宋诗','song-poetry','','[]','厚味無人設佞湯，微芬時自炷廉香。',16,'全唐诗/poet.song.136000.json','["厚味無人設佞湯，微芬時自炷廉香。"]'),
('a62ec8dc-d286-48a5-95e0-abf5c2c296c4','句  其四','陸游','宋','宋诗','song-poetry','','[]','窮達得非吾有命，吉凶誰謂汝前知。',16,'全唐诗/poet.song.136000.json','["窮達得非吾有命，吉凶誰謂汝前知。"]'),
('2973dd38-3905-4bf0-9706-ae8df0969641','句  其五','陸游','宋','宋诗','song-poetry','','[]','使君何所樂，樂在南湖濱。',12,'全唐诗/poet.song.136000.json','["使君何所樂，樂在南湖濱。"]'),
('733a9066-0357-4026-b665-41c6714cfb45','句  其六','陸游','宋','宋诗','song-poetry','','[]','歌呼宛轉連漁市，燈火青熒擁郡樓。',16,'全唐诗/poet.song.136000.json','["歌呼宛轉連漁市，燈火青熒擁郡樓。"]'),
('27f9e21a-a221-4835-a79e-442a705e797b','句  其七','陸游','宋','宋诗','song-poetry','','[]','我老詩不工，非復薛與岑。',12,'全唐诗/poet.song.136000.json','["我老詩不工，非復薛與岑。"]'),
('426bb906-2c07-4298-b961-06611b076f03','句  其八','陸游','宋','宋诗','song-poetry','','[]','是邦山水窟，領會得佳處。',36,'全唐诗/poet.song.136000.json','["是邦山水窟，領會得佳處。", "山回如可招，水集若來赴。", "竹葉溯江船，春薺隔烟樹。"]'),
('8ff5e0f4-21c0-4901-a017-b115eaead182','句  其九','陸游','宋','宋诗','song-poetry','','[]','禿老本儒冠，荆公使爲僧。',12,'全唐诗/poet.song.136000.json','["禿老本儒冠，荆公使爲僧。"]'),
('b39653c0-ebb9-43f3-a0aa-a4dc620960c6','句  其一○','陸游','宋','宋诗','song-poetry','','[]','但見古河東，蕎麥鋪如雪。',12,'全唐诗/poet.song.136000.json','["但見古河東，蕎麥鋪如雪。"]'),
('98fc04fe-9aed-45ff-bde4-17cf333cbea3','存目  其一','陸游','宋','宋诗','song-poetry','','[]','詩題：成材將還旴江幕以詩四章爲貺次韵其二以識別，首句：漂泊干戈到粵山文場妙譽古推高。',42,'全唐诗/poet.song.136000.json','["詩題：成材將還旴江幕以詩四章爲貺次韵其二以識別，首句：漂泊干戈到粵山文場妙譽古推高。"]'),
('7223c3bf-4bd6-47af-8203-e98e4ff6edea','存目  其二','陸游','宋','宋诗','song-poetry','','[]','詩題：寄鄧志宏五首首句：三徑從來半草萊彭澤思歸意未成厭從薄宦思蓮幕筆下文章信有神中原回首涕沾裳。',48,'全唐诗/poet.song.136000.json','["詩題：寄鄧志宏五首首句：三徑從來半草萊彭澤思歸意未成厭從薄宦思蓮幕筆下文章信有神中原回首涕沾裳。"]'),
('be828ec0-32a1-4246-8194-c008eaf64ba2','存目  其三','陸游','宋','宋诗','song-poetry','','[]','詩題：贈徐相師首句：許負遺書果是非。',18,'全唐诗/poet.song.136000.json','["詩題：贈徐相師首句：許負遺書果是非。"]'),
('417aaa2e-168a-4a1c-aa47-8742b4821558','題壁','陸放翁妾','宋','宋诗','song-poetry','','[]','玉階蟋蟀閙清夜，金井梧桐辭故枝。',32,'全唐诗/poet.song.136000.json','["玉階蟋蟀閙清夜，金井梧桐辭故枝。", "一枕凄凉眠不得，呼燈起作感秋時。"]'),
('d1b81c93-4981-4bf7-afff-4cd0930e3482','行路難','范成大','宋','宋诗','song-poetry','','[]','贈君以丹棘忘憂之草，青棠合歡之花。',65,'全唐诗/poet.song.136000.json','["贈君以丹棘忘憂之草，青棠合歡之花。", "馬腦遊仙之夢枕，龍綜辟寒之寶紗。", "天河未翻月未落，夜長如年引春酌。", "昔人安在空城郭，今夕不飲何時樂。"]'),
('0d1000fe-058c-4528-85b1-99b22c763e6e','西江有單鵠行','范成大','宋','宋诗','song-poetry','','[]','西江有單鵠，託身萬里雲。',240,'全唐诗/poet.song.136000.json','["西江有單鵠，託身萬里雲。", "猥爲稻粱謀，墮此鷗鷺羣。", "朝遊楓葉杪，暮宿蘆花根。", "懷安浦溆暖，忘記雲海寬。", "忽有孤征鴻，驚飛落江濱。", "眼明見黄鵠，邂逅傾情真。", "羽毛雖不同，意氣頗相親。", "言鵠有六翮，何不高飛翾。", "水鳥不足羣，朝暮徒嘲喧。", "相將乘風去，一上盤秋旻。", "渴飲顥露滋，饑吸晴霞暾。", "方知翅翎俊，可以凌埃塵。", "東風昨解凍，春光暖如薰。", "陽鳥當北鄉，行止倏已分。", "儻欲相逐去，關山隔吳秦。", "兩鳥竟分飛，鳴聲動行人。", "豈不有歲晚，鴻當復來賓。", "但愁山海闊，岐路多糾紛。", "復來失故道，那得相知聞。", "鴻歸有儔侶，鵠住長悲辛。"]'),
('8f5c5d4a-c5d7-4372-aa11-a5a33c8639d8','車遥遥篇','范成大','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u6292\u6000"]','車遥遥，馬憧憧。',60,'全唐诗/poet.song.136000.json','["車遥遥，馬憧憧。", "君遊東山東復東，安得奮飛逐西風。", "願我如星君如月，夜夜流光相皎潔。", "月暫晦，星常明。", "留明待月復，三五共盈盈。"]'),
('ab9636ad-0446-4c6d-aaa4-65d85f329891','放魚行','范成大','宋','宋诗','song-poetry','','[]','水落塘枯魚卧陸，小兒抱取不濡足。',96,'全唐诗/poet.song.136000.json','["水落塘枯魚卧陸，小兒抱取不濡足。", "昂藏赤鯶亦垂頭，背負玄鱗三十六。", "家人滌砧不辭勞，云有素書金錯刀。", "嗟予贖放豈徼福，忍把汝命供吾饕。", "如今已脫張胡子，好上龍門飲湖水。", "不然崛起載飛仙，切莫顛狂稱長史。"]'),
('7ce6a8a4-d215-4aa5-b1df-a9844dd62bdd','晚步東郊','范成大','宋','宋诗','song-poetry','','[]','水墨依林寺，青黄負郭田。',48,'全唐诗/poet.song.136000.json','["水墨依林寺，青黄負郭田。", "斜陽猶滿地，片月早中天。", "策策鴉飛急，冥冥樹影圓。", "西山元自好，那更著雲煙。"]'),
('cd8f4269-d015-4a12-8205-de4876759e4c','元夜憶羣從','范成大','宋','宋诗','song-poetry','','[]','愁裏仍蒿徑，閒中更蓽門。',48,'全唐诗/poet.song.136000.json','["愁裏仍蒿徑，閒中更蓽門。", "青燈聊自照，濁酒爲誰溫。", "隙月知無夢，窗梅寄斷魂。", "遥憐好兄弟，飄泊兩江村。"]'),
('44d1a5ab-b8ff-473f-9e68-842c85dbe083','登西樓','范成大','宋','宋诗','song-poetry','','[]','少年豪氣合摧鋒，青鬢朱顔萬事慵。',64,'全唐诗/poet.song.136000.json','["少年豪氣合摧鋒，青鬢朱顔萬事慵。", "疇昔四愁無夢到，及時一笑有誰供。", "詩情飲興如雲薄，草色花光似酒醲。", "千里春心吟不盡，下樓分付晚煙鐘。"]'),
('943cb81f-be89-40e1-a727-4302a28d2170','不寐','范成大','宋','宋诗','song-poetry','','[]','南風釀卑濕，滑滑病履舄。',192,'全唐诗/poet.song.136000.json','["南風釀卑濕，滑滑病履舄。", "竟日隠几坐，拳局不得適。", "丹田恍澒洞，銀海眩眵黑。", "髀弱類跨鞍，臂强如運甓。", "合體競酸嘶，莫夜輒增極。", "奏牀不得眠，耿耿到明發。", "黄妳共住久，來夢乃其職。", "睡魔吾故人，曩是不速客。", "招呼各偃蹇，莫效尺寸力。", "周公無由來，咫尺今古隔。", "彭尸不得去，罡騎無行色。", "主客兩愁緒，虛室浪生白。", "人言老禪師，兩脇不到席。", "茲事恐未暇，但願了今夕。", "平生北窗眠，栩栩即聖域。", "睡僊吾所慕，行步亦鼾息。"]'),
('3485c42e-2931-4cb5-ae0e-3e3571c93ce6','河豚歎','范成大','宋','宋诗','song-poetry','','[]','鯫生藜莧腸，食事一飽足。',252,'全唐诗/poet.song.136000.json','["鯫生藜莧腸，食事一飽足。", "腥腐色所難，況乃衷酖毒。", "彭亨强名魚，殺氣孕慘黷。", "既非養生具，宜謝砧几酷。", "吳儂真差事，網索不遺育。", "捐生決下箸，縮手汗童僕。", "朝來里中子，饞吻不待熟。", "濃睡喚不譍，已落新鬼錄。", "百年三寸咽，水陸富肴䔩。", "一物不登俎，未負將軍腹。", "爲口忘計身，饕死何足哭。", "作俑者誰歟，至今走末俗。", "或云先王意，除惡如藝菽。", "逆梟與毒獍，歲歲參幣玉。", "芟夷入薦羞，蓋欲殲種族。", "生死有定數，斷命烏可續。", "適丁是時者，未易一理局。", "黿鼎子公怒，羊羹華元衄。", "異味古所珍，無事苦畏縮。", "駢頭訌此語，戒諭袛取瀆。", "聾盲死不悟，明知諒已燭。"]'),
('77aff130-af7d-4a1f-8ade-49b28ef3d437','續長恨歌七首  其一','范成大','宋','宋诗','song-poetry','','[]','金杯瀲灧曉粧寒，國色天香勝牡丹。',32,'全唐诗/poet.song.136000.json','["金杯瀲灧曉粧寒，國色天香勝牡丹。", "白鳳詔書來已暮，六宮鉛粉半春闌。"]'),
('24139805-360b-4aff-a935-d7d8eaf2a72b','續長恨歌七首  其二','范成大','宋','宋诗','song-poetry','','[]','紫薇金屋閉春陽，石竹山花却自芳。',32,'全唐诗/poet.song.136000.json','["紫薇金屋閉春陽，石竹山花却自芳。", "莫道故情無覓處，領巾猶有隔生香。"]'),
('7e7bac25-a4d0-48f1-ada5-e1b645c9e65f','續長恨歌七首  其三','范成大','宋','宋诗','song-poetry','','[]','聞道蓬壺重見時，瘦來全不耐風吹。',32,'全唐诗/poet.song.136000.json','["聞道蓬壺重見時，瘦來全不耐風吹。", "無端却作塵間念，已被仙官聖得知。"]'),
('f282fa67-8537-43ae-8799-f982b4782482','續長恨歌七首  其四','范成大','宋','宋诗','song-poetry','','[]','別後相思夢亦難，東虛雲路海漫漫。',32,'全唐诗/poet.song.136000.json','["別後相思夢亦難，東虛雲路海漫漫。", "仙凡頓隔銀屏影，不似當時取次看。"]'),
('e3d8b263-a07c-4c00-a445-84dac519241f','續長恨歌七首  其五','范成大','宋','宋诗','song-poetry','','[]','人似飛花去不歸，蘭昌宮殿幾斜暉。',32,'全唐诗/poet.song.136000.json','["人似飛花去不歸，蘭昌宮殿幾斜暉。", "百年只有雲容姊，留得當時舊舞衣。"]'),
('e9c3d348-0272-42d0-95a7-7fdb80953e26','續長恨歌七首  其六','范成大','宋','宋诗','song-poetry','','[]','驪山六十二高樓，突兀華清最上頭。',32,'全唐诗/poet.song.136000.json','["驪山六十二高樓，突兀華清最上頭。", "玉羽川長湘浦暗，三郎無事更神遊。"]'),
('20da25d5-2faa-42d7-ad4a-bca659ff6df7','續長恨歌七首  其七','范成大','宋','宋诗','song-poetry','','[]','帝鄉雲馭若爲留，八景三清好在不。',32,'全唐诗/poet.song.136000.json','["帝鄉雲馭若爲留，八景三清好在不。", "玉笛不隨雙鶴去，人間猶得聽梁州。"]'),
('be5cc00b-0c6a-4cf1-99ff-0899cf912587','雷雨鄰舍起龍','范成大','宋','宋诗','song-poetry','','[]','雨工避事欲蟠泥，帝遣豐隆執以歸。',32,'全唐诗/poet.song.136000.json','["雨工避事欲蟠泥，帝遣豐隆執以歸。", "連鼓一聲人失箸，不知挂壁幾梭飛。"]'),
('8ffdf430-c438-49fb-997b-83eb7681e726','次韻唐致遠雨後喜凉','范成大','宋','宋诗','song-poetry','','[]','老陽作氣再三衰，鼓竭之餘不支雨。',64,'全唐诗/poet.song.136000.json','["老陽作氣再三衰，鼓竭之餘不支雨。", "搴旗拔幟埽迹空，一點新凉破殘暑。", "飛蚊薨薨已無奇，蜻蜓翅浄摩天嬉。", "竹窗日暮轉蕭瑟，喜有促織鳴聲悲。"]'),
('a7a14466-7f7c-4b04-8bab-3af0159a5234','秋日二絕  其一','范成大','宋','宋诗','song-poetry','','[]','碧蘆青柳不宜霜，染作滄洲一带黄。',32,'全唐诗/poet.song.136000.json','["碧蘆青柳不宜霜，染作滄洲一带黄。", "莫把江山誇北客，冷雲寒水更荒凉。"]'),
('712871b7-2259-4f86-a14e-b225f90d68f4','秋日二絕  其二','范成大','宋','宋诗','song-poetry','','[]','新秋病骨頓成衰，不度溪橋半月來。',32,'全唐诗/poet.song.136000.json','["新秋病骨頓成衰，不度溪橋半月來。", "無事閉門非左計，饒渠屐齒上青苔。"]'),
('7975b49a-4233-486c-8df8-041f5cf239fa','窗前木芙蓉','范成大','宋','宋诗','song-poetry','','[]','辛苦孤花破小寒，花心應似客心酸。',32,'全唐诗/poet.song.136000.json','["辛苦孤花破小寒，花心應似客心酸。", "更憑青女留連得，未作愁紅怨綠看。"]'),
('5d5e33a5-30da-48ee-a498-ccf1d48d72ac','嘲里人新婚','范成大','宋','宋诗','song-poetry','','[]','冷艷頩容一笑開，休將鸞扇更徘徊。',32,'全唐诗/poet.song.136000.json','["冷艷頩容一笑開，休將鸞扇更徘徊。", "箜篌細寫歸舟字，彷彿遊仙夢裏來。"]'),
('08943f93-017a-4237-983a-8683e4c7f062','過松江','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','長虹斗起蛟龍穴，朱碧爛干夜明滅。',144,'全唐诗/poet.song.136000.json','["長虹斗起蛟龍穴，朱碧爛干夜明滅。", "太湖三萬六千頃，多少清風與明月。", "青鷁驚飛白鷺閒，丹楓未老黄蘆折。", "誰將橫笛叫蒼煙，無限驚波翻白雪。", "洞庭林屋舊遊處，玉柱金庭路巉絕。", "水仙逢迎摻脩袂，問我歸計何當決。", "去年匹馬兀春寒，今此孤篷窘秋熱。", "人生意氣得失間，輕重劍頭吹一吷。", "莫將塵土涴朱顔，却待丹砂回白髮。"]'),
('ead212a7-7fa5-41bb-a967-8cc8457cf951','過平望','范成大','宋','宋诗','song-poetry','','[]','寸碧闖高浪，孤墟明夕陽。',96,'全唐诗/poet.song.136000.json','["寸碧闖高浪，孤墟明夕陽。", "水柳搖病綠，霜蒲蘸新黄。", "孤嶼乍舉網，蒼煙忽鳴榔。", "波明荇葉顫，風熟蘋花香。", "雞犬各村落，蓴鱸近江鄉。", "野寺對客起，樓陰濯滄浪。", "古來離別地，清詩斷人腸。", "亭前舊時水，還照兩鴛鴦。"]'),
('cceb0765-1609-4699-b22e-01366640869c','長安閘','范成大','宋','宋诗','song-poetry','','[]','斗門貯浄練，懸板淙驚雷。',156,'全唐诗/poet.song.136000.json','["斗門貯浄練，懸板淙驚雷。", "黄沙古岸轉，白屋飛檐開。", "是間袤丈許，舳艫蔽川來。", "千車擁孤隧，萬馬盤一坏。", "篙尾亂若雨，檣竿束如堆。", "摧摧勢排軋，洶洶聲喧豗。", "偪仄復偪仄，誰肯少徘徊。", "傳呼津吏至，弊蓋凌高埃。", "囁嚅議譏征，叫怒不可裁。", "吾觀舟中子，一一皆可哀。", "大爲聲利驅，小者饑寒催。", "古今共來往，所得隨飛灰。", "我乃畸於人，胡爲乎來哉。"]'),
('bd0c1ccd-9b59-4f6d-90cf-95b6746cb467','榮木','范成大','宋','宋诗','song-poetry','','[]','薰風南來，木榮於茲。',150,'全唐诗/poet.song.136000.json','["薰風南來，木榮於茲。", "木榮幾時，黄落從之。", "逝其須臾，坐成四時。", "今我不學，殆其已而。", "天旋地遊，日月其根。", "形息氣徂，不亡者存。", "去鄉離家，莫肯過門。", "猗歟先師，不我疵陋。", "褰衣示珠，俾我復舊。", "自我來歸，十年不富。", "孰蠹孰蠱，惟汝自疚。", "冉冉榮木，霜華將墜。", "天黑路長，屹蹶可畏。", "隸也不力，奚取六驥。", "脂車著鞭，一息而至。"]'),
('27997096-b3fa-43e7-8582-d7e51178dc05','兩木  其一','范成大','宋','宋诗','song-poetry','','[]','枇杷昔所嗜，不問甘與酸。',108,'全唐诗/poet.song.136000.json','["枇杷昔所嗜，不問甘與酸。", "黄泥裹餘核，散擲籬落間。", "春風拆勾萌，樸𣙙如榛菅。", "一株獨成長，蒼然齊屋山。", "去年小試花，瓏瓏犯冰寒。", "化成黄金彈，同登桃李盤。", "大鈞播羣物，斡旋不作難。", "樹老人何堪，挽鏡覓朱顔。", "頷髭爾許長，大笑欹巾冠。"]'),
('c261a52f-77d9-441f-811c-c6e08447ac72','兩木  其二','范成大','宋','宋诗','song-poetry','','[]','綠橘生西山，得自髯翁家。',108,'全唐诗/poet.song.136000.json','["綠橘生西山，得自髯翁家。", "云此接活根，是歲當著花。", "俛仰乃十霜，垂蠹紛相遮。", "芳意竟寂莫，枯枝謾槎牙。", "風土諒非宜，翁言豈予夸。", "會令返故山，高深謝汙邪。", "石液滋舊根，山英擢新葩。", "黄團挂霜實，大如崆峒瓜。", "當有四老人，來駐七香車。"]'),
('2afdff4f-69f9-4284-962a-87a8a073ce5d','道中','范成大','宋','宋诗','song-poetry','','[]','月冷吟蛩草，湖平宿鷺沙。',48,'全唐诗/poet.song.136000.json','["月冷吟蛩草，湖平宿鷺沙。", "客愁無錦字，鄉信有燈花。", "蹤跡隨風葉，程途犯斗槎。", "君看枝上鵲，薄暮亦還家。"]'),
('24a8e1f4-aff7-4db4-b899-e7b1a180e8c2','落鴻','范成大','宋','宋诗','song-poetry','','[]','落鴻聲裏怨關山，淚濕秋衣不肯乾。',32,'全唐诗/poet.song.136000.json','["落鴻聲裏怨關山，淚濕秋衣不肯乾。", "只道一番新雨過，誰知雙袖倚樓寒。"]'),
('924d46c9-f345-4546-8581-860527a67d13','題山水橫看二首  其一','范成大','宋','宋诗','song-poetry','','[]','煙山漠漠水漫漫，老柳知秋渡口寒。',32,'全唐诗/poet.song.136000.json','["煙山漠漠水漫漫，老柳知秋渡口寒。", "盡是西溪腸斷處，憑君將與故人看。"]'),
('df48f304-7c9f-4882-b918-166c71d9eb7f','題山水橫看二首  其二','范成大','宋','宋诗','song-poetry','','[]','霜入丹楓白葦林，橫煙平遠暮江深。',32,'全唐诗/poet.song.136000.json','["霜入丹楓白葦林，橫煙平遠暮江深。", "君看鴈落帆飛處，知我秋風故國心。"]'),
('14ed541a-b797-44a3-b1b5-9844f537541e','瑞香花','范成大','宋','宋诗','song-poetry','','[]','萬粒叢芳破雪殘，曲房深院閉春寒。',64,'全唐诗/poet.song.136000.json','["萬粒叢芳破雪殘，曲房深院閉春寒。", "紫紫青青雲錦被，百疊薰籠晚不翻。", "酒惡休拈花蘂嗅，花氣醉人醲勝酒。", "大將香供惱幽禪，恰在蘭枯梅落後。"]'),
('093fabf8-76a7-4d2d-adfd-e3c29b116fb4','讀史','范成大','宋','宋诗','song-poetry','','[]','登壇策劉項，卧廬料曹孫。',180,'全唐诗/poet.song.136000.json','["登壇策劉項，卧廬料曹孫。", "探懷取事業，一一如印圈。", "英豪蓋天資，八極入控摶。", "由來事成毀，只繫手覆翻。", "玉虹朝貫日，劍氣夜燭天。", "雖欲避功名，何處蟄龍鸞。", "我生後千載，愚暗難具言。", "長大但食粟，閔凶不能文。", "麥豆已難辨，楣梲固不分。", "抱甕灌圃畦，截竿避城門。", "智略類如此，何以超籬籓。", "龜刳始神筴，木斷方犠尊。", "朝市有機穽，冠裳或鉗髠。", "茲事定不暗，吾其老泥蟠。", "敢云善用短，聊復强自寬。"]'),
('6ac79b21-2c46-4b5e-a259-e5261023fa57','浙江小磯春日','范成大','宋','宋诗','song-poetry','','[]','客裏無人共一杯，故園桃李爲誰開。',32,'全唐诗/poet.song.136000.json','["客裏無人共一杯，故園桃李爲誰開。", "春潮不管天涯恨，更捲西興暮雨來。"]'),
('c4ad48d3-e33f-4f46-8204-5ca296def321','代聖集贈別','范成大','宋','宋诗','song-poetry','','[]','一曲悲歌水倒流，尊前何計緩千憂。',64,'全唐诗/poet.song.136000.json','["一曲悲歌水倒流，尊前何計緩千憂。", "事如夢斷無尋處，人似春歸挽不留。", "草色粘天鶗鴂恨，雨聲連曉鷓鴣愁。", "迢迢綠浦帆飛遠，今夜新晴獨倚樓。"]'),
('c962106d-b6a5-4b06-aa28-7f9af1cbc1fa','二月三日登樓有懷金陵宣城諸友','范成大','宋','宋诗','song-poetry','','[]','百尺西樓十二欄，日遲花影對人閒。',64,'全唐诗/poet.song.136000.json','["百尺西樓十二欄，日遲花影對人閒。", "春風已入片時夢，寒食從今數日間。", "折柳故情多望斷，落梅新曲與愁關。", "詩成欲訪江南便，千里煙波萬疊山。"]'),
('ba41f074-cfa7-4a8b-bb2b-5ca7f0e57b99','寒食郊行書事二首  其一','范成大','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282", "\u519c\u6751", "\u98ce\u4fd7"]','野店垂楊步，荒祠苦竹叢。',48,'全唐诗/poet.song.136000.json','["野店垂楊步，荒祠苦竹叢。", "鷺窺蘆箔水，烏啄紙錢風。", "媼引濃粧女，兒扶爛醉翁。", "深村時節好，應爲去年豐。"]'),
('e872d9e8-f326-4532-b154-ee1d7a0d1dcb','寒食郊行書事二首  其二','范成大','宋','宋诗','song-poetry','','[]','隴麥欣欣綠，山桃寂寂紅。',48,'全唐诗/poet.song.136000.json','["隴麥欣欣綠，山桃寂寂紅。", "帆邊漁蕝浪，木末酒旗風。", "信步隨芳草，迷途問小童。", "賞心添脚力，呼渡過溪東。"]'),
('5209044f-2a4b-4fdb-95de-e778f79d02d2','初夏二首  其一','范成大','宋','宋诗','song-poetry','','[]','清晨出郭更登臺，不見餘春只麽回。',32,'全唐诗/poet.song.136000.json','["清晨出郭更登臺，不見餘春只麽回。", "桑葉露枝蠶向老，菜花成莢蝶猶來。"]'),
('91156c6a-c459-4952-b4b5-1f8994b2c026','初夏二首  其二','范成大','宋','宋诗','song-poetry','','[]','晴絲千尺挽韶光，百舌無聲燕子忙。',32,'全唐诗/poet.song.136000.json','["晴絲千尺挽韶光，百舌無聲燕子忙。", "永日屋頭槐影暗，微風扇裏麥花香。"]'),
('6be57118-17e8-40e0-ac06-147693f5a840','夏夜','范成大','宋','宋诗','song-poetry','','[]','脉脉惜佳夜，泠泠成浩歌。',48,'全唐诗/poet.song.136000.json','["脉脉惜佳夜，泠泠成浩歌。", "儻無詩句子，將奈月明何。", "露氣濛花重，風聲入樹多。", "清歡殊未辦，桂影墮江波。"]'),
('e40b336c-1a59-4af6-b1e3-d7276aed8c63','與時敘現老納凉池上時敘誦新詞甚工','范成大','宋','宋诗','song-poetry','','[]','會心不在遠，頃步便得之。',108,'全唐诗/poet.song.136000.json','["會心不在遠，頃步便得之。", "長風吹月來，清影落半池。", "屋頭見木葉，玲瓏剪琉璃。", "紅塵絆兩足，大笑兒輩癡。", "老禪挽我遊，高論方軒眉。", "潘郎忽鼎來，談詩解人頤。", "晚誦雲髻篇，濯濯餘春姿。", "想見篇中人，清潤如君詩。", "笑我兩枯木，獨與三冬期。"]'),
('08ce494e-1f9f-46dd-b0f0-4c9fb3dbccf2','林元復輓詩','范成大','宋','宋诗','song-poetry','','[]','胸次崢嶸滿貯書，十年名字滿江湖。',64,'全唐诗/poet.song.136000.json','["胸次崢嶸滿貯書，十年名字滿江湖。", "張公閲世詩千首，揚子傳家宅一區。", "謾道春風須得意，那知秋雨不成珠。", "自從雪魄冰魂散，魯國今誰更服儒。"]'),
('77bc4b5d-0a77-4f91-9035-c2b20dd4d1a3','戲贈少梁','范成大','宋','宋诗','song-poetry','','[]','屈膝銅鋪晝掩關，薰爐誰伴夕香寒。',32,'全唐诗/poet.song.136000.json','["屈膝銅鋪晝掩關，薰爐誰伴夕香寒。", "秋來合有相思字，會待風前片葉看。"]'),
('5e589ab2-11d6-4f59-8d6f-e2cdbdd36c7e','南徐道中','范成大','宋','宋诗','song-poetry','','[]','生憎行路與心違，又逐孤帆擘浪飛。',64,'全唐诗/poet.song.136000.json','["生憎行路與心違，又逐孤帆擘浪飛。", "吳岫湧雲穿望眼，楚江浮月冷征衣。", "長歌悲似垂垂淚，短夢紛如草草歸。", "若有一廛供閉戶，肯將篾舫換柴扉。"]'),
('1dc51a62-a06f-4c22-8d68-84ea76e86e45','望金陵行闕','范成大','宋','宋诗','song-poetry','','[]','聖代規模跨六朝，行宮臺殿壓金鼇。',64,'全唐诗/poet.song.136000.json','["聖代規模跨六朝，行宮臺殿壓金鼇。", "三山落日青鸞近，雙闕清風紫鳳高。", "石虎蹲江蟠王氣，玉麟湧地鎮神臯。", "太平不用千尋鎖，靜聽西城打夜濤。"]'),
('49311e43-9753-43c8-8010-2e408ac3fb37','金陵道中','范成大','宋','宋诗','song-poetry','','[]','山晚黄羊隨日下，天寒白犢弄風歸。',32,'全唐诗/poet.song.136000.json','["山晚黄羊隨日下，天寒白犢弄風歸。", "愁埃百轉西州路，笑憶沙湖一棹飛。"]'),
('fcddd0df-fa73-4730-87be-7f201256e424','曉行','范成大','宋','宋诗','song-poetry','','[]','篝燈驛吏喚人行，寥落星河向五更。',32,'全唐诗/poet.song.136000.json','["篝燈驛吏喚人行，寥落星河向五更。", "馬上誰驚千里夢，石頭岡下小車聲。"]'),
('a0401a23-9d74-4631-8758-225aa04d5dcb','秦淮','范成大','宋','宋诗','song-poetry','','[]','不將行李試間關，誰信江湖道路難。',32,'全唐诗/poet.song.136000.json','["不將行李試間關，誰信江湖道路難。", "腸斷秦淮三百曲，船頭終日見方山。"]'),
('95afff68-bc6b-4913-a834-09f1553a0204','重九獨登賞心亭','范成大','宋','宋诗','song-poetry','','[]','誰教佳節滯天涯，强展愁眉管物華。',64,'全唐诗/poet.song.136000.json','["誰教佳節滯天涯，强展愁眉管物華。", "每歲有詩題白鴈，今年無酒對黄花。", "悠悠造化占斜日，草草登臨記落霞。", "宇宙此身元是客，不須彈鋏更思家。"]'),
('cf7e5ce7-b71e-4fd2-8da9-48027f5c81c9','賞心亭再題','范成大','宋','宋诗','song-poetry','','[]','天險東南重，兵雄百二尊。',48,'全唐诗/poet.song.136000.json','["天險東南重，兵雄百二尊。", "拂雲千雉繞，截水萬崖奔。", "赤日吳波動，蒼煙楚樹昏。", "向無形勝地，何以控乾坤。"]'),
('5593b5a4-f103-4793-85be-5d1ecfcdc289','宿義林院','范成大','宋','宋诗','song-poetry','','[]','暝氣昏如雨，禪房冷似冰。',48,'全唐诗/poet.song.136000.json','["暝氣昏如雨，禪房冷似冰。", "竹間東嶺月，松杪上方燈。", "驚鶻盤金剎，流螢拂玉繩。", "明朝窮脚力，連夜斬崖藤。"]'),
('fa3a344c-c3a3-4f16-a041-5fe44ac2ed43','荆公墓二首  其一','范成大','宋','宋诗','song-poetry','','[]','百歲誰人巧拙，一丘底處虧成。',28,'全唐诗/poet.song.136000.json','["百歲誰人巧拙，一丘底處虧成。", "半世青苗法意，當年雪竹詩情。"]'),
('c45e4434-78d1-441b-82b7-e26e7680a17c','荆公墓二首  其二','范成大','宋','宋诗','song-poetry','','[]','本意治功徙木，何心黨禍揚塵。',28,'全唐诗/poet.song.136000.json','["本意治功徙木，何心黨禍揚塵。", "報讎豈教行劫，作俑翻成害仁。"]'),
('fb8880fd-cb17-4721-baad-62cabd093fdf','十月朔客建業不得與兄弟上冢之列悲感成詩','范成大','宋','宋诗','song-poetry','','[]','歲已看成暮，身今未得歸。',72,'全唐诗/poet.song.136000.json','["歲已看成暮，身今未得歸。", "風塵孤淚盡，霜露寸心違。", "南磵新流水，西山舊落暉。", "煙松應好在，宿草定成非。", "逝水方東去，浮雲浪北飛。", "危魂先自斷，不待更沾衣。"]'),
('1443948e-448b-449f-aebb-327e75864043','白鷺亭','范成大','宋','宋诗','song-poetry','','[]','倦遊客舍不勝閒，日日清江見倚闌。',32,'全唐诗/poet.song.136000.json','["倦遊客舍不勝閒，日日清江見倚闌。", "少待西風吹雨過，更從二水看淮山。"]'),
('7cb8e2ba-2dc2-4138-9c0d-2a3d76ac5949','臙脂井三首  其一','范成大','宋','宋诗','song-poetry','','[]','昭光殿下起樓臺，拚得山河付酒杯。',32,'全唐诗/poet.song.136000.json','["昭光殿下起樓臺，拚得山河付酒杯。", "春色已從金井去，月華空上石頭來。"]'),
('847306b9-8d8b-49aa-b7d9-75f15bad8e40','臙脂井三首  其二','范成大','宋','宋诗','song-poetry','','[]','午醉醒來一夢非，匆匆玉樹逐春歸。',32,'全唐诗/poet.song.136000.json','["午醉醒來一夢非，匆匆玉樹逐春歸。", "臙脂却作千年計，不似愁魂四散飛。"]'),
('63407948-4f2b-437d-a6de-fc649c7a9b64','臙脂井三首  其三','范成大','宋','宋诗','song-poetry','','[]','腰支旅拒更神遊，桃葉山前水自流。',32,'全唐诗/poet.song.136000.json','["腰支旅拒更神遊，桃葉山前水自流。", "三十六書都莫恨，煩將歌舞過揚州。"]'),
('c6faddf0-3f48-46cb-8dec-8d201b9685fd','秦淮','范成大','宋','宋诗','song-poetry','','[]','祖龍驅羣龍，疏此萬丈溝。',192,'全唐诗/poet.song.136000.json','["祖龍驅羣龍，疏此萬丈溝。", "雨工戀故棲，十步九回頭。", "至今秦淮曲，蜿若春蛇遊。", "舟師厭回互，歎息倚柂樓。", "維昔東巡初，八極圍寸眸。", "天端有佳氣，鬰鬰東南浮。", "卜云當興王，在後五百秋。", "叱咤召六丁，慘淡風雲愁。", "鑿渠斷地脈，自謂神與謀。", "乾坤有端倪，已露不可收。", "大帝開吳天，定鼎臨江陬。", "融融秣陵日，始照十二斿。", "經營暨六代，茲地稱神州。", "乃知歷數定，昧者徒私憂。", "茲事故老傳，未知信然不。", "姑置勿重陳，作詩歎遲留。"]'),
('d152e59f-0b7f-4e56-a58c-b56d764a229d','九月三日宿胥口始聞鴈','范成大','宋','宋诗','song-poetry','','[]','故人久不見，乍見雜悲喜。',144,'全唐诗/poet.song.136000.json','["故人久不見，乍見雜悲喜。", "新鴈如故人，一聲驚我起。", "把酒不能觴，送目問行李。", "曾雲行路難，空濛千萬里。", "塞北多關山，江南渺雲水。", "風高吹汝瘦，旅伴今餘幾。", "斜行不少駐，滅沒蒼煙裏。", "羈遊吾亦倦，客程殊未已。", "扁舟費年華，短纜繫沙尾。", "物生各有役，冥心聽行止。", "江郊匝地熟，場圃平如砥。", "歸期且忽念，共飽豐年米。"]'),
('e7296b0d-03a4-4692-8214-05b985b22284','欲雪','范成大','宋','宋诗','song-poetry','','[]','烏鴉撩亂舞黄雲，樓上飛花已唾人。',32,'全唐诗/poet.song.136000.json','["烏鴉撩亂舞黄雲，樓上飛花已唾人。", "說與江梅須早計，馮夷無頼欲爭春。"]'),
('cd13d8ac-41bb-4cdd-9d20-de08f220a46b','讀史三首  其一','范成大','宋','宋诗','song-poetry','','[]','百歲虧成費械機，烏鳶螻蟻竟同歸。',32,'全唐诗/poet.song.136000.json','["百歲虧成費械機，烏鳶螻蟻竟同歸。", "一檠燈火挑明滅，兩眼昏花管是非。"]'),
('d4608271-d37d-47da-b9d3-14b892d8defb','讀史三首  其二','范成大','宋','宋诗','song-poetry','','[]','堂堂列傳冠元功，紙上浮雲萬事空。',32,'全唐诗/poet.song.136000.json','["堂堂列傳冠元功，紙上浮雲萬事空。", "我若材堪當世用，他年應只似諸公。"]'),
('3c7cc082-ee48-43f2-8f6f-a20b3315c885','讀史三首  其三','范成大','宋','宋诗','song-poetry','','[]','鏤冰琢雪戰毛氂，畫餠聲名骨朽時。',32,'全唐诗/poet.song.136000.json','["鏤冰琢雪戰毛氂，畫餠聲名骨朽時。", "汗簡書青已兒戲，峴山辛苦更沉碑。"]'),
('03cc6d82-d190-4568-8e71-630c5399e350','宴坐菴四首  其一','范成大','宋','宋诗','song-poetry','','[]','油燈已暗忽微明，石鼎將乾尚有聲。',32,'全唐诗/poet.song.136000.json','["油燈已暗忽微明，石鼎將乾尚有聲。", "衲被蒙頭籠兩袖，藜牀無地著功名。"]'),
('64503ae5-5dad-43de-a044-7f548327b2d6','宴坐菴四首  其二','范成大','宋','宋诗','song-poetry','','[]','五更風竹閙軒窗，聽作江船浪隠牀。',32,'全唐诗/poet.song.136000.json','["五更風竹閙軒窗，聽作江船浪隠牀。", "枕上翻身尋斷夢，故人待漏滿鞾霜。"]'),
('72bbac4b-bb74-4d32-8215-fd7b6f1fd52d','宴坐菴四首  其三','范成大','宋','宋诗','song-poetry','','[]','粥魚吼罷鼓逢逢，卧聽饑鼯上曉釭。',32,'全唐诗/poet.song.136000.json','["粥魚吼罷鼓逢逢，卧聽饑鼯上曉釭。", "一點斜光明紙帳，悟知檐雀已穿窗。"]'),
('c1e227d3-9573-4f51-bafd-dca8c50fcde7','宴坐菴四首  其四','范成大','宋','宋诗','song-poetry','','[]','跏趺合眼是無何，靜裏惟聞鳥雀多。',32,'全唐诗/poet.song.136000.json','["跏趺合眼是無何，靜裏惟聞鳥雀多。", "俗客叩門稱問字，又煩居士起穿鞾。"]'),
('d08fe0e1-4e69-4f69-937e-a8206cb1d8b4','青青磵上松送致遠入官','范成大','宋','宋诗','song-poetry','','[]','青青磵上松，鬰鬰磵底柏。',132,'全唐诗/poet.song.136000.json','["青青磵上松，鬰鬰磵底柏。", "松森上曾雲，柏跼抱幽石。", "偃植雖不同，臭味乃相得。", "千霜與百雪，偶立衆芳側。", "衆芳豈不好，歲晏掃無迹。", "廣厦罩羣木，萬牛挽山澤。", "松材可世用，攀援入王國。", "草木豈有情，亦復念離析。", "君看此翠柏，錯莫無顔色。", "孤陰愁月夜，獨籟怨風夕。", "蒼官何當歸，相望長相憶。"]'),
('74459836-6422-41d1-a906-e3c1b70d6688','除夜感懷','范成大','宋','宋诗','song-poetry','','[]','松楸百年哀，霜露終歲悲。',216,'全唐诗/poet.song.136000.json','["松楸百年哀，霜露終歲悲。", "天地豈汝偏，鬼神諒無私。", "孤窮罪當爾，我今怨尤誰。", "噎絕夢自語，伶俜影相隨。", "豈無一經傳，政坐五鬼嗤。", "鑿枘共齟齬，榛荆費耘耔。", "付畀踰丘山，奉承劣毫釐。", "生男九族歡，所願作門楣。", "時命有大謬，生男竟何裨。", "匏瓜謾枵腹，蒲柳無真姿。", "蹙縮高顴頰，蕭騷短髯髭。", "貧病老歲月，斗杓坐成移。", "曉風凄以寒，簾幕相紛披。", "月星炯我冠，霧雨泫我衣。", "焄蒿奉祠事，苦淚落酒巵。", "逝者日已遠，生者日以衰。", "羸驂駕九折，日暮抱長饑。", "岐路正巉絕，耿耿誰當知。"]'),
('1d1d59a2-9031-4408-b353-b5d8dc2ca0dd','次韻唐子光席上賞梅','范成大','宋','宋诗','song-poetry','','[]','玉枝橫斜照清空，纖手撚香□□公。',96,'全唐诗/poet.song.136000.json','["玉枝橫斜照清空，纖手撚香□□公。", "水部無人廣平去，後來我輩猶情鍾。", "誰噴昭華送愁絕，叫雲三弄怨斜月。", "徑須踏雪問前村，莫待馬蹄如踣鐵。", "春風壓盡百花橋，尊前仍有董嬌嬈。", "惜無楚客歌成雪，空有蕭郎眼似刀。"]'),
('3e573e89-75a2-4a8e-b42c-e4acf718f087','夜行上沙見梅記東坡作詩招魂之句','范成大','宋','宋诗','song-poetry','','[]','玉妃謫人世，乃在流水村。',120,'全唐诗/poet.song.136000.json','["玉妃謫人世，乃在流水村。", "天風吹嬋娟，飄墮寂莫濱。", "芳心怨命薄，玉色凄路塵。", "佳人來無期，日暮多碧雲。", "溪聲爲咽絕，月亦低微顰。", "相逢倦遊子，一笑不復珍。", "脈脈問不語，亭亭意彌真。", "要我冰雪句，招此欲斷魂。", "蘇仙上賓天，妙意終難陳。", "璿柄忽傾墮，曉嵐愁翠昏。"]'),
('f39b1e6d-ba8e-4b40-b30b-97539df7c524','次韻唐子光教授河豚','范成大','宋','宋诗','song-poetry','','[]','世間尤物美惡并，江鄉未用誇吳羹。',160,'全唐诗/poet.song.136000.json','["世間尤物美惡并，江鄉未用誇吳羹。", "清宮洞房寒熱媒，深山大澤龍蛇生。", "胡夷信美胎殺氣，不奈吳兒苦知味。", "楊花欲動荻芽肥，汙手死心搖食指。", "食魚要是□黄粱，古來不必須河魴。", "君看嗔腹似渾脫，寧肯滑甘隨芥薑。", "先生法語峻立壁，譏評不使一錢直。", "膨亨從此迹如掃，坐令梅老詩無力。", "懸知仙骨有青冥，風香久已滌羶腥。", "大笑日華解毒法，何如肘後餐霞經。"]'),
('b980b1cd-9800-4398-8c5b-dfd6a166b5ed','題如夢堂壁','范成大','宋','宋诗','song-poetry','','[]','勃姑午啼喚雨，鵯鵊曉囀留春。',28,'全唐诗/poet.song.136000.json','["勃姑午啼喚雨，鵯鵊曉囀留春。", "片雲不載歸夢，兩鬢全供客塵。"]'),
('329049b6-0896-4f94-adb5-7e3f8dd26931','曉起','范成大','宋','宋诗','song-poetry','','[]','簾額繡波蕩漾，燭盤紅淚闌干。',28,'全唐诗/poet.song.136000.json','["簾額繡波蕩漾，燭盤紅淚闌干。", "夢裏五更風急，愁邊一半春殘。"]'),
('ba1c018b-5b9a-42dd-bbb2-d5df86af1bc2','再遊上方','范成大','宋','宋诗','song-poetry','','[]','僧共老花俱在，客將春鴈同回。',28,'全唐诗/poet.song.136000.json','["僧共老花俱在，客將春鴈同回。", "范叔一寒如此，劉郎前度曾來。"]'),
('36740830-6172-476b-8a04-ad9378ff0ed7','即事','范成大','宋','宋诗','song-poetry','','[]','醉袖籠鞭轉柳塘，青門芳樹掩殘香。',32,'全唐诗/poet.song.136000.json','["醉袖籠鞭轉柳塘，青門芳樹掩殘香。", "誰驚翡翠雙飛去，衹有蓮花對斷腸。"]'),
('c0e9529b-bcf1-4c25-a4a6-e2ccad613f0e','春晚即事','范成大','宋','宋诗','song-poetry','','[]','屋頭清樾暗荆扉，紫葚斕斑翠莢肥。',32,'全唐诗/poet.song.136000.json','["屋頭清樾暗荆扉，紫葚斕斑翠莢肥。", "春晚軒窗人獨困，日長籬落燕雙飛。"]'),
('f0fc6869-7b12-496b-93e8-182edca0ebee','春晚三首  其一','范成大','宋','宋诗','song-poetry','','[]','陰陰垂柳閉朱門，一曲闌干一斷魂。',32,'全唐诗/poet.song.136000.json','["陰陰垂柳閉朱門，一曲闌干一斷魂。", "手把青梅春已去，滿城風雨怕黄昏。"]'),
('ca25a2c3-77ff-4a84-9dba-14c58db9e6cf','春晚三首  其二','范成大','宋','宋诗','song-poetry','','[]','客去鉤窗詠小詩，遊絲撩亂柳花稀。',32,'全唐诗/poet.song.136000.json','["客去鉤窗詠小詩，遊絲撩亂柳花稀。", "微風盡日吹芳草，蝴蝶雙雙貼地飛。"]'),
('bb3e24ad-6d92-4de0-9196-58221d2e82d3','春晚三首  其三','范成大','宋','宋诗','song-poetry','','[]','夕陽槐影上簾鈎，一枕清風夢昔遊。',32,'全唐诗/poet.song.136000.json','["夕陽槐影上簾鈎，一枕清風夢昔遊。", "夢見錢塘春盡處，碧桃花謝水西流。"]'),
('2c4cc0aa-e9d7-4a94-8bf9-a95a0a2a6245','樂先生闢新堂以待芍藥酴醿作詩奉贈','范成大','宋','宋诗','song-poetry','','[]','芍藥有國色，酴醿乃天香。',156,'全唐诗/poet.song.136000.json','["芍藥有國色，酴醿乃天香。", "二妙絕世立，百草爲不芳。", "先生絕俗姿，風味本無雙。", "年來悟結習，欲試安心方。", "天魔巧伺便，作計迴剛腸。", "多情開此花，艷絕溫柔鄉。", "道人爲一笑，正爾未易忘。", "呼童葺荷芷，擇勝開軒窗。", "啼鶑不愁思，遊蜂亦猖狂。", "百年顰呻頃，共此過隙光。", "朝爲春條綠，暮爲秋葉黄。", "把翫尚無幾，況以憂愁妨。", "願言秉燭遊，迨此春宵長。"]'),
('71c2ba08-a326-414d-a3af-b390c2e89ebc','題城山晚對軒壁','范成大','宋','宋诗','song-poetry','','[]','一枕清風夢綠蘿，人間隨處是南柯。',32,'全唐诗/poet.song.136000.json','["一枕清風夢綠蘿，人間隨處是南柯。", "也知睡足當歸去，不奈溪山留客何。"]'),
('07c71969-0265-41f5-93cb-802fbea3b232','題城山挂月堂壁','范成大','宋','宋诗','song-poetry','','[]','百疊煙鬟得眼明，坐來心跡喜雙清。',32,'全唐诗/poet.song.136000.json','["百疊煙鬟得眼明，坐來心跡喜雙清。", "秋陽滿地西風起，猶有啼鶑四五聲。"]'),
('8ed2ea2f-7957-4407-a962-283e181f9f65','姑惡','范成大','宋','宋诗','song-poetry','','[]','姑惡婦所云，恐是婦偏辭。',52,'全唐诗/poet.song.136000.json','["姑惡婦所云，恐是婦偏辭。", "姑言婦惡定有之，婦言姑惡未可知。", "姑不惡，婦不死。", "與人作婦亦大難，已死人言尚如此。"]'),
('5921d850-9b57-4bc3-bde0-ab481722adca','大暑舟行含山道中雨驟至霆奔龍挂可駭','范成大','宋','宋诗','song-poetry','','[]','隤雲曖前驅，連鼓訌後殿。',204,'全唐诗/poet.song.136000.json','["隤雲曖前驅，連鼓訌後殿。", "駸駸失高丘，擾擾暗古縣。", "白龍起幽蟄，黑霧佐神變。", "盆傾耳雙聵，斗暗目四眩。", "帆重腹逾飽，櫓潤鳴更健。", "圓漪暈雨點，濺滴走波面。", "伶俜愁孤鴛，颭閃亂饑燕。", "麥老枕水卧，秧穉與風戰。", "牛蹊岌城沉，蟻隧洶瓴建。", "水車競施行，歲事敢休宴。", "咿啞嘯簧鳴，轣轆連鎖轉。", "駢頭立婦子，列舍望宗伴。", "東枯駭西潰，寸涸驚尺澱。", "嗟余豈能賢，與彼亦何辨。", "扁舟風露熟，半世江湖徧。", "不知憂稼穡，但解加餐飯。", "遥憐老農苦，敢厭遊子倦。"]'),
('7c2dcddf-a200-45f0-840a-d3be97d3d0fe','題畫卷五首  其一','范成大','宋','宋诗','song-poetry','','[]','鑿落秋江水石明，高楓老柳兩灘橫。',32,'全唐诗/poet.song.136000.json','["鑿落秋江水石明，高楓老柳兩灘橫。", "君看疊巘雲容變，又有中宵雨意生。"]'),
('82cf4fd8-65b1-4503-84df-97252120d7e7','題畫卷五首  其二','范成大','宋','宋诗','song-poetry','','[]','欹傾棧路繞山明，隔隴人家犬吠聲。',32,'全唐诗/poet.song.136000.json','["欹傾棧路繞山明，隔隴人家犬吠聲。", "無限白雲堆去路，不知誰識許宣平。"]'),
('378fc6f0-7942-4e2b-ab05-924d008bb939','題畫卷五首  其三','范成大','宋','宋诗','song-poetry','','[]','春陰十日溪頭暗，夜半西風雨脚收。',32,'全唐诗/poet.song.136000.json','["春陰十日溪頭暗，夜半西風雨脚收。", "但覺奔霆吼空谷，遥知萬壑正爭流。"]'),
('00dbdc36-9c96-488b-bf17-1fe6ced51b6c','題畫卷五首  其四','范成大','宋','宋诗','song-poetry','','[]','暑雲潑墨送驚雷，坐見前山驟雨來。',32,'全唐诗/poet.song.136000.json','["暑雲潑墨送驚雷，坐見前山驟雨來。", "今夜一凉千萬里，更無焦卷與塵埃。"]'),
('ddc22284-f0bb-46d9-941d-9713bef6009a','題畫卷五首  其五','范成大','宋','宋诗','song-poetry','','[]','秋晚黄蘆斷岸，江南野水連天。',28,'全唐诗/poet.song.136000.json','["秋晚黄蘆斷岸，江南野水連天。", "日色微明魚網，鴈行飛入蒼煙。"]'),
('a1ae0dd4-5be3-46e2-b555-e158389f6cc7','六月七日夜起坐殿廡取凉','范成大','宋','宋诗','song-poetry','','[]','畏暑中夜起，出門月露清。',144,'全唐诗/poet.song.136000.json','["畏暑中夜起，出門月露清。", "晶熒卧銀漢，錯落低玉繩。", "網戶閉妙香，石樓棲古燈。", "風從何處來，殿閣微凉生。", "桂旗儼不動，藻井森上征。", "榱楣共突兀，鬼物相枝撐。", "彭觥鐵拄杖，磔磔棲燕驚。", "俗人豈解事，鼻息春雷鳴。", "大星送曉來，四窗炯微明。", "顥氣澡肌骨，栩栩兩腋輕。", "乘風欲歸去，驂鸞羾青冥。", "却恐方平知，浪得狡獪名。"]'),
('4f75b2e0-971c-4be7-8b9e-ac9015b195f4','中秋卧病呈同社','范成大','宋','宋诗','song-poetry','','[]','人間佳風月，浩浩滿大千。',108,'全唐诗/poet.song.136000.json','["人間佳風月，浩浩滿大千。", "俗子不解愛，我乃知其天。", "以此有盡姿，翫彼無窮妍。", "受用能幾何，北溟一杯然。", "天公尚齟齬，不肯畀其全。", "卧病窘詩料，坐貧羞酒錢。", "瓊樓與金闕，想像屋角邊。", "如聞真率社，勝遊若登仙。", "四者自難并，造物豈我偏。"]'),
('7bab07a8-6a25-47c5-a4fa-b2deee87600b','秋日雜興六首  其一','范成大','宋','宋诗','song-poetry','','[]','我友蓬蒿士，却掃謝四鄰。',108,'全唐诗/poet.song.136000.json','["我友蓬蒿士，却掃謝四鄰。", "內無三尺童，外無雙蒲輪。", "豈非騏驥姿，執轡難其人。", "無衣可御冬，忍寒待陽春。", "仰雲發永歎，夜作寒螿呻。", "奓戶勸之起，懷寶善自珍。", "秋月耿清夜，秋風捲曾雲。", "佳哉爲誰歟，定爲我與君。", "莫嫌酒味薄，聊復相歡欣。"]'),
('d0390a86-6c40-4f80-8dfd-d7588880d99f','秋日雜興六首  其二','范成大','宋','宋诗','song-poetry','','[]','夕陽下桑柘，餘暉挂西山。',84,'全唐诗/poet.song.136000.json','["夕陽下桑柘，餘暉挂西山。", "西山在何許，冉冉紫翠間。", "綵雲無朝昏，綠蘿竟暄寒。", "昔與霞上人，同跨雙飛翰。", "上凌紫霄峰，下弄白石湍。", "風吹墮渺莽，及此行路難。", "佳人應望予，我豈真忘還。"]'),
('d449600a-bb28-4592-aeb3-f7abc4b43ae6','秋日雜興六首  其三','范成大','宋','宋诗','song-poetry','','[]','秋高氣彌清，歲晏天雨霜。',60,'全唐诗/poet.song.136000.json','["秋高氣彌清，歲晏天雨霜。", "繁枝各病綠，況乃枝上香。", "向來不勝春，渺在無何鄉。", "樂極定自悲，誰歟此更張。", "春秋無終窮，榮落殊未央。"]'),
('df13424e-b115-4569-b5aa-2535b420e846','秋日雜興六首  其四','范成大','宋','宋诗','song-poetry','','[]','嫣嫣芙蓉花，秀出清霜晨。',84,'全唐诗/poet.song.136000.json','["嫣嫣芙蓉花，秀出清霜晨。", "衆卉已昨夢，孤芳若爲新。", "寒蜂無儇飛，一笑靜自珍。", "誰令嬋娟姿，墮此寂寞濱。", "絕世貴獨立，後時莫酸辛。", "回風佐小舞，薄日生微醺。", "即事亦足樂，何必桃李塵。"]'),
('c572f4df-a658-4c79-80c6-d6f7b833ec72','秋日雜興六首  其五','范成大','宋','宋诗','song-poetry','','[]','蒼筠如蒼玉，鄉是磵壑姿。',72,'全唐诗/poet.song.136000.json','["蒼筠如蒼玉，鄉是磵壑姿。", "朅來西窗下，死生付汙泥。", "蟲緣有病葉，土瘦無新枝。", "太陽豈我偏，檐影爲蔽虧。", "昔如松柏獨，今作蒲柳衰。", "暮夜風雨急，歲晏誰與歸。"]'),
('afd360c7-85c7-48c5-9aba-020c65be25bc','秋日雜興六首  其六','范成大','宋','宋诗','song-poetry','','[]','屋東雙梧桐，婉娩無真姿。',60,'全唐诗/poet.song.136000.json','["屋東雙梧桐，婉娩無真姿。", "朝爲春風條，暮爲秋霜枝。", "夜久風葉鳴，驚鵲一再飛。", "梧桐不足愁，會有明年期。", "人老真可歎，寧復遊冶時。"]'),
('4bd805bc-c4ac-4214-87f4-e1a5d3c38d02','擬古','范成大','宋','宋诗','song-poetry','','[]','彎環樓前月，掩抑樓上人。',48,'全唐诗/poet.song.136000.json','["彎環樓前月，掩抑樓上人。", "人月不得語，相看兩凝顰。", "西窗回紋機，織徧錦字春。", "聊可自持翫，何由將寄君。"]'),
('8a2555fc-f2d6-461d-b0b8-47abb94ad8fb','立春日郊行','范成大','宋','宋诗','song-poetry','','[]','竹擁溪橋麥蓋坡，土牛行處亦笙歌。',64,'全唐诗/poet.song.136000.json','["竹擁溪橋麥蓋坡，土牛行處亦笙歌。", "麴塵欲暗垂垂柳，醅面初明淺淺波。", "日滿縣前春市合，潮平浦口暮帆多。", "春來不飲兼無句，奈此金旛綵勝何。"]'),
('16d3a4e8-bb6f-4a23-8072-a5177387135f','次韻漢卿舅即事二絕  其一','范成大','宋','宋诗','song-poetry','','[]','風捲南枝一夜休，孤芳寧肯爲人留。',32,'全唐诗/poet.song.136000.json','["風捲南枝一夜休，孤芳寧肯爲人留。", "淡粧素服真成夢，落月橫參各自愁。"]'),
('c9c863b0-0722-41b3-be09-af7db255b377','次韻漢卿舅即事二絕  其二','范成大','宋','宋诗','song-poetry','','[]','萬木垂垂欲改柯，根萌焦渴奈春何。',32,'全唐诗/poet.song.136000.json','["萬木垂垂欲改柯，根萌焦渴奈春何。", "晚來礎汗南風壯，會有溪雲載雨過。"]'),
('7bcbf9c1-9695-4356-9fe7-c46ebcd171a1','晚潮','范成大','宋','宋诗','song-poetry','','[]','東風吹雨晚潮生，疊鼓催船鏡裏行。',32,'全唐诗/poet.song.136000.json','["東風吹雨晚潮生，疊鼓催船鏡裏行。", "底事今年春漲小，去年曾與畫橋平。"]'),
('c03aaf2d-5582-44aa-bcbe-4dfa09f8f94b','一篙','范成大','宋','宋诗','song-poetry','','[]','一篙新綠浦東西，雪絮漫江鴈不飛。',32,'全唐诗/poet.song.136000.json','["一篙新綠浦東西，雪絮漫江鴈不飛。", "宿雨纔晴風又轉，片帆那得及時歸。"]'),
('bf98520d-726f-4787-84e1-6128d3249be5','碧瓦','范成大','宋','宋诗','song-poetry','','[]','碧瓦樓頭繡幙遮，赤欄橋外綠溪斜。',32,'全唐诗/poet.song.136000.json','["碧瓦樓頭繡幙遮，赤欄橋外綠溪斜。", "無風楊柳漫天絮，不雨棠梨滿地花。"]'),
('0baf9992-a128-42bc-86d9-75a13dcf503c','題記事冊','范成大','宋','宋诗','song-poetry','','[]','劃破虛空一劍間，六根同轉上頭關。',32,'全唐诗/poet.song.136000.json','["劃破虛空一劍間，六根同轉上頭關。", "如今宴坐菴中事，政在凡夫道法間。"]'),
('c5062f22-40e2-4b76-b7be-a82143782bea','暮春上塘道中','范成大','宋','宋诗','song-poetry','','[]','店舍無煙野水寒，競船人醉鼓闌珊。',64,'全唐诗/poet.song.136000.json','["店舍無煙野水寒，競船人醉鼓闌珊。", "石門柳綠清明市，洞口桃紅上巳山。", "飛絮著人春共老，片雲將夢晚俱還。", "明朝遮日長安道，慚愧江湖釣手閒。"]'),
('cefa2633-df7f-4518-8fb5-0dcfb4021d21','江上','范成大','宋','宋诗','song-poetry','','[]','天色無情淡，江聲不斷流。',24,'全唐诗/poet.song.136000.json','["天色無情淡，江聲不斷流。", "古人愁不盡，留與後人愁。"]'),
('457096f6-57cf-4b99-a516-60f5ca5f0cd7','餘杭道中','范成大','宋','宋诗','song-poetry','','[]','落花流水淺深紅，盡日帆飛繡浪中。',64,'全唐诗/poet.song.136000.json','["落花流水淺深紅，盡日帆飛繡浪中。", "桑眼迷離應欠雨，麥鬚騷殺已禁風。", "牛羊路杳千山合，雞犬村深一徑通。", "五柳能消多許地，客程何苦鎮匆匆。"]'),
('b8c06960-5833-4fb7-862c-907d639009c9','陳侍御園坐上','范成大','宋','宋诗','song-poetry','','[]','愁眼逢歡春水明，詩情得酒春雲生。',64,'全唐诗/poet.song.136000.json','["愁眼逢歡春水明，詩情得酒春雲生。", "花梢蝴蝶作團去，竹裏鵓鳩相對鳴。", "邂逅浮生此日好，纏綿俗累何時輕。", "擘牋沫墨乏奇句，擫笛當筵慚妙聲。"]'),
('a30c9945-b654-453c-bda9-ad024ab89cf4','獨遊虎跑泉小菴','范成大','宋','宋诗','song-poetry','','[]','苔徑彎環入，茅齋取次成。',48,'全唐诗/poet.song.136000.json','["苔徑彎環入，茅齋取次成。", "蔓花緣壁起，閒草上階生。", "宿雨松篁色，新晴燕雀聲。", "筒泉烹御米，聊共老僧傾。"]'),
('ba435f5e-29ba-4b73-a49d-9212ff0d5d84','王希武通判挽詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','當代名臣後，惟公奕世賢。',48,'全唐诗/poet.song.136000.json','["當代名臣後，惟公奕世賢。", "及親三釜養，遺子一經傳。", "藥石探奇字，芸香緝斷編。", "堂堂今不見，塵迹自依然。"]'),
('2d90df4f-797b-4513-b24c-5c64c81984fb','王希武通判挽詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','事契從先世，姻聯亦近親。',48,'全唐诗/poet.song.136000.json','["事契從先世，姻聯亦近親。", "遽爲重壤去，凄斷十年鄰。", "物理真飄忽，家聲正隠轔。", "門闌可三戟，何止駟車云。"]'),
('ae70b50b-e1b7-4af8-9909-10b323b1c9c4','劇暑','范成大','宋','宋诗','song-poetry','','[]','赫赫炎官張傘，啾啾赤帝騎龍。',28,'全唐诗/poet.song.136000.json','["赫赫炎官張傘，啾啾赤帝騎龍。", "安得雷轟九地，會令雨起千峰。"]'),
('439f2e25-c4fb-4383-bfe4-4d999633159e','次韻時敘','范成大','宋','宋诗','song-poetry','','[]','新春殘春一夢間，夢中兀兀長閉關。',64,'全唐诗/poet.song.136000.json','["新春殘春一夢間，夢中兀兀長閉關。", "今朝出門春已去，但見新笋齊屋山。", "作詩惜春聊復爾，春亦何能與人事。", "閒心如絮久沾泥，但愛日長添午睡。"]'),
('410b5364-9e1c-43a4-afb0-213a1a676b89','夜宴曲','范成大','宋','宋诗','song-poetry','','[]','金麟噴香煙龍蟠，玉燈九枝青闌干。',72,'全唐诗/poet.song.136000.json','["金麟噴香煙龍蟠，玉燈九枝青闌干。", "明瓊翠带湘簾斑，風幃繡浪千飛鸞。", "舞娥紫袖如弓彎，雲中一笑天解顔。", "銜杯快卷玻璃乾，花樓促箭春宵寒，二十五聲宮點闌。"]'),
('0352898b-be66-45fa-a57c-bb7c90a5cce5','神弦','范成大','宋','宋诗','song-poetry','','[]','雙娥一去三千秋，粉篁春淚凝古愁。',64,'全唐诗/poet.song.136000.json','["雙娥一去三千秋，粉篁春淚凝古愁。", "神鼉悲鳴老龍怨，水爲翻瀾雲爲留。", "素空逗露晚花泣，神官行水鱗僮濕。", "潮聲不平江風急，蒼梧冥茫九山立。"]'),
('e5c5531f-c866-4a0d-b119-6bf2617234af','樂神曲','范成大','宋','宋诗','song-poetry','','[]','豚蹄滿盤酒滿盃，清風蕭蕭神欲來。',64,'全唐诗/poet.song.136000.json','["豚蹄滿盤酒滿盃，清風蕭蕭神欲來。", "願神好來復好去，男兒拜迎女兒舞。", "老翁翻香笑且言，今年田家勝去年。", "去年解衣折租價，今年有衣著祭社。"]'),
('86738978-eae6-4225-83a2-934604dd5121','繰絲行','范成大','宋','宋诗','song-poetry','','[]','小麥青青大麥黄，原頭日出天色凉。',64,'全唐诗/poet.song.136000.json','["小麥青青大麥黄，原頭日出天色凉。", "姑婦相呼有忙事，舍後煮繭門前香。", "繰車嘈嘈似風雨，繭厚絲長無斷縷。", "今年那暇織絹著，明日西門賣絲去。"]'),
('2cf1edb3-1544-4921-95ad-ddee87719647','田家留客行','范成大','宋','宋诗','song-poetry','','[]','行人莫笑田家小，門戶雖低堪灑掃。',64,'全唐诗/poet.song.136000.json','["行人莫笑田家小，門戶雖低堪灑掃。", "大兒繫馿桑樹邊，小兒拂席軟勝氈。", "木臼新舂雪花白，急炊香飯來看客。", "好人入門百事宜，今年不憂蠶麥遲。"]'),
('04d3b2db-0fa6-4378-a4f7-7ae9944cfff5','催租行','范成大','宋','宋诗','song-poetry','','[]','輸租得鈔官更催，踉蹡里正敲門來。',64,'全唐诗/poet.song.136000.json','["輸租得鈔官更催，踉蹡里正敲門來。", "手持文書雜嗔喜，我亦來營醉歸耳。", "牀頭慳囊大如拳，撲破正有三百錢。", "不堪與君成一醉，聊復償君草鞋費。"]'),
('ce0ec8c4-4e0b-42bb-b972-082abf667790','緘口翁','范成大','宋','宋诗','song-poetry','','[]','君子取中道，常在語默間。',91,'全唐诗/poet.song.136000.json','["君子取中道，常在語默間。", "多言固自費，不語良獨難。", "此翁身如鄭文淵，辨如懸河思如泉。", "邇來緘口欲挂壁，囁嚅畏客翻可憐。", "君不見東家玉壺本弟兄，叩之猶解語分明。", "願聞胚渾甚深義，定自能令一座傾。"]'),
('84cc9138-60cd-4d9e-a639-649dd4adf770','春思','范成大','宋','宋诗','song-poetry','','[]','沙際綠蘋滿，樓頭芳樹多。',56,'全唐诗/poet.song.136000.json','["沙際綠蘋滿，樓頭芳樹多。", "光風入網戶，羅幕生繡波。", "前年花開憶湘水，今年花開淚如洗。", "園樹傷心三見花，依舊銀屏夢千里。"]'),
('6318e0b2-0c66-43e7-bb11-3c2600f5993c','次韻漢卿舅臘梅二首  其一','范成大','宋','宋诗','song-poetry','','[]','垂垂瘦萼泫微霜，剪剪纖英鎖暗香。',32,'全唐诗/poet.song.136000.json','["垂垂瘦萼泫微霜，剪剪纖英鎖暗香。", "金雀釵頭金蛺蝶，春風傳得舊宮粧。"]'),
('5c669c7f-95c1-4a21-a1c4-c0f6981506a1','次韻漢卿舅臘梅二首  其二','范成大','宋','宋诗','song-poetry','','[]','湘袂朝天紫錦裳，光風微度絳霄香。',32,'全唐诗/poet.song.136000.json','["湘袂朝天紫錦裳，光風微度絳霄香。", "壽陽信美無仙骨，空把心情學澹粧。"]'),
('299b9cd8-60df-48de-a186-9999b4010d2a','宿東寺二首  其一','范成大','宋','宋诗','song-poetry','','[]','淡天如水霧如塵，殘雪和霜凍瓦鱗。',32,'全唐诗/poet.song.136000.json','["淡天如水霧如塵，殘雪和霜凍瓦鱗。", "織女無言千古恨，素娥有意十分春。"]'),
('5b95859b-8fb5-4850-9997-3d62a2e39af0','宿東寺二首  其二','范成大','宋','宋诗','song-poetry','','[]','一聲黄鵠夜深歸，栖雀驚鳴觸殿扉。',32,'全唐诗/poet.song.136000.json','["一聲黄鵠夜深歸，栖雀驚鳴觸殿扉。", "北斗半垂樓閣外，風旛渾欲上雲飛。"]'),
('64ba49ca-ea5a-43d1-b93d-30b7d8d1100e','範老前歲相別約歸括蒼便游四明今不知何地暇日有懷','范成大','宋','宋诗','song-poetry','','[]','春色重來意未闌，故人一去肯復還。',64,'全唐诗/poet.song.136000.json','["春色重來意未闌，故人一去肯復還。", "括蒼洞天掃舊隠，補陀海岸尋神山。", "杖屨雲煙遠遊樂，衣裳風雪行路難。", "鴻飛冥冥鷗浩蕩，安得置之雞鶩間。"]'),
('4ae7727b-7bdd-4686-beb6-3fd5da853125','癸亥日泊舟吳會亭','范成大','宋','宋诗','song-poetry','','[]','去年春盤浙江驛，湛湛清波動浮石。',96,'全唐诗/poet.song.136000.json','["去年春盤浙江驛，湛湛清波動浮石。", "今年春盤吳會亭，冥冥細雨濕高城。", "天邊作客風沙裏，今年去年成老矣。", "客心古井冷無波，過眼人情亦如水。", "憶昔三生住翠微，偶來平地著征衣。", "山中故人應大笑，扁舟坐穩何當歸。"]'),
('7ea3fea1-0bfd-4b9b-aebf-ee67821469c4','時敘火後意不釋然作詩解之','范成大','宋','宋诗','song-poetry','','[]','潘郎曉衾夢蘧蘧，舞馬竟與融風俱。',176,'全唐诗/poet.song.136000.json','["潘郎曉衾夢蘧蘧，舞馬竟與融風俱。", "前驅炎官後熱屬，席捲不貸淵明廬。", "君家十年四立壁，震風凌雨啼妻孥。", "平生白眼蓋九州，閉戶不納結駟車。", "清貧往往被鬼笑，付與一炬相揶揄。", "井垔木刊烏鼠赭，汝則暫戲吾何辜。", "天闕悠悠虎豹怒，叱閽上訴非良圖。", "作詩聊復相料理，甑墮已破空踟躕。", "浮生適來且適去，況此茅屋三間餘。", "掃除劫灰得空闊，新月恰上東牆隅。", "幕天席地正可樂，爲君鼓旗助歌呼。"]'),
('f9a90ff1-a678-4652-b52d-8599d1b3506b','題湯致遠運使所藏隆師四圖 欠伸','范成大','宋','宋诗','song-poetry','','[]','春風吹夢驀江飛，行盡江南只片時。',64,'全唐诗/poet.song.136000.json','["春風吹夢驀江飛，行盡江南只片時。", "深院無人自驚覺，夕陽芳樹乳鴉啼。", "背立粧臺髻鬟懶，鏡鸞應見茸茸眼。", "不須回首更嫣然，劉郎已自無腸斷。"]'),
('e05e0dee-739a-4faa-b857-79c5bdb44f57','題湯致遠運使所藏隆師四圖 倦繡','范成大','宋','宋诗','song-poetry','','[]','猧兒弄煖緣階走，花氣薰人濃似酒。',64,'全唐诗/poet.song.136000.json','["猧兒弄煖緣階走，花氣薰人濃似酒。", "困來如醉復如愁，不管低鬟釵燕溜。", "無端心緒向天涯，想見檣竿旛脚斜。", "槐陰忽到簾旌上，遲却尋常一線花。"]'),
('8640d4c5-bf1a-43f7-8de3-c286373c5c03','題湯致遠運使所藏隆師四圖 倚竹','范成大','宋','宋诗','song-poetry','','[]','輕薄人情翻覆手，冰容却耐幽居久。',64,'全唐诗/poet.song.136000.json','["輕薄人情翻覆手，冰容却耐幽居久。", "關中舊事逐春休，付與新人莫迴首。", "目送斜陽忘却歸，竹風搖曳翠羅衣。", "君看脈脈無言處，中有杜陵饑客詩。"]'),
('315ff65d-4bdc-44a7-84ad-783e394d9b92','題湯致遠運使所藏隆師四圖 嗅梅','范成大','宋','宋诗','song-poetry','','[]','雪意勒花愁未解，背陰一朶寒先退。',64,'全唐诗/poet.song.136000.json','["雪意勒花愁未解，背陰一朶寒先退。", "東風還是去年香，不比人心容易改。", "宿酒瞢騰正耐春，花枝人面兩時新。", "相看好作風流伴，只恐花枝却妒人。"]'),
('14175c47-e9d9-480f-80a8-f32477ac7590','晚步','范成大','宋','宋诗','song-poetry','','[]','排門簾幕夜香飄，燈火人聲小市橋。',32,'全唐诗/poet.song.136000.json','["排門簾幕夜香飄，燈火人聲小市橋。", "滿縣月明春意好，旗亭吹笛近元宵。"]'),
('931651e2-0897-4b3d-bcdc-adc38c3f530b','題開元天寶遺事四首  其一','范成大','宋','宋诗','song-poetry','','[]','御前羯鼓透春空，笑覺花奴手未工。',32,'全唐诗/poet.song.136000.json','["御前羯鼓透春空，笑覺花奴手未工。", "一曲打開紅杏蕊，須知天子是天公。"]'),
('54f0603c-a624-4491-b63b-f604d0f1eaa2','題開元天寶遺事四首  其二','范成大','宋','宋诗','song-poetry','','[]','謝蠻舞袖貴妃弦，秦國如花虢國妍。',32,'全唐诗/poet.song.136000.json','["謝蠻舞袖貴妃弦，秦國如花虢國妍。", "不賞纏頭三百萬，阿姨何處費金錢。"]'),
('4d3a0bd7-8913-4062-87b6-9662fe2f6c44','題開元天寶遺事四首  其三','范成大','宋','宋诗','song-poetry','','[]','朝天車馬詔頻催，斸得新湯未敢開。',32,'全唐诗/poet.song.136000.json','["朝天車馬詔頻催，斸得新湯未敢開。", "忽報豬龍掀宇宙，阿瞞虛讀相書來。"]'),
('32448513-bcde-4325-83b0-0fbb23a2a84e','題開元天寶遺事四首  其四','范成大','宋','宋诗','song-poetry','','[]','剝啄延秋屋上烏，明朝箭道入東都。',32,'全唐诗/poet.song.136000.json','["剝啄延秋屋上烏，明朝箭道入東都。", "宮中亦有風流陣，不及漁陽突騎粗。"]'),
('0c3211f5-a724-4e84-8ef5-34cdd0a1a1d5','讀甘露遺事二首  其一','范成大','宋','宋诗','song-poetry','','[]','神理人情本不同，絕憐鼠輩倖元功。',32,'全唐诗/poet.song.136000.json','["神理人情本不同，絕憐鼠輩倖元功。", "天公盍假毛氂助，成敗都懸反掌中。"]'),
('94771464-c909-4583-8edd-a7f43d3775e1','讀甘露遺事二首  其二','范成大','宋','宋诗','song-poetry','','[]','上林輦路草青青，誰向憑高識聖情。',32,'全唐诗/poet.song.136000.json','["上林輦路草青青，誰向憑高識聖情。", "謾展東封圖畫看，不如醲酒亂平生。"]'),
('3d458683-82f9-4a83-817f-5749169c9208','半塘','范成大','宋','宋诗','song-poetry','','[]','柳暗閶門逗曉開，半塘塘下越溪回。',32,'全唐诗/poet.song.136000.json','["柳暗閶門逗曉開，半塘塘下越溪回。", "炊煙擁柂船船過，芳草緣堤步步來。"]'),
('95635794-6d95-40ae-8ec7-5dcd5c5c21a6','楓橋','范成大','宋','宋诗','song-poetry','','[]','朱門白壁枕彎流，桃李無言滿屋頭。',32,'全唐诗/poet.song.136000.json','["朱門白壁枕彎流，桃李無言滿屋頭。", "牆上浮圖路傍堠，送人南北管離愁。"]'),
('acc9679c-6bb3-4da9-904a-984c411cfbbd','橫塘','范成大','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u5b8b\u8bd7", "\u5199\u666f", "\u4f24\u6000"]','南浦春來綠一川，石橋朱塔兩依然。',32,'全唐诗/poet.song.136000.json','["南浦春來綠一川，石橋朱塔兩依然。", "年年送客橫塘路，細雨垂楊繫畫船。"]'),
('20130dc3-6e18-4dac-9941-1f21349bc737','胥口','范成大','宋','宋诗','song-poetry','','[]','扁舟拍浪信西東，何處孤帆萬里風。',32,'全唐诗/poet.song.136000.json','["扁舟拍浪信西東，何處孤帆萬里風。", "一雨快晴雲放樹，兩山中斷水粘空。"]'),
('10a91f3d-279b-4729-8b5c-c92148c875c9','香山','范成大','宋','宋诗','song-poetry','','[]','採香徑裏木蘭舟，嚼蕊吹芳爛熳遊。',32,'全唐诗/poet.song.136000.json','["採香徑裏木蘭舟，嚼蕊吹芳爛熳遊。", "落日青山都好在，桑間蕎麥滿芳洲。"]'),
('0275f932-f788-4730-95f9-d83b2fe5890a','上沙','范成大','宋','宋诗','song-poetry','','[]','水邊犬吠隔疎林，籬落蕭森日半陰。',32,'全唐诗/poet.song.136000.json','["水邊犬吠隔疎林，籬落蕭森日半陰。", "繁杏鎖紅春意淺，晚梅飄粉暮寒深。"]'),
('e7f796ad-d5de-46ab-9abf-323bb99d0899','天平寺','范成大','宋','宋诗','song-poetry','','[]','舊遊彷彿記三年，轟飲題詩夜滿山。',32,'全唐诗/poet.song.136000.json','["舊遊彷彿記三年，轟飲題詩夜滿山。", "山上白雲應解笑，又將塵土涴朱顔。"]'),
('5970f55e-9054-4f7f-844f-3b4d0eb7092e','白雲泉','范成大','宋','宋诗','song-poetry','','[]','龍頭高啄嗽飛流，玉醴甘渾乳氣浮。',32,'全唐诗/poet.song.136000.json','["龍頭高啄嗽飛流，玉醴甘渾乳氣浮。", "捫腹煮泉烹鬭胯，真成騎鶴上揚州。"]'),
('00b52fa6-f0cf-44bc-a6f3-d5871d6998a2','山頂','范成大','宋','宋诗','song-poetry','','[]','翠屏無路强攀緣，我與枯藤各半仙。',32,'全唐诗/poet.song.136000.json','["翠屏無路强攀緣，我與枯藤各半仙。", "不敢高聲天闕近，人間漠漠但寒煙。"]'),
('4cd81b4a-d392-4893-939f-fd4fd06e74e5','山徑','范成大','宋','宋诗','song-poetry','','[]','雲根新徑絡山腰，暗綠交陰宿露飄。',32,'全唐诗/poet.song.136000.json','["雲根新徑絡山腰，暗綠交陰宿露飄。", "行到竹深啼鳥閙，鵓鳩老怨畫眉嬌。"]'),
('3c30bf59-7c25-4ca1-be5e-282414a40fef','泉亭','范成大','宋','宋诗','song-poetry','','[]','收拾風煙鎖翠微，亂山窮處結巖扉。',32,'全唐诗/poet.song.136000.json','["收拾風煙鎖翠微，亂山窮處結巖扉。", "青天不盡鳥飛盡，吳楚川原似衲衣。"]'),
('d06c0f76-23a9-48bc-b149-3a0ecb5949f8','金氏菴','范成大','宋','宋诗','song-poetry','','[]','醉墨題窗側暮鴉，蔓藤緣壁走青蛇。',32,'全唐诗/poet.song.136000.json','["醉墨題窗側暮鴉，蔓藤緣壁走青蛇。", "春深有燕捎飛蝶，日暮無人掃落花。"]'),
('be5ca3ac-882f-4f67-a8a3-f7b93545498c','平雲閣','范成大','宋','宋诗','song-poetry','','[]','背倚天峰湧化宮，橫空閣道拖雙虹。',32,'全唐诗/poet.song.136000.json','["背倚天峰湧化宮，橫空閣道拖雙虹。", "火雲六月應奇絕，青瑣玲瓏八面風。"]'),
('e7861f97-7e3e-44d2-9c94-f075852194f6','鐵錫','范成大','宋','宋诗','song-poetry','','[]','八環流韻寶枝鳴，古鐵無花紫翠明。',32,'全唐诗/poet.song.137000.json','["八環流韻寶枝鳴，古鐵無花紫翠明。", "莫遣閒人容易振，泉飛石落鬼寰驚。"]'),
('78ea606b-491a-4dbe-b111-aebf5c476f39','放鶴亭','范成大','宋','宋诗','song-poetry','','[]','石門關外古亭基，樹老藤枯野徑微。',32,'全唐诗/poet.song.137000.json','["石門關外古亭基，樹老藤枯野徑微。", "放鶴道人今不見，故應人與鶴俱飛。"]'),
('7cab8d30-fc6f-4d10-950b-a01aba7d8943','馬跡石','范成大','宋','宋诗','song-poetry','','[]','跨馬凌空亦快哉，龍腰鶴背謾徘徊。',32,'全唐诗/poet.song.137000.json','["跨馬凌空亦快哉，龍腰鶴背謾徘徊。", "遊人欲識仙蹤處，但覓蒼崖白塔來。"]'),
('76e45e3f-df50-4a3d-99a6-2b3112d60973','金沙','范成大','宋','宋诗','song-poetry','','[]','莊嚴福地守靈仙，不爲人閒計子錢。',32,'全唐诗/poet.song.137000.json','["莊嚴福地守靈仙，不爲人閒計子錢。", "一掬斕斒光照眼，路傍饞隸枉流涎。"]'),
('88769a8b-028e-41b4-8893-b67013fc5ce8','龍母廟','范成大','宋','宋诗','song-poetry','','[]','孝龍分職隸湘西，天許寧親歲一歸。',32,'全唐诗/poet.song.137000.json','["孝龍分職隸湘西，天許寧親歲一歸。", "風雹春春損桃李，山中寒食尚冬衣。"]'),
('c1eea762-1737-4e8c-983a-c781ecbc9dd7','白蓮堂','范成大','宋','宋诗','song-poetry','','[]','古木參天護碧池，青錢弱葉戰漣漪。',32,'全唐诗/poet.song.137000.json','["古木參天護碧池，青錢弱葉戰漣漪。", "匆匆遊子匆匆去，不見風清月冷時。"]'),
('cd86098a-a032-4571-bb94-44bbe57526ec','白善坑','范成大','宋','宋诗','song-poetry','','[]','銀鬚玉璞紫金精，犯難窮探亦有名。',32,'全唐诗/poet.song.137000.json','["銀鬚玉璞紫金精，犯難窮探亦有名。", "白堊區區土同價，吳儂無事亦輕生。"]'),
('0ffe196f-3d84-4dd6-980c-28f92f7a27de','賀樂丈先生南郭新居','范成大','宋','宋诗','song-poetry','','[]','新堂燕雀喜，竹籬挂藤蘿。',144,'全唐诗/poet.song.137000.json','["新堂燕雀喜，竹籬挂藤蘿。", "崩奔風濤裏，得此巢龜荷。", "西山效爽氣，南浦供清波。", "會心不在遠，容膝何須多。", "先生淮海俊，踏地嘗兵戈。", "飄飄萬里道，芒鞵厭關河。", "風吹落下邑，楚語成吳歌。", "豈不有故國，荒垣鞠秋莎。", "無庸說當歸，到處皆南柯。", "卜遷不我遐，一水明青羅。", "閉戶長獨佳，奈客剝啄何。", "會令蒼苔石，屐齒如蜂窠。"]'),
('19f8e4ba-8cc0-4a30-b8bc-93e13a6c6ee3','歲旱邑人禱第五羅漢得雨樂先生有詩次韻','范成大','宋','宋诗','song-poetry','','[]','海山之湫龍所宮，濺瀑下赴聲琤琮。',192,'全唐诗/poet.song.137000.json','["海山之湫龍所宮，濺瀑下赴聲琤琮。", "碧矑大士何許主，愛此匹練飛冥濛。", "偶然宴坐百千劫，神力悲願俱無窮。", "向來火雲挾日走，沙煎日爛千山童。", "陸渾風高煽熱屬，涇川草肥閒雨工。", "萬口嗷嗷叫此士，爐燎未吐誠先通。", "暮塵捲地羊角暗，朝霞橫天魚尾紅。", "商羊摩霄鳶起舞，居然一澍歌年豐。", "人言佛陀入三昧，斷取世界如旋蓬。", "指麾釋梵駿奔走，況爾風伯并雷公。", "風騷老將亦贊喜，筆陣獨掃詩壇空。", "嗟余嘯咏不釋手，一曲何啻歌三終。"]'),
('e31ec8c8-4b93-4d41-9d07-68b992a37013','次韻時敘賦樂先生新居','范成大','宋','宋诗','song-poetry','','[]','愚士繁俗如囚奴，至人遺形與化俱。',160,'全唐诗/poet.song.137000.json','["愚士繁俗如囚奴，至人遺形與化俱。", "紛紜覺夢不可辨，蘧蘧栩栩知誰歟。", "百年如泡亦如電，剛欲鑄鐵充門樞。", "列仙之臞墮山澤，一席三椽良有餘。", "平生嶔巇百戰勇，頓挫久已歸夷途。", "光芒無用入詩句，青天白日轟雷車。", "松煤繭紙妙揮掃，芸香錦囊深貯儲。", "紫露雙瓶春夜醉，黄雲一稜秋田租。", "誰能摶扶北溟海，政爾歸卧南陽廬。", "鴻飛冥冥隔雲雨，弋人可慕不可呼。"]'),
('6c2bf5bb-e958-47b1-b3b4-ee3d537c91e6','病中夜坐呈致遠','范成大','宋','宋诗','song-poetry','','[]','似霧如煙夜氣浮，鶴鳴驚睡起搔頭。',64,'全唐诗/poet.song.137000.json','["似霧如煙夜氣浮，鶴鳴驚睡起搔頭。", "含風竹影淡留月，著雨蛩聲深怨秋。", "萬事心空癡已慣，百骸歲晚病相投。", "便當採藥西山去，脚力蹣跚怕遠游。"]'),
('6ffb2040-eadb-4619-9169-e1e56fe0b294','戲題藥裹','范成大','宋','宋诗','song-poetry','','[]','捲却絲綸颺却竿，莫隨魚鼈弄腥涎。',32,'全唐诗/poet.song.137000.json','["捲却絲綸颺却竿，莫隨魚鼈弄腥涎。", "須知別有垂鈎處，枯海無風浪拍天。"]'),
('1ccb89f5-4655-4300-a801-15b84aa1dea7','夜歸','范成大','宋','宋诗','song-poetry','','[]','竹輿伊軋走長街，掠面風清醉夢迴。',32,'全唐诗/poet.song.137000.json','["竹輿伊軋走長街，掠面風清醉夢迴。", "曲巷無聲門戶閉，一燈猶照酒壚開。"]'),
('e0bff0bf-14d0-43d7-b46d-6815e215d976','田舍','范成大','宋','宋诗','song-poetry','','[]','呼喚携鋤至，安排築圃忙。',48,'全唐诗/poet.song.137000.json','["呼喚携鋤至，安排築圃忙。", "兒童眠落葉，鳥雀噪斜陽。", "煙火村聲遠，林菁野氣香。", "樂哉今歲事，天末稻雲黄。"]'),
('134f766f-d459-4d30-bc5a-e9e5d587c03f','戲題致遠書房','范成大','宋','宋诗','song-poetry','','[]','照叢菊靨萬黄金，欹架薇條半綠陰。',32,'全唐诗/poet.song.137000.json','["照叢菊靨萬黄金，欹架薇條半綠陰。", "逋客已隨丹鳳詔，但餘花草怨秋深。"]'),
('a2b2147c-0a82-4373-acc1-926b4f342dd7','烏戍密印寺','范成大','宋','宋诗','song-poetry','','[]','青堆溪上水平堤，絳瓦參差半掩扉。',64,'全唐诗/poet.song.137000.json','["青堆溪上水平堤，絳瓦參差半掩扉。", "我與聖公俱客寓，人傳帝子尚靈威。", "勝緣齟齬三重障，志士辛勤十載歸。", "花木禪房都不見，但餘蝙蝠晝羣飛。"]'),
('89231544-6d72-4977-ab75-1312cb4d6490','月夜泛舟新塘','范成大','宋','宋诗','song-poetry','','[]','溪上清風柳萬重，綠煙無路月朦朧。',32,'全唐诗/poet.song.137000.json','["溪上清風柳萬重，綠煙無路月朦朧。", "船頭忽逐回塘轉，一水迢迢却向東。"]'),
('c864d434-d279-4ac8-9710-a30839cf0158','客舍','范成大','宋','宋诗','song-poetry','','[]','轂擊肩摩錦繡堆，朝聲洶洶暮聲催。',32,'全唐诗/poet.song.137000.json','["轂擊肩摩錦繡堆，朝聲洶洶暮聲催。", "忽然憶起長橋路，天鏡無邊白鳥迴。"]'),
('f16b321b-10b5-4549-8480-43e97c501fc4','病中夜坐','范成大','宋','宋诗','song-poetry','','[]','村巷秋舂遠，禪房夕磬深。',48,'全唐诗/poet.song.137000.json','["村巷秋舂遠，禪房夕磬深。", "饑蚊常繞鬢，暗鼠忽鳴琴。", "薄薄寒相中，稜稜瘦不禁。", "時成洛下詠，却似越人吟。"]'),
('56eccca5-5e5c-4472-be66-6fd2030293a8','秋芸有春綠','范成大','宋','宋诗','song-poetry','','[]','秋芸有春綠，疎籬照孤芳。',48,'全唐诗/poet.song.137000.json','["秋芸有春綠，疎籬照孤芳。", "清霜早晚至，何草能不黄。", "寧當念衰落，政爾事容光。", "及時且自好，來日殊未量。"]'),
('30d97acf-1da3-414d-8d39-00eabcc3aaba','三湘怨','范成大','宋','宋诗','song-poetry','','[]','牙檣罨畫櫓，搖漾三湘浦。',48,'全唐诗/poet.song.137000.json','["牙檣罨畫櫓，搖漾三湘浦。", "佳人翔綠裾，含顰爲誰舞。", "拳拳新荷葉，愁絕煙水暮。", "風雲忽飄蕩，隠約聞簫鼓。"]'),
('04ad879d-1c01-4176-8bf1-c9f3562d48a1','夜發崑山','范成大','宋','宋诗','song-poetry','','[]','歲寒人墐戶，霜重獨登舟。',48,'全唐诗/poet.song.137000.json','["歲寒人墐戶，霜重獨登舟。", "弱櫓搖孤夢，疎篷蓋百憂。", "但吟今不樂，豈計幾宜休。", "慚愧沙湖月，年年照薄遊。"]'),
('3ee2fc3e-e07d-497b-993e-8a04c5831229','十一月十二日枕上曉作','范成大','宋','宋诗','song-poetry','','[]','竹響風成陣，窗明雪已花。',48,'全唐诗/poet.song.137000.json','["竹響風成陣，窗明雪已花。", "柴扉吟凍犬，紙瓦啄饑鴉。", "宿酒欺寒力，新詩管歲華。", "日高猶擁被，蓐食愧鄰家。"]'),
('2557b3ae-eb5d-448e-bc3e-7404f60b9e34','南樓望雪','范成大','宋','宋诗','song-poetry','','[]','夜月流瑶圃，春風滿玉都。',48,'全唐诗/poet.song.137000.json','["夜月流瑶圃，春風滿玉都。", "籬疎先剝落，樹密正模糊。", "亂點橫煙鴈，驚啼失木烏。", "醉魂方浩蕩，風袖不支梧。"]'),
('55566664-a45a-4dcf-8c42-15127fb0624a','除夜書懷','范成大','宋','宋诗','song-poetry','','[]','運斗寅杓轉，周天日御回。',168,'全唐诗/poet.song.137000.json','["運斗寅杓轉，周天日御回。", "夜從冬後短，春逐雨中來。", "鬢綠看看雪，心丹念念灰。", "有懷憐斷鴈，無思惜疎梅。", "絮厚眼生纈，蔬寒腸轉雷。", "燭花紅瑣碎，香霧碧徘徊。", "昨夢書三篋，平生酒一杯。", "牀頭新曆日，衣上舊塵埃。", "搖落何堪柳，紛紜各夢槐。", "隙光能幾許，世事劇悠哉。", "岐路東西變，羲娥日夜催。", "頭顱元自覺，懷抱故應開。", "踴躍金何意，青黄木自災。", "身謀同斥鷃，政爾願蒿萊。"]'),
('16786fae-8cde-448a-8833-a2d6f7128c65','戲答澹菴小偈','范成大','宋','宋诗','song-poetry','','[]','莫問前程事，漂然海上舟。',48,'全唐诗/poet.song.137000.json','["莫問前程事，漂然海上舟。", "命乖逢鬼國，緣合遇蓬丘。", "畢竟非身計，俱成錯路頭。", "故鄉隨脚是，流浪不知休。"]'),
('96aa4748-a2a4-49a8-a3ed-8aa020436912','偶書','范成大','宋','宋诗','song-poetry','','[]','出處由人不繫天，癡兒富貴更求仙。',32,'全唐诗/poet.song.137000.json','["出處由人不繫天，癡兒富貴更求仙。", "東家就食西家宿，世事何緣得兩全。"]'),
('020bca9b-8767-4e30-82f2-e2edb0d10686','題立雪圖','范成大','宋','宋诗','song-poetry','','[]','堂下心如鐵，菴中語似雷。',24,'全唐诗/poet.song.137000.json','["堂下心如鐵，菴中語似雷。", "有人參此語，三箇一坑埋。"]'),
('0d97ca5d-c12c-4360-a3ea-039385cc0f4e','題日記','范成大','宋','宋诗','song-poetry','','[]','誰言萬事轉頭空，未轉頭時亦夢中。',32,'全唐诗/poet.song.137000.json','["誰言萬事轉頭空，未轉頭時亦夢中。", "若向夢中尋夢覺，覺來還入大槐宮。"]'),
('708f37b0-c2b6-497b-a255-7c16a793bf2b','題張氏新亭','范成大','宋','宋诗','song-poetry','','[]','水楊成幄翠相遮，猶有東風管歲華。',64,'全唐诗/poet.song.137000.json','["水楊成幄翠相遮，猶有東風管歲華。", "葉底青梅無數子，梢頭紅杏不多花。", "煩將鍊火炊香飯，更引長泉煮鬭茶。", "約我詩成須疥壁，莫嗔欹側似歸鴉。"]'),
('e027e993-f59f-40d4-a754-c0524af585a2','玉臺體','范成大','宋','宋诗','song-poetry','','[]','捲幔燈千朶，鈎簾月半弓。',48,'全唐诗/poet.song.137000.json','["捲幔燈千朶，鈎簾月半弓。", "繡鴛翔瀝水，金雀跂屏風。", "細意翩長袖，多情結短封。", "銅壺從婉娩，玉珮正丁東。"]'),
('969484c8-f980-4871-81e5-32015c87de1a','枕上','范成大','宋','宋诗','song-poetry','','[]','明月無聲滿屋梁，夢餘分影上人牀。',32,'全唐诗/poet.song.137000.json','["明月無聲滿屋梁，夢餘分影上人牀。", "素娥脈脈翻愁寂，付與風鈴語夜長。"]'),
('16c04d8d-d0d7-4db9-b994-f927134413b8','斑騅','范成大','宋','宋诗','song-poetry','','[]','斑騅別後月纖纖，門外疎桐影畫簾。',32,'全唐诗/poet.song.137000.json','["斑騅別後月纖纖，門外疎桐影畫簾。", "留下可憐將不去，西風吹上兩眉尖。"]'),
('9cc08ff5-5edf-4456-8161-571f7845eeae','題傳記二首  其一','范成大','宋','宋诗','song-poetry','','[]','莫將綵筆寄朝雲，紅淚羅巾隔路塵。',32,'全唐诗/poet.song.137000.json','["莫將綵筆寄朝雲，紅淚羅巾隔路塵。", "說與東風無限恨，倩風吹斷去年春。"]'),
('3f705309-18bf-45ed-aed5-6e922ba9368b','題傳記二首  其二','范成大','宋','宋诗','song-poetry','','[]','綵舟歸去海山青，寂莫瑶臺月自明。',32,'全唐诗/poet.song.137000.json','["綵舟歸去海山青，寂莫瑶臺月自明。", "啼雨落花春已盡，夢魂何必更多情。"]'),
('fb7bfca6-5bd4-4923-9e13-1e0ee0aa99c6','病中絕句八首  其一','范成大','宋','宋诗','song-poetry','','[]','空裏情知不著花，逢場將病當生涯。',32,'全唐诗/poet.song.137000.json','["空裏情知不著花，逢場將病當生涯。", "蒲團軟暖無時節，夜聽蚊雷曉聽鴉。"]'),
('904dc1ba-b7ed-4e60-b796-8981b64c13bd','病中絕句八首  其二','范成大','宋','宋诗','song-poetry','','[]','溽暑薰天地湧泉，彎跧避濕挂行纏。',32,'全唐诗/poet.song.137000.json','["溽暑薰天地湧泉，彎跧避濕挂行纏。", "出門斟酌無忙事，睡過黄梅細雨天。"]'),
('e6318978-42c5-4069-9abc-4a5776947e21','病中絕句八首  其三','范成大','宋','宋诗','song-poetry','','[]','石鼎颼颼夜煮湯，亂拖芝朮鬭溫凉。',32,'全唐诗/poet.song.137000.json','["石鼎颼颼夜煮湯，亂拖芝朮鬭溫凉。", "化兒幻我知何用，祗與人間試藥方。"]'),
('2db42548-c55b-426f-a932-e18cd3a7bead','病中絕句八首  其四','范成大','宋','宋诗','song-poetry','','[]','病中心境兩俱降，猶憶江湖白鳥雙。',32,'全唐诗/poet.song.137000.json','["病中心境兩俱降，猶憶江湖白鳥雙。", "一夜雨聲鳴紙瓦，聽成飛雪打船窗。"]'),
('413eb6af-7487-4d97-862d-4da9e36f8295','病中絕句八首  其五','范成大','宋','宋诗','song-poetry','','[]','檐頭排溜密如簾，溪上層陰定解嚴。',32,'全唐诗/poet.song.137000.json','["檐頭排溜密如簾，溪上層陰定解嚴。", "最是看山奇絕處，白雲堆絮擁青尖。"]'),
('948637d4-9ba3-4c16-9cd3-bbac6ba94d55','病中絕句八首  其六','范成大','宋','宋诗','song-poetry','','[]','夜合梢頭蘸紫茸，菉葱頂上拆黄封。',32,'全唐诗/poet.song.137000.json','["夜合梢頭蘸紫茸，菉葱頂上拆黄封。", "去年團扇題詩處，依舊疎簾細雨中。"]'),
('75d5dcd4-e480-4ed1-b890-34efc04676b1','病中絕句八首  其七','范成大','宋','宋诗','song-poetry','','[]','盆傾瓴建夜翻渠，繞屋蛙聲一倍粗。',32,'全唐诗/poet.song.137000.json','["盆傾瓴建夜翻渠，繞屋蛙聲一倍粗。", "想見西堂渾不睡，明朝踏濕看菖蒲。"]'),
('84518b01-afe8-4840-ad5d-2e402dad81e6','病中絕句八首  其八','范成大','宋','宋诗','song-poetry','','[]','晴色先從喜鵲知，斜陽一抹照天西。',32,'全唐诗/poet.song.137000.json','["晴色先從喜鵲知，斜陽一抹照天西。", "竹雞何物能無頼，如許泥深更苦啼。"]'),
('101de314-8aa3-4f55-828c-2d0d28e272aa','病中三偈  其一','范成大','宋','宋诗','song-poetry','','[]','擾擾隨流無定期，波停浪息始應知。',64,'全唐诗/poet.song.137000.json','["擾擾隨流無定期，波停浪息始應知。", "一塵不偶同歸處，四海無親獨步時。", "苦相打通俱入妙，病緣纔入更何疑。", "霜清木落千山露，笑殺東風葉滿枝。"]'),
('4ca12e01-7795-40f0-95e2-f7cf804e84fc','病中三偈  其二','范成大','宋','宋诗','song-poetry','','[]','一交銷取萬黄金，將病求醫在用心。',32,'全唐诗/poet.song.137000.json','["一交銷取萬黄金，將病求醫在用心。", "化盡此身成藥樹，不妨栽得病根深。"]'),
('2e9fd4c5-8a6e-4507-a513-6ed8a26f81e3','病中三偈  其三','范成大','宋','宋诗','song-poetry','','[]','莫把無言絕病根，病根深處是無言。',32,'全唐诗/poet.song.137000.json','["莫把無言絕病根，病根深處是無言。", "丈夫解却維摩縛，八字轟開不二門。"]'),
('07055326-7dd6-4bd5-ad51-625c33630dfd','雲間湖光亭','范成大','宋','宋诗','song-poetry','','[]','微風不動斂濤湍，組練晶晶色界寒。',32,'全唐诗/poet.song.137000.json','["微風不動斂濤湍，組練晶晶色界寒。", "斜照發揮猶未盡，月明殘夜更來看。"]'),
('e4603905-21dc-46d1-96d9-e1a66a08ff4e','高景菴泉亭','范成大','宋','宋诗','song-poetry','','[]','峰頭揮手笑紅塵，天入雙眸洗翳昏。',32,'全唐诗/poet.song.137000.json','["峰頭揮手笑紅塵，天入雙眸洗翳昏。", "萬里西風熟秔稻，白雲堆裏著黄雲。"]'),
('64cb1f22-b455-4bb9-8851-bf939bb1adf0','晚入盤門','范成大','宋','宋诗','song-poetry','','[]','人語嘲喧晚吹凉，萬窗燈火轉河塘。',64,'全唐诗/poet.song.137000.json','["人語嘲喧晚吹凉，萬窗燈火轉河塘。", "兩行碧柳籠官渡，一簇紅樓壓女牆。", "何處采菱聞度曲，誰家拜月認飄香。", "輕裘駿馬慵穿市，困倚蒲團入睡鄉。"]'),
('611b0382-997b-4ac3-b0cd-0c6ed3751db5','九月三十日夜出關候致遠不至','范成大','宋','宋诗','song-poetry','','[]','風勁便輕棹，霜嚴怯弊裘。',48,'全唐诗/poet.song.137000.json','["風勁便輕棹，霜嚴怯弊裘。", "青山蟠巨浸，紅樹立滄洲。", "月黑鴈猶去，燈寒人更愁。", "煙松漫小峴，何處問鳴騶。"]'),
('191c25f7-ea78-42a9-8bea-39485c921563','次韻致遠自毘陵見寄二首  其一','范成大','宋','宋诗','song-poetry','','[]','黄鵠高飛碧落寒，向來山水夢驚殘。',32,'全唐诗/poet.song.137000.json','["黄鵠高飛碧落寒，向來山水夢驚殘。", "故情若問玄真子，依舊江頭把釣竿。"]'),
('cbf84673-f114-4003-a027-17c5a19c2cb7','次韻致遠自毘陵見寄二首  其二','范成大','宋','宋诗','song-poetry','','[]','新詞一闋話羈愁，清似寒泉咽隴頭。',32,'全唐诗/poet.song.137000.json','["新詞一闋話羈愁，清似寒泉咽隴頭。", "官下有誰同此景，仲宣應是獨登樓。"]'),
('e741f70f-bd77-4233-a052-ce56550d880c','元日山寺','范成大','宋','宋诗','song-poetry','','[]','聽熟朝魚又暮鐘，全將慵懶度三冬。',64,'全唐诗/poet.song.137000.json','["聽熟朝魚又暮鐘，全將慵懶度三冬。", "貪眠豹褥窗間日，怕擁駞裘陌上風。", "登版自憐行蹭蹬，讀碑仍怪視蒙籠。", "少年豪壯今如此，略與殘僧氣味同。"]'),
('b0663265-4678-4126-87a9-f57954bf0835','題記事冊','范成大','宋','宋诗','song-poetry','','[]','北山山下小菴居，佛劫仙塵只故吾。',32,'全唐诗/poet.song.137000.json','["北山山下小菴居，佛劫仙塵只故吾。", "八萬四千空色界，不離一法認毘盧。"]'),
('43515ca3-1d2d-4e81-acc1-9dc4483b45aa','寄贈致遠并呈現老','范成大','宋','宋诗','song-poetry','','[]','草草家風節物新，從來憂病不憂貧。',64,'全唐诗/poet.song.137000.json','["草草家風節物新，從來憂病不憂貧。", "琴書稍覺浮生誤，香火惟知此事真。", "室裏談空思二士，花間對影謾三人。", "袛愁盧李分携後，別有箜篌一曲春。"]'),
('2eae2a99-ffd8-4f4a-84b7-39ce68f23a1e','春後微雪一宿而晴','范成大','宋','宋诗','song-poetry','','[]','綵勝金旛換物華，垂垂天意晚平沙。',64,'全唐诗/poet.song.137000.json','["綵勝金旛換物華，垂垂天意晚平沙。", "東君未破含春蕊，青女先飛剪水花。", "夜逐回風鳴瓦壠，曉成疎雨滴檐牙。", "朝暾不與同雲便，烘作晴空萬縷霞。"]'),
('0b8b263f-0b8f-4317-b944-6f37ab157fd1','雪霽獨登南樓','范成大','宋','宋诗','song-poetry','','[]','雪晴風勁晚來冰，樓上奇寒病骨驚。',64,'全唐诗/poet.song.137000.json','["雪晴風勁晚來冰，樓上奇寒病骨驚。", "雀啄空檐銀笋墮，鴉翻高樹玉塵傾。", "青帘閃閃千家靜，黄帽亭亭一水橫。", "坐久天容却溫麗，一彎新月對長庚。"]'),
('6723b580-7e3c-471b-8df7-9b14d67ff37d','次時敘韻送至先兄赴調','范成大','宋','宋诗','song-poetry','','[]','梅柳欲動風作難，行人意在飛鴻間。',64,'全唐诗/poet.song.137000.json','["梅柳欲動風作難，行人意在飛鴻間。", "一官遠遊門戶弱，百歲上策身心閑。", "胸次饒渠有廊廟，夢魂叵使無江山。", "栽桃種杏須付我，已辦鐵鎖遲公攀。"]'),
('921abbc7-c734-455f-91a2-55f6bdb86066','上沙遇雨快凉','范成大','宋','宋诗','song-poetry','','[]','刮地風來健葛衣，一凉便覺暑光低。',32,'全唐诗/poet.song.137000.json','["刮地風來健葛衣，一凉便覺暑光低。", "雲頭龍挂如垂筯，雨在中峰白塔西。"]'),
('4ed8057d-83fe-4d75-a9ff-a1232fdce163','自天平嶺過高景菴','范成大','宋','宋诗','song-poetry','','[]','卓筆峰前樹作團，天平嶺上石成關。',32,'全唐诗/poet.song.137000.json','["卓筆峰前樹作團，天平嶺上石成關。", "綠陰匝地無人過，落日秋蟬滿四山。"]'),
('06b7db37-72f3-4af5-be8c-d5edaa2d7904','高景山夜歸','范成大','宋','宋诗','song-poetry','','[]','伊軋籃輿草露間，夜凉月暗走孱顔。',32,'全唐诗/poet.song.137000.json','["伊軋籃輿草露間，夜凉月暗走孱顔。", "忽逢陂水明如鏡，照見沉沉倒景山。"]'),
('e1d44e85-cad5-4850-8bde-2f354d548b07','白雲嶺','范成大','宋','宋诗','song-poetry','','[]','路入千峰一線通，陸離長劍立天風。',32,'全唐诗/poet.song.137000.json','["路入千峰一線通，陸離長劍立天風。", "五年領客題詩處，正在孤雲亂石中。"]'),
('bd889340-5318-4701-b947-d72c04d2004e','偃月泉','范成大','宋','宋诗','song-poetry','','[]','松風竹露午猶寒，知有龍蟠一掬慳。',32,'全唐诗/poet.song.137000.json','["松風竹露午猶寒，知有龍蟠一掬慳。", "我欲今年來結夏，莫扃岫幌掩雲關。"]'),
('5334abe2-a8b7-4489-aa75-30ba7c884f31','代人七月十四日生朝','范成大','宋','宋诗','song-poetry','','[]','秋入壺中玉宇鮮，芝蘭桃李共熙然。',64,'全唐诗/poet.song.137000.json','["秋入壺中玉宇鮮，芝蘭桃李共熙然。", "已饒瑞莢明朝滿，先借清蟾一夜圓。", "北闕紫泥應道路，東山紅袖莫雲煙。", "如今且醉江湖酒，來歲城南尺五天。"]'),
('d0cadcf5-32bc-4174-8606-32a62f0ac39f','題金牛洞','范成大','宋','宋诗','song-poetry','','[]','故鄉江吳多好山，筍輿篾舫相窮年。',96,'全唐诗/poet.song.137000.json','["故鄉江吳多好山，筍輿篾舫相窮年。", "春風吹入江南陌，疊障雙峰如舊識。", "聞道金牛更孱顔，古來鐵鎖高難攀。", "自從仙伯弭芝蓋，鳳舞鸞歌開洞天。", "新詩賸說山中妙，我不曾游先夢到。", "從渠弱水隔蓬萊，雲山何處無瑶草。"]'),
('a75bfeff-56e7-483e-9c6d-069e52024199','曉自銀林至東灞登舟寄宣城親戚','范成大','宋','宋诗','song-poetry','','[]','曉山障望眼，脈脈紫翠橫。',132,'全唐诗/poet.song.137000.json','["曉山障望眼，脈脈紫翠橫。", "澄江已不見，況乃江上城。", "結束治野裝，木末浮三星。", "羸馬隴頭嘶，小車谷中鳴。", "亭亭東灞樹，練練綠浦明。", "篙師笑迎我，新漲沒蘋汀。", "徑投一葉去，雲水相與平。", "聊將塵土面，照此玻瓈清。", "懷我二三友，高堂晨欲興。", "風細桐葉墮，露濃荷蓋傾。", "凝香繞燕几，安知路傍情。"]'),
('24507638-c1c9-4ce7-8f79-03423621ae80','讀唐太宗紀  其一','范成大','宋','宋诗','song-poetry','','[]','宮府相圖勢不收，國家何有各身謀。',32,'全唐诗/poet.song.137000.json','["宮府相圖勢不收，國家何有各身謀。", "縱無管蔡當時例，業已彎弓肯罷休。"]'),
('3995fe24-e1d8-485a-8c16-13154d25b7c6','讀唐太宗紀  其二','范成大','宋','宋诗','song-poetry','','[]','弟兄相賊斁天倫，自古無如舜苦辛。',32,'全唐诗/poet.song.137000.json','["弟兄相賊斁天倫，自古無如舜苦辛。", "掩井捐階危萬死，不聞親殺鼻亭神。"]'),
('6587110e-2f50-4077-8473-b4756ff910d7','讀唐太宗紀  其三','范成大','宋','宋诗','song-poetry','','[]','佐命諸公趣夜裝，爭言社稷要靈長。',32,'全唐诗/poet.song.137000.json','["佐命諸公趣夜裝，爭言社稷要靈長。", "就令昆季尸神器，未必唐家便破亡。"]'),
('cb5a02d9-eba4-4d67-9e10-fc3b5ba4db47','讀唐太宗紀  其四','范成大','宋','宋诗','song-poetry','','[]','建成回馬欲馳歸，元吉行趨武德闈。',32,'全唐诗/poet.song.137000.json','["建成回馬欲馳歸，元吉行趨武德闈。", "若使兩人俱得去，却於何處極兵威。"]'),
('b129ad53-f6c9-4601-b4c7-cf597c6fc2c6','讀唐太宗紀  其五','范成大','宋','宋诗','song-poetry','','[]','嫡長承祧有大倫，老公愛子本平均。',32,'全唐诗/poet.song.137000.json','["嫡長承祧有大倫，老公愛子本平均。", "只知世上尋常理，爭信英雄解滅親。"]'),
('5105a884-549c-451f-88fc-c7782900994a','重讀唐太宗紀  其一','范成大','宋','宋诗','song-poetry','','[]','父子情深苦亦深，蓋天神武一沾襟。',32,'全唐诗/poet.song.137000.json','["父子情深苦亦深，蓋天神武一沾襟。", "想當拔刃投牀際，也憶海池舟裏心。"]'),
('a6f4e5cc-6f82-4d01-90c5-8dd5504e2ce4','重讀唐太宗紀  其二','范成大','宋','宋诗','song-poetry','','[]','承乾謀父保天年，青雀圖兄亦兩全。',32,'全唐诗/poet.song.137000.json','["承乾謀父保天年，青雀圖兄亦兩全。", "隠刺諸兒却孥戮，一私知隔幾山淵。"]'),
('f0fe92b3-c18a-4149-a8ae-94a9fcba36c3','重讀唐太宗紀  其三','范成大','宋','宋诗','song-poetry','','[]','更張聊欲亢吾宗，仁孝承家合至公。',32,'全唐诗/poet.song.137000.json','["更張聊欲亢吾宗，仁孝承家合至公。", "天發殺機那可料，正投阿武禍胎中。"]'),
('dd874f5e-c299-45d7-8344-a21ce1223ff8','復自姑蘇過宛陵至鄧步出陸','范成大','宋','宋诗','song-poetry','','[]','漿家饋食槿爲藩，酒市停驂竹廡門。',64,'全唐诗/poet.song.137000.json','["漿家饋食槿爲藩，酒市停驂竹廡門。", "紅樹亭亭棲晚照，黄茅杳杳被高原。", "飲溪有跡於菟過，掠草如飛朴渥翻。", "車軌如溝平地少，飽帆天鏡憶江村。"]'),
('0b169e80-2da9-4066-acc2-68d09faa445e','題南塘客舍','范成大','宋','宋诗','song-poetry','','[]','閒裏方知得此生，癡人身外更經營。',32,'全唐诗/poet.song.137000.json','["閒裏方知得此生，癡人身外更經營。", "君看坐賈行商輩，誰復從容唱渭城。"]'),
('1be48033-f434-4d17-be1e-d509a11dfc30','南塘冬夜倡和','范成大','宋','宋诗','song-poetry','','[]','燃萁烘煖夜窗幽，時有新詩趣倡酬。',64,'全唐诗/poet.song.137000.json','["燃萁烘煖夜窗幽，時有新詩趣倡酬。", "爲問灞橋風雪裏，何如田舍火爐頭。", "寒釭欲暗吟方苦，凍筆難驅字更遒。", "絕笑兒癡生活淡，略無歲晚稻粱謀。"]'),
('4e25929c-2800-4c23-8a6e-37c56063bd99','游金牛洞題石壁上','范成大','宋','宋诗','song-poetry','','[]','仙翁舊游處，琅璈韻靈曲。',48,'全唐诗/poet.song.137000.json','["仙翁舊游處，琅璈韻靈曲。", "至今有餘音，玄鶴舞幽谷。", "衆真期我住，歲晚芝田熟。", "腰鑱從翁來，籋雲跨飛鹿。"]'),
('4f884de9-d904-4e49-8359-3823fd8f1143','浄行寺傍皆圩田每爲潦漲所决民歲歲興築患糧絕功輒不成','范成大','宋','宋诗','song-poetry','','[]','崩濤裂岸四三年，落日寒煙正渺然。',32,'全唐诗/poet.song.137000.json','["崩濤裂岸四三年，落日寒煙正渺然。", "空腹荷鋤那辦此，人功未至不關天。"]'),
('3c2851d3-ed2c-4a2d-98e8-966da2284aa4','衮山道中','范成大','宋','宋诗','song-poetry','','[]','虎嘯狐鳴苦竹叢，魂驚終日走蒙茸。',32,'全唐诗/poet.song.137000.json','["虎嘯狐鳴苦竹叢，魂驚終日走蒙茸。", "松林斷處前山缺，又見南湖數十峰。"]'),
('d50d9ed8-db7f-4a7f-bb1e-8d42b587af99','花山村舍','范成大','宋','宋诗','song-poetry','','[]','潦退灘灘露，沙虛岸岸頹。',48,'全唐诗/poet.song.137000.json','["潦退灘灘露，沙虛岸岸頹。", "澗聲穿竹去，雲影過山來。", "柳菌粘枝住，桑花共葉開。", "菴廬少來往，門巷濕蒼苔。"]'),
('09a553bb-3658-4209-a5c9-db3909e480da','清明日狸渡道中','范成大','宋','宋诗','song-poetry','','["\u6e05\u660e\u8282", "\u6e05\u660e", "\u5199\u666f"]','灑灑沾巾雨，披披側帽風。',48,'全唐诗/poet.song.137000.json','["灑灑沾巾雨，披披側帽風。", "花燃山色裏，柳卧水聲中。", "石馬立當道，紙鳶鳴半空。", "墦間人散後，烏鳥正西東。"]'),
('3c3edb72-11da-4e82-b2e1-851256d12028','寒食客中有懷','范成大','宋','宋诗','song-poetry','','[]','江郭花開也寂寥，不須綠暗與紅凋。',64,'全唐诗/poet.song.137000.json','["江郭花開也寂寥，不須綠暗與紅凋。", "疾風甚雨過寒食，白日青春吟大招。", "芳景尚隨流水去，故人應作綵雲飄。", "煙波千里家何在，惟有溪聲似晚潮。"]'),
('3b97d406-4c49-4820-a2a4-8d75406389dd','南塘寒食書事','范成大','宋','宋诗','song-poetry','','[]','埂外新陂綠，岡頭宿燒紅。',48,'全唐诗/poet.song.137000.json','["埂外新陂綠，岡頭宿燒紅。", "裹魚蒸菜把，饋鴨鎖筠籠。", "酒侶晨相命，歌場夜不空。", "土風并節物，不與故鄉同。"]'),
('f3e75cc8-726a-4083-bb4d-c276890c3595','周德萬携孥赴龍舒法曹道過水陽相見留別女弟','范成大','宋','宋诗','song-poetry','','[]','草草相逢小駐船，一杯和淚飲江天。',64,'全唐诗/poet.song.137000.json','["草草相逢小駐船，一杯和淚飲江天。", "妹孤忍使行千里，兄老那堪別數年。", "馬轉不容吾悵望，櫓鳴肯爲汝留連。", "神如相此俱强健，綠髮歸來慰眼前。"]'),
('ff1be8b5-f7e5-4675-a70f-45a5c655332e','高淳道中','范成大','宋','宋诗','song-poetry','','[]','路入高淳麥更深，草泥霑潤馬駸駸。',64,'全唐诗/poet.song.137000.json','["路入高淳麥更深，草泥霑潤馬駸駸。", "雨歸隴首雲凝黛，日漏山腰石滲金。", "老柳不春花自蔓，古祠無壁樹空陰。", "一簞定屬前村店，衮衮炊煙起竹林。"]'),
('ea36587d-b397-43a7-b471-fceca6fb3bcc','夜至寧菴見壁間端禮昆仲倡和明日將去次其韻','范成大','宋','宋诗','song-poetry','','[]','杉松廡門森老蒼，佛屋深夜幡花香。',64,'全唐诗/poet.song.137000.json','["杉松廡門森老蒼，佛屋深夜幡花香。", "借牀睡倒恍何處，夢隨潛魚聽驚榔。", "咿啞禽語曉光浄，窸窣草鳴朝雨凉。", "哦詩出門懷二妙，春漲繞山湖水黄。"]'),
('6856bff8-bf27-4d99-bb34-6f81ab7ab69b','行唐村平野晴色妍甚','范成大','宋','宋诗','song-poetry','','[]','暖日烘繁梅，穠香撲征鞅。',48,'全唐诗/poet.song.137000.json','["暖日烘繁梅，穠香撲征鞅。", "雲煙釀春色，心目兩駘蕩。", "柳眉翠已掃，桑眼青未放。", "茲遊定不俗，前路入千嶂。"]'),
('1149026a-8885-45ba-9b7c-fd55f0ed94f1','嶺上紅梅','范成大','宋','宋诗','song-poetry','','[]','霧雨臙脂照松竹，江南春風一枝足。',64,'全唐诗/poet.song.137000.json','["霧雨臙脂照松竹，江南春風一枝足。", "滿城桃李各嫣然，寂莫傾城在空谷。", "城中誰解惜娉婷，遊子路傍空復情。", "花不能言客無語，日暮清愁相對生。"]'),
('e109cd1d-fbf6-4f53-a926-2f4a63e0fa80','浙東參政寄示會稽蓬萊閣詩軸次韻寄題二首  其一','范成大','宋','宋诗','song-poetry','','[]','仙翁來佩玉符麟，綠髮無霜照碧筠。',64,'全唐诗/poet.song.137000.json','["仙翁來佩玉符麟，綠髮無霜照碧筠。", "永夜闌干千嶂月，清風揮麈七州春。", "塵埃不隔壺中境，功業猶關物外身。", "鸞鶴莫驚兵衛峻，主人元是白雲人。"]'),
('73941890-7227-43e8-889e-04a5cd457ef5','浙東參政寄示會稽蓬萊閣詩軸次韻寄題二首  其二','范成大','宋','宋诗','song-poetry','','[]','鰲背飛來紺碧浮，人間還有小蓬丘。',64,'全唐诗/poet.song.137000.json','["鰲背飛來紺碧浮，人間還有小蓬丘。", "不須擊水三千里，已壓中天十二樓。", "羽駕舊曾將夢到，芝田今合爲公秋。", "玉霄有客方東望，竟欲乘風馭氣遊。"]'),
('8e1403aa-c9b2-41ca-8f9e-4b946369de13','外舅輓詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','植德千章茂，硎材百鍊剛。',48,'全唐诗/poet.song.137000.json','["植德千章茂，硎材百鍊剛。", "事功纔止此，物理故難量。", "鴈序雲天遠，蘭階雨露芳。", "公無憾身後，人自惜堂堂。"]'),
('07eb554b-53da-4385-984b-2dabc6653249','外舅輓詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','幽介聯昏援，門闌閲歲更。',48,'全唐诗/poet.song.137000.json','["幽介聯昏援，門闌閲歲更。", "方欣承燕几，何意寫銘旌。", "笑語猶尋夢，恩勤已隔生。", "情傷到深處，有淚不勝傾。"]'),
('077ca672-93ce-4f38-ba3b-bce0148fcf26','天平先隴道中時將赴新安掾','范成大','宋','宋诗','song-poetry','','[]','霜橋冰澗浄無塵，竹塢梅溪未放春。',64,'全唐诗/poet.song.137000.json','["霜橋冰澗浄無塵，竹塢梅溪未放春。", "百疊海山鄉夢熟，三年江路旅愁生。", "松楸永寄孤窮淚，泉石終收漫浪身。", "好住鄰翁各安健，歸來相訪說情真。"]'),
('123ef56d-3aea-4939-843e-873294e77925','元夕泊舟霅川','范成大','宋','宋诗','song-poetry','','[]','蓮炬光中月自圓，人情草草競華年。',32,'全唐诗/poet.song.137000.json','["蓮炬光中月自圓，人情草草競華年。", "最憐一夜旗亭鼓，能共鐘聲到客船。"]'),
('91991111-3bcf-4b0a-a853-d1dcb4d1b528','桐川郡圃梅極盛皆圍抱高木浙中無有','范成大','宋','宋诗','song-poetry','','[]','家住丹楓白葦林，橫枝一笑萬黄金。',32,'全唐诗/poet.song.137000.json','["家住丹楓白葦林，橫枝一笑萬黄金。", "玉溪園裏逢千樹，還盡春風未足心。"]'),
('18a3a817-6048-47ad-b18f-0ccc2cc82b73','牧馬山道中','范成大','宋','宋诗','song-poetry','','[]','土橋茅屋兩三家，竹裏鳴泉漱白沙。',32,'全唐诗/poet.song.137000.json','["土橋茅屋兩三家，竹裏鳴泉漱白沙。", "春色惱人無畔岸，亂飄風袖拂梅花。"]'),
('f2cc720a-48f6-4a66-886d-ce2c163d8dbe','宿牧馬山勝果寺','范成大','宋','宋诗','song-poetry','','[]','佛燈已暗還吐，旅枕纔安却驚。',28,'全唐诗/poet.song.137000.json','["佛燈已暗還吐，旅枕纔安却驚。", "月色看成曉色，溪聲聽作松聲。"]'),
('092f35d0-efc4-4730-91eb-978ac7aae7ea','游寧國奉聖寺','范成大','宋','宋诗','song-poetry','','[]','松梢臺殿鬰高標，山轉溪迴一水朝。',32,'全唐诗/poet.song.137000.json','["松梢臺殿鬰高標，山轉溪迴一水朝。", "不惜褰裳呼小渡，夜來春漲失浮橋。"]'),
('f7920a59-5660-4ff6-82a3-ece9a7ec28ca','自寧國溪行至宣城舟人云凡百八十灘','范成大','宋','宋诗','song-poetry','','[]','波驚石險夜喧雷，曉泊旗亭笑眼開。',32,'全唐诗/poet.song.137000.json','["波驚石險夜喧雷，曉泊旗亭笑眼開。", "休問行人緣底瘦，適從百八十灘來。"]'),
('f142cc9d-6f97-41f9-97db-f365be7fd2cc','次韻宣州西園二首  其一','范成大','宋','宋诗','song-poetry','','[]','苔茵無地著紅塵，花草含芳一笑新。',32,'全唐诗/poet.song.137000.json','["苔茵無地著紅塵，花草含芳一笑新。", "不待東君能剪刻，相公筆力挽回春。"]'),
('d547a1e0-d925-4cc1-9796-fe108ea3c455','次韻宣州西園二首  其二','范成大','宋','宋诗','song-poetry','','[]','星芒垂耀筆牀寒，河漢波流硯滴乾。',32,'全唐诗/poet.song.137000.json','["星芒垂耀筆牀寒，河漢波流硯滴乾。", "棐几松跗入三昧，一篇詩就一杯殘。"]'),
('44dfc846-fc0c-4c5f-845f-904d31c78c45','晚步西園','范成大','宋','宋诗','song-poetry','','[]','料峭輕寒結晚陰，飛花院落怨春深。',32,'全唐诗/poet.song.137000.json','["料峭輕寒結晚陰，飛花院落怨春深。", "吹開紅紫還吹落，一種東風兩樣心。"]'),
('6556daf7-058d-4f97-9b22-f7b106980a0f','送端言','范成大','宋','宋诗','song-poetry','','[]','東君留戀一分春，蜂蝶闌珊燕子新。',32,'全唐诗/poet.song.137000.json','["東君留戀一分春，蜂蝶闌珊燕子新。", "桃李無情空綠徑，市橋楊柳送行人。"]'),
('edcee483-f576-4206-b52b-4486489c5518','早發竹下','范成大','宋','宋诗','song-poetry','','[]','結束晨裝破小寒，跨鞍聊得散疲頑。',64,'全唐诗/poet.song.137000.json','["結束晨裝破小寒，跨鞍聊得散疲頑。", "行衝薄薄輕輕霧，看放重重疊疊山。", "碧穗炊煙當樹直，綠紋溪水趁橋彎。", "清禽百囀似迎客，正在有情無思間。"]'),
('20c36c97-a4e9-4f13-9940-08f851ff859f','小澗','范成大','宋','宋诗','song-poetry','','[]','石礙珠旒濺，灘平霧縠鋪。',24,'全唐诗/poet.song.137000.json','["石礙珠旒濺，灘平霧縠鋪。", "小童能好事，繫馬斸菖蒲。"]'),
('89640e9a-fc8b-4d7d-b76f-6a9d12ae4a09','次韻子文探梅水西春已深猶未開水西謂歙溪而黄君謨州學記云瀕江地卑蓋此水爲浙之源正可謂之江也','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孤山山下小斜橋，客魂曾共暗香飄。',96,'全唐诗/poet.song.137000.json','["孤山山下小斜橋，客魂曾共暗香飄。", "五年不踏西湖路，想見黄昏清淺處。", "如今憔悴古江干，豈有幽芳伴倚欄。", "臘盡雪殘春不至，坐令愁裏眼長寒。", "霜稜未貸千林槁，門外風饕人欲倒。", "斟酌芳心正怯寒，有情真被無情惱。"]'),
('1b6e9733-e2d5-45fd-8a50-f1273696d592','後催租行','范成大','宋','宋诗','song-poetry','','["\u51c4\u82e6", "\u5199\u4eba", "\u751f\u6d3b", "\u519c\u6c11", "\u5199\u4eba\u8bd7"]','老父田荒秋雨裏，舊時高岸今江水。',112,'全唐诗/poet.song.137000.json','["老父田荒秋雨裏，舊時高岸今江水。", "傭耕猶自抱長饑，的知無力輸租米。", "自從鄉官新上來，黄紙放盡白紙催。", "賣衣得錢都納却，病骨雖寒聊免縛。", "去年衣盡到家口，大女臨岐兩分首。", "今年次女已行媒，亦復驅將換升斗。", "室中更有第三女，明年不怕催租苦。"]'),
('e81d031d-2dd9-4bc7-9ddc-c36177d617be','次韻子文衝雨迓使者道聞子規','范成大','宋','宋诗','song-poetry','','[]','夢魂翾蜨翅，鼻息吼鼉鼓。',72,'全唐诗/poet.song.137000.json','["夢魂翾蜨翅，鼻息吼鼉鼓。", "喚起治曉裝，馬嘶童僕語。", "汩泥溷鳬鶩，慚愧黄鵠舉。", "猥吟陬隅池，浪廢桔槹圃。", "啼鵑撩客心，鈎引著何許。", "請歌蘇仙詞，歸耕一犁雨。"]'),
('ebe3131a-9acf-4196-9076-7ff27ad1a0e9','奉題胡宗偉推官攬秀堂','范成大','宋','宋诗','song-poetry','','[]','城外屏峰雲百疊，城裏看雲笏拄頰。',64,'全唐诗/poet.song.137000.json','["城外屏峰雲百疊，城裏看雲笏拄頰。", "山靈自與人爭秀，明滅煙霏難應接。", "南鄰范叔骨相寒，不如騎曹知愛山。", "晨霞儻可救枵腹，丐君分我入朝餐。"]'),
('3b5f6a75-2149-448a-a1f3-a1b4f1c6e579','次韻太守出郊','范成大','宋','宋诗','song-poetry','','[]','曉裝緹騎踏芳辰，江爲安瀾露浥塵。',64,'全唐诗/poet.song.137000.json','["曉裝緹騎踏芳辰，江爲安瀾露浥塵。", "棨戟前驅留住月，笙簫後備带行春。", "魚龍水面金杯滿，鸞鶴山頭綵筆新。", "聞道將軍寬禮數，不辭酩酊吐車茵。"]'),
('2191ce91-796f-466e-820b-d027e6fb6c75','曉出古巖呈宗偉子文','范成大','宋','宋诗','song-poetry','','[]','曉風生小寒，嵐潤裛巾屨。',108,'全唐诗/poet.song.137000.json','["曉風生小寒，嵐潤裛巾屨。", "宿雲埋樹黑，奔溪轉山怒。", "東方動光彩，晃晃金鉦吐。", "千峰森隠現，一氣澹回互。", "平生癖幽討，邂逅飽新遇。", "那知塵滿甑，晨炊午未具。", "不愧忍饑面，來尋古巖路。", "稻粱亦易謀，烟霞乃難痼。", "持此慰龜腸，搜枯尚能句。"]'),
('811eb62e-371e-46e3-8d10-3d89e39417dc','積雨蒸潤體中不佳頗思故居之樂戲書呈子文','范成大','宋','宋诗','song-poetry','','[]','門外泥深蘸馬鞍，墨雲未放四維寬。',64,'全唐诗/poet.song.137000.json','["門外泥深蘸馬鞍，墨雲未放四維寬。", "前山忽接後山暗，暑雨全如秋雨寒。", "夢裏江湖三歎息，醉中天地一憑闌。", "斗升留滯休惆悵，枳棘從來著鳳鸞。"]'),
('da8543d3-a882-4c76-bd16-815dc39678d3','簽廳夜歸用前韻呈子文','范成大','宋','宋诗','song-poetry','','[]','簿書堆裏解歸鞍，我亦蕭然轡勒寬。',64,'全唐诗/poet.song.137000.json','["簿書堆裏解歸鞍，我亦蕭然轡勒寬。", "爐篆無風香霧直，庭柯有月露光寒。", "閒思喜鵲填河鼓，靜數流螢繞井欄。", "明日又驅官裏去，從教白鷺侶紅鸞。"]'),
('58925989-ec45-41b3-9ae6-9f4b00dca937','聖集誇說少年俊遊用韻記其語戲之','范成大','宋','宋诗','song-poetry','','[]','京塵紅軟撲雕鞍，年少王孫酒量寬。',64,'全唐诗/poet.song.137000.json','["京塵紅軟撲雕鞍，年少王孫酒量寬。", "倚袖竹風憐翠薄，捧杯花露怯金寒。", "黄雲城上栖烏曲，綠水橋邊鬭鴨欄。", "別後相思惟故物，壁煤侵損扇中鸞。"]'),
('c7494a15-25ea-4929-8fb7-fb0dbe348ffc','次溫伯用林公正劉慶充倡和韻','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','前山後山梅子雨，屯雲日夜相吞吐。',160,'全唐诗/poet.song.137000.json','["前山後山梅子雨，屯雲日夜相吞吐。", "長林絕壑望不到，時有樵歸說逢虎。", "奔溪朝來忽怒漲，夾岸柳梢餘尺許。", "屋頭未放濃嵐散，苦憶清風汎瓊宇。", "客行落此亂山中，但欲尋人訴羈旅。", "比鄰邂逅得清士，眉宇津津佳笑語。", "杯行起舞出新句，我氣已衰聊復鼓。", "明年與君杭太湖，扁舟踏浪不踏土。", "沉沉玉柱閟仙扃，矯矯虹梁浮水府。", "目力無窮天不盡，却笑向來誰縛汝。"]'),
('85f6cf90-087d-4a8c-8ec8-fab091610200','次韻溫伯夜坐今日忽得舍弟到杭消息喜見於詞','范成大','宋','宋诗','song-poetry','','[]','長風吹月來，影碎竹間牖。',96,'全唐诗/poet.song.137000.json','["長風吹月來，影碎竹間牖。", "良宵坐窘束，媿我塵外友。", "平生煙霞興，硉兀上南斗。", "頗亦契三三，未省計九九。", "迷塗入簿領，鄉心幾回首。", "嗟予季行役，舟拂漲溪柳。", "凌晨雙鵲鳴，翫占得無咎。", "何當從汝去，履綦尋蕙畝。"]'),
('4bfee833-8571-4aab-a740-615cfd5badcd','再次韻呈宗偉溫伯','范成大','宋','宋诗','song-poetry','','[]','官居數椽間，局促如甕牖。',96,'全唐诗/poet.song.137000.json','["官居數椽間，局促如甕牖。", "幸鄰詩酒社，金薤對玉友。", "真清廊廟器，偉望配山斗。", "行當侍紫極，槐棘位三九。", "館舍有奇士，高文粲參首。", "倡酬猥及我，雙松壓孤柳。", "生活從冷淡，幸免譽與咎。", "相從結此夏，何異歸隴畝。"]'),
('7dbabd2d-4374-4686-91b8-49143aa13e7e','次韻溫伯納凉','范成大','宋','宋诗','song-poetry','','[]','日斜猶畏暑，吏退合偷閒。',48,'全唐诗/poet.song.137000.json','["日斜猶畏暑，吏退合偷閒。", "霞散紅綃薄，溪迴碧玉彎。", "伴人惟羽扇，娛客欠風鬟。", "且復哦新句，相嘲飯顆山。"]'),
('5a32f96f-0879-460e-9a72-105397f7bd03','雨凉二首呈宗偉  其一','范成大','宋','宋诗','song-poetry','','[]','誰扶病客起龍鍾，恩在盆傾一雨中。',32,'全唐诗/poet.song.137000.json','["誰扶病客起龍鍾，恩在盆傾一雨中。", "問訊九關何路到，擬牋歡喜謝天公。"]'),
('92c59a9b-a7c7-42a8-8fd2-0bf3ec5d9225','雨凉二首呈宗偉  其二','范成大','宋','宋诗','song-poetry','','[]','驚雷隠地送凉颸，起舞看山不自持。',32,'全唐诗/poet.song.137000.json','["驚雷隠地送凉颸，起舞看山不自持。", "說與騷人須早計，片雲催雨雨催詩。"]'),
('edff2533-cb9c-4aa6-b100-74c17626dd11','明日復雨凉再用韻二首  其一','范成大','宋','宋诗','song-poetry','','[]','東山朝日澹冥濛，一片雲生萬疊中。',32,'全唐诗/poet.song.137000.json','["東山朝日澹冥濛，一片雲生萬疊中。", "宿雨未蘇焦卷盡，又煩箕井喚雷公。"]'),
('ce25842c-2bbb-44fa-aac5-12bd35351bc8','明日復雨凉再用韻二首  其二','范成大','宋','宋诗','song-poetry','','[]','濺瓦排檐散萬絲，顛狂風篠要扶持。',32,'全唐诗/poet.song.137000.json','["濺瓦排檐散萬絲，顛狂風篠要扶持。", "恩深到骨吾能報，急賦新凉第一詩。"]'),
('29b3ef01-2293-4d5e-9a77-f6403dbfa364','次韻慶充避暑水西寺','范成大','宋','宋诗','song-poetry','','[]','佳晨出西郭，仰視天宇清。',144,'全唐诗/poet.song.137000.json','["佳晨出西郭，仰視天宇清。", "樂哉曠士懷，浩浩吞四溟。", "新漲忽勇退，籬落粘枯萍。", "風幡招客遊，曠望隔蘋汀。", "僕夫厲清深，竹輿竦亭亭。", "波翻石鑿落，尚带蛟龍腥。", "華堂入松竹，德人占聚星。", "脫帽飛羽觴，頹放解天刑。", "時當行火令，草腐亦化螢。", "炎官紛陸梁，空飛赤雲軿。", "遥知隴上耘，暴背愁白丁。", "茲遊豈易得，未用歎沉冥。"]'),
('5a0d11ec-ac7f-4382-8d9c-66ea256f4c7f','送滕子昭績溪罷歸','范成大','宋','宋诗','song-poetry','','[]','天馬西極來，目力盡九寰。',96,'全唐诗/poet.song.137000.json','["天馬西極來，目力盡九寰。", "執轡者誰歟，墮此空谷間。", "草深石齧足，一躍度孱顔。", "長風送逸駕，蕩蕩登虎關。", "五雲清都上，白日開帝閑。", "鈎陳動光彩，球琳鏘轡環。", "亦復念舊羣，依然歎駑頑。", "紅塵起天末，可望不可攀。"]'),
('a7e9362f-3fea-416c-948a-00b84678a86d','次韻溫伯謀歸','范成大','宋','宋诗','song-poetry','','[]','官路驅馳易折肱，官曹隨處是愁城。',64,'全唐诗/poet.song.137000.json','["官路驅馳易折肱，官曹隨處是愁城。", "隨風片葉鄉心動，過雨千峰病眼明。", "一臠何須嘗世味，寸田久已廢吾耕。", "羨君早作歸歟計，屈指從今幾合并。"]'),
('f8565d6a-69eb-46f6-94fd-eeecfba1f85d','次韻溫伯雨凉感懷','范成大','宋','宋诗','song-poetry','','[]','窮士病且饑，古今同一流。',192,'全唐诗/poet.song.137000.json','["窮士病且饑，古今同一流。", "身安腹果然，此外吾何求。", "判司誠卑官，未免塵甑憂。", "窮山更癉暑，憊卧不舉頭。", "二物交寇我，生世真如浮。", "晨朝墨雲作，疾雷破山丘。", "排檐忽飛溜，蛙蟈鳴相酬。", "朱冠領熱屬，橫潰輸一籌。", "新凉蘇肺氣，踏濕登城樓。", "好邀雲雨仙，長袖按梁州。", "吹水添瓶罍，浄洗千斛愁。", "何從有此段，冰廳冷如秋。", "但覺詩思生，爽氣入銀鈎。", "章成竟何用，知能救窮不。", "湯子亦旅食，回望家還羞。", "倡予敢不和，共作商聲謳。"]'),
('0b616352-3d10-472f-bd89-512de67c79a8','次韻子文雨後思歸','范成大','宋','宋诗','song-poetry','','[]','斷雲將雨洗松篁，昨夜癡龍起蟄藏。',64,'全唐诗/poet.song.137000.json','["斷雲將雨洗松篁，昨夜癡龍起蟄藏。", "人自無情孤樂事，天猶有意作新凉。", "尊前不見凌波襪，樓下空聞拜月香。", "萬事安能盡如願，且來相伴壓糟牀。"]'),
('e2a004a8-f8d3-435a-9095-c77a6b0f5bbc','次韻溫伯苦蚊','范成大','宋','宋诗','song-poetry','','[]','白鳥營營夜苦饑，不堪薰燎出窗扉。',32,'全唐诗/poet.song.137000.json','["白鳥營營夜苦饑，不堪薰燎出窗扉。", "小蟲與我同憂患，口腹驅來敢倦飛。"]'),
('e912de38-4de4-40a0-b30a-89acd2a2b71b','慶充自黄山歸索其道中詩書一絕問之','范成大','宋','宋诗','song-poetry','','[]','鳴騶如電馬如雷，知是婆娑醉尉迴。',32,'全唐诗/poet.song.137000.json','["鳴騶如電馬如雷，知是婆娑醉尉迴。", "常日錦囊猶有句，況從三十六峰來。"]'),
('06990cb1-6c17-4d9e-84ce-aab3e708cca5','曉出古城山','范成大','宋','宋诗','song-poetry','','[]','落月墮眇莽，殘星澹微茫。',120,'全唐诗/poet.song.137000.json','["落月墮眇莽，殘星澹微茫。", "竹輿亂清溪，飛蓋入嵐光。", "松檜霧靄濕，桑麻風露香。", "空翠滴塵纓，何必濯滄浪。", "山家亦早作，迨此朝氣凉。", "林深無人聲，木末炊煙蒼。", "離離瓜芋區，肅肅棗栗場。", "田園古云樂，令我思故鄉。", "墟市稍來集，筠籠轉山忙。", "吏事亦挽我，歸路盤朝陽。"]'),
('1fce5e4e-72de-4f57-8266-b8cbce156628','李深之西尉同年談吳興風物再用古城韻','范成大','宋','宋诗','song-poetry','','[]','李侯昔遊吳，蓮舟鏡蒼茫。',120,'全唐诗/poet.song.137000.json','["李侯昔遊吳，蓮舟鏡蒼茫。", "風鬟與霧鬢，共濯玻瓈光。", "采花不盈舫，日暮雲水香。", "還登縹緲樓，羅襟酒淋浪。", "卷箔納星月，踏筵按伊梁。", "安知有恨事，但恐蒹葭蒼。", "風吹落窮谷，草深麋鹿場。", "高岡苦炎熱，游子悲異鄉。", "尚喜簡書省，期會無匆忙。", "猶餘作詩苦，消瘦如東陽。"]'),
('12fb9fe8-3dbc-4283-8ee7-2766410aa580','七月五日夜雨快晴','范成大','宋','宋诗','song-poetry','','[]','豐隆坎坎夜伐鼓，靈湫老龍撇波舞。',176,'全唐诗/poet.song.137000.json','["豐隆坎坎夜伐鼓，靈湫老龍撇波舞。", "褰雲掣電上清空，倒捲天潢作飛雨。", "向來炎官作夏旱，萬里彤霞烘玉宇。", "豈惟牛馬困蚊蝱，壠上行人口生土。", "我從雪浪葉舟來，不謂山城熱如許。", "天公知我愁欲病，施與一凉蘇逆旅。", "稍聞水繞屋除鳴，不覺星從雲罅吐。", "千山濯濯浄鬟髻，缺月娟娟炯眉嫵。", "浮生此景萬事足，但欠清歌對芳醑。", "天上秋期正多事，趣駕星橋跨銀渚。", "人間四者自難并，莫妒黄姑迎織女。"]'),
('709b8df1-c9cc-4993-985f-fbdae735b89f','次韻宗偉溫伯','范成大','宋','宋诗','song-poetry','','[]','冉冉流光迫歲餘，青林日夜向人疎。',64,'全唐诗/poet.song.137000.json','["冉冉流光迫歲餘，青林日夜向人疎。", "雨滋巖桂重堆粟，風折庭蕉又獻書。", "逋客解蘭思婉娩，先生彈鋏厭清虛。", "一塵不立渾輸我，即境心安是故廬。"]'),
('370958bf-fcf5-4d2c-beab-bc359de9bc46','再韻答子文','范成大','宋','宋诗','song-poetry','','[]','浮生飽外莫求餘，羈旅東來計已疎。',64,'全唐诗/poet.song.137000.json','["浮生飽外莫求餘，羈旅東來計已疎。", "肩聳已高猶索句，眼明無用且繙書。", "百年子莫占元緒，萬法吾今付子虛。", "惟有登臨心未厭，黄山聞道勝衡廬。"]'),
('1ae82f4a-4146-44e5-8c06-b55dba527ccc','道見蓼花','范成大','宋','宋诗','song-poetry','','[]','秋風裊裊露華鮮，去歲如今刺釣船。',32,'全唐诗/poet.song.137000.json','["秋風裊裊露華鮮，去歲如今刺釣船。", "歙縣門西見紅蓼，此身曾在白鷗前。"]'),
('e4e0bf7b-9404-4c2c-a850-2eb910539aae','次韻溫伯種蘭','范成大','宋','宋诗','song-poetry','','[]','靈均墮荒寒，采采紉蘭手。',108,'全唐诗/poet.song.137000.json','["靈均墮荒寒，采采紉蘭手。", "九畹不留客，高丘一迴首。", "崢嶸路孔棘，悽愴肘生柳。", "遂令此粲者，永與窮愁友。", "不如湯子遠，情事只詩酒。", "但知愛國香，此外付烏有。", "栽培带苔蘚，披拂護塵垢。", "孤芳亦有遇，洒濯居座右。", "君看深林下，埋沒隨藜莠。"]'),
('0e814802-df90-4b05-a103-bcb15f29aae9','次韻子文','范成大','宋','宋诗','song-poetry','','[]','幻塵久已破狐涎，身世誰能料鼠肝。',64,'全唐诗/poet.song.137000.json','["幻塵久已破狐涎，身世誰能料鼠肝。", "暮夜雨收千嶂出，晨朝風卷四維寬。", "我今無事不如夢，君豈有心猶覓安。", "但促小槽添壓石，龍頭珠滴夜珊珊。"]'),
('d49335fb-8c83-4055-a9e1-4eece5079298','次韻知郡安撫九日南樓宴集三首  其一','范成大','宋','宋诗','song-poetry','','[]','雙旌暮捲小舂容，畫棟雲生笑語中。',64,'全唐诗/poet.song.137000.json','["雙旌暮捲小舂容，畫棟雲生笑語中。", "但覺山光侵酒綠，不知日脚染溪紅。", "控臨縹緲疑無地，指點虛無欲馭風。", "誰遣玉蟾催騎吹，歸來人影在朦朧。"]'),
('c4b2661e-fc76-4b04-a542-bf2fe7a17999','次韻知郡安撫九日南樓宴集三首  其二','范成大','宋','宋诗','song-poetry','','[]','珠履參陪北海觴，仍邀擁節舊中郎。',64,'全唐诗/poet.song.137000.json','["珠履參陪北海觴，仍邀擁節舊中郎。", "碧城香霧連天暝，黄葉霜風捲地凉。", "佳節轉頭論聚散，清波從古閲興亡。", "明年重把茱萸醉，公在叢霄貢玉堂。"]'),
('4cdd5457-33d7-42da-9d80-0bd18a35c716','次韻知郡安撫九日南樓宴集三首  其三','范成大','宋','宋诗','song-poetry','','[]','斯民鄒魯更豐年，雅道凄凉見此賢。',64,'全唐诗/poet.song.137000.json','["斯民鄒魯更豐年，雅道凄凉見此賢。", "萬隴登禾新霽色，千村鳴柝舊寒煙。", "鏘金絕世詩情妙，倚劍凌空隸墨鮮。", "珍重北窗山六六，使君名與汝俱傳。"]'),
('f11bd57a-96a8-4b1c-adab-bbc330a4d83e','晚集南樓','范成大','宋','宋诗','song-poetry','','[]','浪隨兒女怨萍蓬，笑拍闌干萬事空。',64,'全唐诗/poet.song.137000.json','["浪隨兒女怨萍蓬，笑拍闌干萬事空。", "宇宙勳名無骨相，江山得句有神功。", "掉頭莫覷秋高鶚，留眼來賓日暮鴻。", "懶拙已成三昧解，此生還證一圓通。"]'),
('5fbcc487-4061-4d9b-96cd-13dd61b9abac','賞雪騎鯨軒子文夜歸酒渴侍兒薦茗飲蜜漿明日以詫同游戲爲書事邀宗偉同作','范成大','宋','宋诗','song-poetry','','[]','溪山四時佳，今日更奇絕。',180,'全唐诗/poet.song.137000.json','["溪山四時佳，今日更奇絕。", "天公妙莊嚴，施此一川雪。", "飛花浩如海，眩轉塞空闊。", "水西萬珠樹，玉塔照銀闕。", "碧溪不受凍，長灘瀉清咽。", "漁舟晚猶汎，樵檐寒未歇。", "懸知畫不到，未省詩能說。", "歸來强搜句，冰硯冷於鐵。", "不知嚴夫子，迎門生暖熱。", "梅香不可耐，但覺酒腸㷎。", "密融花氣動，茶泛乳膏發。", "寧辭春笋寒，爲暖花瓷滑。", "瞢騰畫屏暖，喚起眼餘纈。", "笑我獨何事，作此淡生活。", "想像高唐賦，何如徑排闥。"]'),
('d769b5ab-1d40-444c-ae2b-8bd5bf45f623','從聖集乞黄巖魚鮓','范成大','宋','宋诗','song-poetry','','[]','截玉凝膏膩白，點酥粘粟輕紅。',28,'全唐诗/poet.song.137000.json','["截玉凝膏膩白，點酥粘粟輕紅。", "千里來從何處，想看舶浪帆風。"]'),
('84caa30a-f533-4ca9-bb5e-484154195c15','從宗偉乞冬筍山藥','范成大','宋','宋诗','song-poetry','','[]','竹塢撥沙犀頂銳，藥畦粘土玉肌豐。',32,'全唐诗/poet.song.137000.json','["竹塢撥沙犀頂銳，藥畦粘土玉肌豐。", "裹芽束縕能分似，政及萊蕪甑釜空。"]'),
('ca1a5958-6f9e-4b04-874f-d83c53f87990','雪後守之家梅未開呈宗偉','范成大','宋','宋诗','song-poetry','','[]','瓦溝凍殘雪，檐溜粘輕冰。',120,'全唐诗/poet.song.137000.json','["瓦溝凍殘雪，檐溜粘輕冰。", "破寒一竿日，春隨人意生。", "瑞葉再三白，南枝尚含情。", "定知司花女，未肯嫁娉婷。", "官居苦無頼，一笑如河清。", "落木露荒山，寒溪繞孤城。", "朝暮何所見，雲黄叫饑鷹。", "東風不早計，愁眼何當明。", "北鄰小橫斜，蘚地可班荆。", "憑君趣花信，把酒撼瓊英。"]'),
('0bfbf2a2-0b00-406e-b48b-419aa5b42f52','次韻溫伯城上','范成大','宋','宋诗','song-poetry','','[]','閉戶成癡坐，扶藜得意行。',48,'全唐诗/poet.song.137000.json','["閉戶成癡坐，扶藜得意行。", "樓臺浮霽色，市井碎春聲。", "雪盡小橋出，煙消千嶂生。", "病多無脚力，遥羨落鴻輕。"]'),
('1d9f32c6-778d-455c-82ff-3aa57b52b2af','知郡安撫以立春日揭所書新安郡榜南樓之上曉雪紛集邦人以爲善祥遂開宴以落之輒賦長句一篇以附風謠之末','范成大','宋','宋诗','song-poetry','','[]','碧瓦朱甍上牛斗，妙墨新題森鎖鈕。',128,'全唐诗/poet.song.137000.json','["碧瓦朱甍上牛斗，妙墨新題森鎖鈕。", "使君筆力挽春來，一夜飛花暗梅柳。", "南山與樓相對高，向來千載爭雄豪。", "八分三字一彈壓，衆峰戢戢如兒曹。", "人間盛事天不隔，急催此雪成三白。", "未論千古福邦人，先卜明年滿岡麥。", "東風酒面吹凝酥，不辭醉倒歸相扶。", "短歌萬一傳樂府，湛輩亦與公名俱。"]'),
('92bf8f6b-0caf-4788-b9be-175422be84f7','次韻知郡安撫元夕賞倅廳紅梅三首  其一','范成大','宋','宋诗','song-poetry','','[]','春入林梢一再風，破寒勻染費天工。',64,'全唐诗/poet.song.137000.json','["春入林梢一再風，破寒勻染費天工。", "雖然媚蕩新粧別，只與橫斜舊格同。", "午枕乍醒鉛粉退，曉奩初罷蠟脂融。", "後來顔色休論似，夾路漫山取次紅。"]'),
('429f1fc7-5c1f-4d8f-8aba-419d935aaf3e','次韻知郡安撫元夕賞倅廳紅梅三首  其二','范成大','宋','宋诗','song-poetry','','[]','真色生香絕世逢，煙光池面兩溶溶。',64,'全唐诗/poet.song.137000.json','["真色生香絕世逢，煙光池面兩溶溶。", "楚鄰不待施朱好，虢國翻嫌傅粉濃。", "晴日曖雲春照耀，溫風霽月夜舂容。", "酒闌且駐紗籠看，慢破團團一壁龍。"]'),
('b00b038b-7018-44b4-8921-5eac65d19606','次韻知郡安撫元夕賞倅廳紅梅三首  其三','范成大','宋','宋诗','song-poetry','','[]','司花一笑爲誰開，知道朱幡得得來。',64,'全唐诗/poet.song.137000.json','["司花一笑爲誰開，知道朱幡得得來。", "疎影有情當洞戶，蔫香無語墮空杯。", "風生翰墨留連看，月入笙歌次第催。", "來歲如今翻舊唱，五雲叢裏望三台。"]'),
('ca3ce33b-03de-48a1-9021-4b0be9f65676','新安絕少紅梅惟倅廳特盛通判朝議召幕僚賞之坐皆有詩亦賦古風一首','范成大','宋','宋诗','song-poetry','','[]','華燈收盡江梅落，別有橫枝照林薄。',128,'全唐诗/poet.song.137000.json','["華燈收盡江梅落，別有橫枝照林薄。", "天教閬苑染芳根，小住山城慰蕭索。", "騰騰醉後酒紅醺，淡淡粧成笑靨新。", "斟酌東君已傾倒，爲渠都費十分春。", "別乘胸懷有風月，催喚清尊洗愁絕。", "花知主客得不凡，一夜光風融絳雪。", "樓頭煙暝吹單于，花梢挂星光有無。", "歸來境熟落春夢，夢入鎖香紅綺疏。"]'),
('546eddcf-8060-4e31-9223-70c3c88ce33a','胡宗偉罷官改秩舉將不及格往謁金陵丹陽諸使者遂朝行在頗有倦游之歎作詩送之','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u592a\u6e56"]','凍雲埋山天冥濛，北風無情雪塞空。',320,'全唐诗/poet.song.137000.json','["凍雲埋山天冥濛，北風無情雪塞空。", "道傍人稀鳥飛絕，問君東遊何怱怱。", "君言薄官淡無味，免俗未能聊復爾。", "我評茲事一鴻毛，因行且看佳山水。", "陵陽樓閣壓高城，煙屏百疊雙流橫。", "姑孰江亭更奇絕，濃黛兩抹長眉青。", "山形成龍復成虎，六代遺蹤供弔古。", "大荒莽蒼江水黄，兩涘風煙眇吳楚。", "却浮一葦下長川，浮玉低昂波聒天。", "梁溪南岸小停櫓，一酌人間第二泉。", "閶門峨峨過吾國，姑蘇臨波照金碧。", "太湖三萬六千頃，上有垂虹跨南極。", "我家越相尚神遊，試從煙浪訪扁舟。", "問訊白鷗相記否，謂言久客不勝愁。", "軟紅三尺長安道，九重城闕乾坤繞。", "西湖山寺浙江樓，君昔曾遊今更好。", "故人客館中天開，非君誰上黄金臺。", "挽著天衢五雲上，却望江湖如夢迴。", "萬境何如一丘壑，幾時定解冠裳縛。", "幔亭山下桂叢深，清社向來都寂莫。"]'),
('30df2fa2-aaf7-4888-b71d-858974266abe','黄伯益官舍賞梅','范成大','宋','宋诗','song-poetry','','[]','一杯何處洗愁顔，黄法曹家玉樹寒。',32,'全唐诗/poet.song.137000.json','["一杯何處洗愁顔，黄法曹家玉樹寒。", "翠袖撚香留客看，春風都在小闌干。"]'),
('58fe3f5f-f1f7-4542-8147-66465bbb4872','次韻朱嚴州從李徽州乞牡丹三首  其一','范成大','宋','宋诗','song-poetry','','[]','佳人絕世墮空谷，破恨解顔春亦來。',32,'全唐诗/poet.song.137000.json','["佳人絕世墮空谷，破恨解顔春亦來。", "莫對溪山話京洛，碧雲西北漲黄埃。"]'),
('b5fd0245-2f52-46df-bd90-81e00cc580e8','次韻朱嚴州從李徽州乞牡丹三首  其二','范成大','宋','宋诗','song-poetry','','[]','歙浦煙山蟠萬疊，釣臺雲日擁千章。',32,'全唐诗/poet.song.137000.json','["歙浦煙山蟠萬疊，釣臺雲日擁千章。", "兩侯好事洗寒劣，寶檻移春入燕香。"]'),
('072e160e-a3ab-42ee-8a42-3468cb73ebf6','次韻朱嚴州從李徽州乞牡丹三首  其三','范成大','宋','宋诗','song-poetry','','[]','閬風苑裏司花女，肯作山腰水尾來。',32,'全唐诗/poet.song.137000.json','["閬風苑裏司花女，肯作山腰水尾來。", "十二玉欄天一笑，只今歸路五雲開。"]'),
('593b17e6-7e1f-47d3-98c1-28ca115f8aa7','送琴客許揚歸永嘉','范成大','宋','宋诗','song-poetry','','[]','烏帽休衝九陌埃，瘦藤定約到秋迴。',32,'全唐诗/poet.song.137000.json','["烏帽休衝九陌埃，瘦藤定約到秋迴。", "龍湫鴈蕩經行處，斷取松風萬壑來。"]'),
('686a6456-b030-4e2c-adf8-efc9bfc5082f','送李徽州赴湖北漕','范成大','宋','宋诗','song-poetry','','[]','徂徠千丈松，閲世聳絕壁。',120,'全唐诗/poet.song.137000.json','["徂徠千丈松，閲世聳絕壁。", "高標上霄漢，峻節貫金石。", "惟有孤生竹，亭亭附微植。", "月夜借清景，春朝分秀色。", "託根未渠央，萬牛挽山澤。", "昂藏轉江湖，夷路入王國。", "明堂五雲上，一柱屹天極。", "可望不可攀，清都與塵隔。", "依然此清士，空山淡愁閴。", "悲吟發清籟，搖蕩風雨夕。"]'),
('619ecd0d-2253-4970-8a99-95a7983637e2','送通守林彥强寺丞還朝','范成大','宋','宋诗','song-poetry','','[]','鴈蕩之山天下無，奔岸絕壑不可圖。',128,'全唐诗/poet.song.137000.json','["鴈蕩之山天下無，奔岸絕壑不可圖。", "地靈境秀有人物，新安府丞今第一。", "紛綸草木變暄寒，竹節松心故凜然。", "窮山薄宦我無恨，識公大勝荆州韓。", "梅風漲溪綠如酒，曉插檣烏上南斗。", "只今廣厦論唐虞，斟酌正須醫國手。", "秀眉津津雙頰丹，想看鳴佩翔九關。", "諸公倘欲持公議，莫遣此賢思故山。"]'),
('a28d4286-2f3d-4032-b11e-a327ff19bc61','送溫伯歸福唐納婦且約復游霅川','范成大','宋','宋诗','song-poetry','','[]','攬秀堂前一笑傾，都忘身世兩浮萍。',64,'全唐诗/poet.song.137000.json','["攬秀堂前一笑傾，都忘身世兩浮萍。", "扶藜處處從君賞，落筆時時得我驚。", "荔熟閩山勞夢想，蘋香苕水約逢迎。", "袛愁誤入桃源後，從此車輪四角生。"]'),
('13151aaf-5cbf-4f37-9474-fcdf5b7a000a','次韻宗偉閲番樂','范成大','宋','宋诗','song-poetry','','[]','十日閒愁晝掩關，起尋一笑共清歡。',64,'全唐诗/poet.song.137000.json','["十日閒愁晝掩關，起尋一笑共清歡。", "罷休詩社工夫淡，洗浄書生氣味酸。", "盡遣餘錢付桑落，莫隨短夢到槐安。", "繡鞾畫鼓留花住，賸舞春風小契丹。"]'),
('20482940-61e1-4a19-979f-b52f6b3c714f','題漫齋壁','范成大','宋','宋诗','song-poetry','','[]','漢陰無械可容機，歲晚功名一衲衣。',64,'全唐诗/poet.song.137000.json','["漢陰無械可容機，歲晚功名一衲衣。", "槁木閒身隨念懶，浮雲幻事轉頭非。", "三彭已罷庚申守，五鬼從教乙丑歸。", "富貴神仙兩俱累，此心安處是真依。"]'),
('151949c8-7bec-429f-9d8d-988bcb32e503','四月十六日拄笏亭偶題','范成大','宋','宋诗','song-poetry','','[]','轉午聞雞日正長，小亭方丈納空光。',32,'全唐诗/poet.song.137000.json','["轉午聞雞日正長，小亭方丈納空光。", "綠陰一雨濃如黛，何處風來百種香。"]'),
('fe29d607-ddab-44f0-a0f7-95175444f467','次韻即席','范成大','宋','宋诗','song-poetry','','[]','留連銀燭照金荷，腸斷華年一擲梭。',64,'全唐诗/poet.song.137000.json','["留連銀燭照金荷，腸斷華年一擲梭。", "月姊有情難獨夜，天孫無頼早斜河。", "晶晶霜瓦寒生粟，衮衮風幃細湧波。", "鴰鶡曉啼鳴鵲散，許多佳景奈愁何。"]'),
('97146529-a846-4e58-94b1-ed0216e3228f','五月聞鶑二首  其一','范成大','宋','宋诗','song-poetry','','[]','桑陰浄盡麥頭齊，江上聞鶑每歲遲。',32,'全唐诗/poet.song.137000.json','["桑陰浄盡麥頭齊，江上聞鶑每歲遲。", "不及曉風鵯鵊子，迎春啼到送春時。"]'),
('bac91e41-34ef-4087-870e-917074e5ff75','五月聞鶑二首  其二','范成大','宋','宋诗','song-poetry','','[]','一聲初上最高枝，忙殺嘔啞百舌兒。',32,'全唐诗/poet.song.137000.json','["一聲初上最高枝，忙殺嘔啞百舌兒。", "老盡西園千樹綠，却憐槐眼正迷離。"]'),
('efbe31bb-babb-4be8-8b46-a57e0eba68c2','知郡檢計齋醮禱雨登時感通輒賦古風以附輿頌','范成大','宋','宋诗','song-poetry','','[]','六月火雲高偃蹇，使君有意憐焦卷。',128,'全唐诗/poet.song.137000.json','["六月火雲高偃蹇，使君有意憐焦卷。", "一封紅篆驛金龍，雨氣倏隨爐燎滿。", "風師避路雷車鳴，石破天驚檐溜傾。", "不知稻本頗甦否，但覺溪聲如百霆。", "稅駕朱旛未云久，造化功成屈伸肘。", "我評茲事與天通，知公小試調元手。", "清壇深夜賓衆真，前驅霓旌後飈輪。", "定有靈官識仙伯，報道紫皇思侍臣。"]'),
('7452791e-5960-4212-8e5f-b4744792f7f7','送子文雜言','范成大','宋','宋诗','song-poetry','','[]','陰谷雲低梅雨多，黄山滌源溪湧波。',324,'全唐诗/poet.song.137000.json','["陰谷雲低梅雨多，黄山滌源溪湧波。", "南風匝地送歸客，雙槳下瀨如投梭。", "嚴夫子，君舉酒，我其爲君歌。", "萬山叢叢石鑿鑿，官居破屋巢煙蘿。", "杜鵑曉啼猿暮叫，客行到此真蹉跎。", "窮愁無復理，一飲三歎息。", "城東黌舍有佳人，邂逅使我加餐食。", "同鄉更同調，目擊心已傳。", "蟄蟲欲作雷奮地，萬籟方寂風行山。", "吹竽喚我醒，連鼓相追攀。", "飈車電轂不可輦，但覺兩腋生飛翰。", "狂歌不必終曲，戲奕不必滿局。", "有時不揖上馬去，出門大笑驚僮僕。", "窮鄉眼冷見未曾，道上囁嚅相指目。", "云此陿隘何以有二士，直恐翩翩跨黄鵠。", "廣文組解登王畿，諸公貴人爭勸歸。", "常日心期有定論，贈行不惜重費詞。", "腰金佩璐衆目好，汗簡沉碑千載癡。", "一尊有意重山嶽，五鼎無心輕網絲。", "嚴夫子，應領略，別後頻書相發藥。", "我既爲萬頃之狎鷗，君勿作九臯之鳴鶴。"]'),
('3a047d13-e160-4be5-ac64-2c41ac6fc2e0','新館','范成大','宋','宋诗','song-poetry','','[]','露稻粘明璫，風茅衮高浪。',96,'全唐诗/poet.song.137000.json','["露稻粘明璫，風茅衮高浪。", "荒煙暗白道，行行亂蛩響。", "日脚午未吐，雲頭晚猶漲。", "欣此半日凉，籃輿走清曠。", "病客不堪暑，茲行天肯相。", "蚊蝱掃無跡，秋意滿千嶂。", "稍尋泉石盟，略褫簿書障。", "鴒原定相念，因風報無恙。"]'),
('a930f487-7e95-452b-ba67-25299e4346ef','臨溪寺','范成大','宋','宋诗','song-poetry','','[]','萬山繞竮竛，二水奔澒洞。',96,'全唐诗/poet.song.137000.json','["萬山繞竮竛，二水奔澒洞。", "亭亭林中寺，金碧燦檐棟。", "解鞍得蒲團，卧受瓦爐供。", "少捐一炊頃，暫作百年夢。", "無人自驚覺，幽禽正清哢。", "倦客如殘僧，無力供世用。", "此行端爲山，紫翠迭迎送。", "漱井出門去，驚塵撲飛鞚。"]'),
('33e280d8-5d9a-4d02-8e8d-4ae7056c7be8','盤龍驛','范成大','宋','宋诗','song-poetry','','[]','聞雞一唱罷，占斗三星沒。',120,'全唐诗/poet.song.137000.json','["聞雞一唱罷，占斗三星沒。", "天高月徘徊，野曠山突兀。", "暗蛩泣草露，怨亂語還咽。", "凉螢不復舉，點綴稻花末。", "惟餘絡緯豪，悲壯殷林樾。", "小蟲亦何情，孤客心斷絕。", "魂驚板橋穿，足側石子滑。", "行路如許難，誰能不華髮。", "高城謾回首，疊嶂屹天闕。", "遥知秋衾夢，千里一飄忽。"]'),
('346007fb-be81-44db-ac82-85048a1794ed','竹下','范成大','宋','宋诗','song-poetry','','[]','松杉晨氣清，桑柘暑陰薄。',108,'全唐诗/poet.song.137000.json','["松杉晨氣清，桑柘暑陰薄。", "稻穗黄欲卧，槿花紅未落。", "秋鶑尚嬌姹，晚蝶成飄泊。", "犬騃逐車馬，雞驚撲籬落。", "道逢行商問，平生幾芒屩。", "頳肩走四方，爲口不計脚。", "劣能濡簞瓢，何敢議囊橐。", "我亦縻斗升，三年去丘壑。", "二俱亡羊耳，未用苦商略。"]'),
('5db516fb-8ba1-44cb-86a8-18a40ecbe201','寒亭','范成大','宋','宋诗','song-poetry','','[]','溝塍與澗合，隴畝抱山轉。',120,'全唐诗/poet.song.137000.json','["溝塍與澗合，隴畝抱山轉。", "向來六月旱，此地免焦卷。", "早穗已垂垂，晚苗猶剪剪。", "一川豐年意，比屋閙雞犬。", "老農霜須鬢，矍鑠黄犢健。", "自云足踏地，常賦何能免。", "刈熟倩人輸，不識長官面。", "康年無復事，但恐社酒淺。", "我亦有二頃，收拾尚可繭。", "懷哉笠澤路，歸鏟犁頭蘚。"]'),
('eaf7fe22-005d-4d26-9c07-1a88d4e53b91','清弋江','范成大','宋','宋诗','song-poetry','','[]','微生本漁樵，長日渺江海。',120,'全唐诗/poet.song.137000.json','["微生本漁樵，長日渺江海。", "扣舷濯滄浪，尚說天宇隘。", "朅來車馬路，悒悒佳思敗。", "黄塵撲眉鬚，驅逐似償債。", "羸驂繫偪仄，狂犬吠荒怪。", "鄉心入旅夢，一葉舞澎湃。", "晨興過墟市，喜有魚蝦賣。", "眼明見清江，積雨助橫潰。", "褰裳喚扁舟，臲卼不勝載。", "不辭野渡險，弄水聊一快。"]'),
('2aef53d5-7254-4aab-9ccf-c016895c2ccf','隠靜山','范成大','宋','宋诗','song-poetry','','[]','五峰抱巖扉，千柱奠雲壑。',120,'全唐诗/poet.song.137000.json','["五峰抱巖扉，千柱奠雲壑。", "荒原蕞爾縣，有此寶樓閣。", "維昔經營初，衣錫化雙鶴。", "杖頭具隻眼，矯矯雲中落。", "尊者一笑許，璇題照林薄。", "庭柏有祖意，石泉韻天樂。", "清簧轉碧雞，飛梭擲蒼鵲。", "號風饑虎怒，失木啼猿愕。", "英遊偶然同，吏檄乃不惡。", "題名記吾曾，醉墨疥丹堊。"]'),
('6bfeda34-4e57-4b41-897a-3283534280cd','新嶺','范成大','宋','宋诗','song-poetry','','[]','瘦馬兀瞢騰，荒雞號莽蒼。',120,'全唐诗/poet.song.137000.json','["瘦馬兀瞢騰，荒雞號莽蒼。", "絲窠罥朝露，籬落萬珠網。", "宿雲拂樹過，飛泉擘山響。", "老桑跼潛虯，怪蔓掛騰蟒。", "山行何許深，空翠滴羈鞅。", "釀愁積雨寒，破悶朝日放。", "曈曈赤幟張，昱昱金鉦上。", "浮動草花馥，清和野禽唱。", "僕夫有好語，沙平路如掌。", "惟憂三溪阻，橋斷山水漲。"]'),
('76d3201a-4e42-4ffa-9e62-5f157abbc1d2','送通守趙積中朝議請祠歸天台','范成大','宋','宋诗','song-poetry','','[]','城頭千峰青繞屋，城下灘流三百曲。',160,'全唐诗/poet.song.137000.json','["城頭千峰青繞屋，城下灘流三百曲。", "誰云偪仄復偪仄，尚有高軒肯來辱。", "紅梅花下兩芳春，春風惠和如主人。", "搶攘塵土簿書裏，見此繅籍天球溫。", "厚祿故人車結轍，掉頭獨泛清溪月。", "不從世外得超然，世間誰肯如公決。", "生平我亦一沙鷗，葦白蘆黄今正秋。", "送公使我歸思動，破煙衝雨憶扁舟。", "明年想見東山起，我亦煎茶石橋水。", "道逢蓑笠把漁竿，即是馬曹狂掾史。"]'),
('85efb08f-1fa2-4c0e-bbe7-20cb38cfe142','送詹道子教授奉祠養親','范成大','宋','宋诗','song-poetry','','[]','新安學宮天下稀，先生孝友真吾師。',160,'全唐诗/poet.song.137000.json','["新安學宮天下稀，先生孝友真吾師。", "斑衣悞作長裾曳，二年思歸今得歸。", "牋詞上訴人叵挽，璽書賜可羣公歎。", "青山百匝不留人，空與諸生遮望眼。", "白雲孤起越南天，向來恨身無羽翰。", "下馬入門懷橘拜，身今却在白雲邊。", "鶴髮鬖鬖堂上坐，兒孫稱觴婦供果。", "世間此樂幾人同，看我風前孤淚墮。", "一杯送舟下水西，我欲贈言無好詞。", "徑須喚起束廣微，爲君重補南陔詩。"]'),
('aa2e5293-c226-4b89-8725-4061b3f14868','道子教授奉祠諸生率余祖席如意院','范成大','宋','宋诗','song-poetry','','[]','暫移三席款雲關，木末闌干暮紫間。',64,'全唐诗/poet.song.137000.json','["暫移三席款雲關，木末闌干暮紫間。", "絳帳莫貪江上路，青鞵先試水西山。", "伯陽有道來重趼，禦寇他年憶解顔。", "怪我抗塵驅俗駕，諸公何事許追攀。"]'),
('f5316d69-9710-418c-8ed0-9015a23b5680','淳安','范成大','宋','宋诗','song-poetry','','[]','篙師叫怒破濤瀧，水石如鐘自擊撞。',32,'全唐诗/poet.song.137000.json','["篙師叫怒破濤瀧，水石如鐘自擊撞。", "欲識人間奇險處，但從歙浦過桐江。"]'),
('dc8a0209-ef54-4990-ba9d-da9c64b18f17','嚴州','范成大','宋','宋诗','song-poetry','','[]','城府黄塵撲馬鞍，一篙重探水雲寒。',32,'全唐诗/poet.song.137000.json','["城府黄塵撲馬鞍，一篙重探水雲寒。", "耳邊眼底無公事，睡過嚴州二百灘。"]'),
('ac0b9fa1-a5b6-480e-a886-f443bdd64c41','釣臺','范成大','宋','宋诗','song-poetry','','[]','山林朝市兩塵埃，邂逅人生有往來。',32,'全唐诗/poet.song.137000.json','["山林朝市兩塵埃，邂逅人生有往來。", "各向此心安處住，釣臺無意壓雲臺。"]'),
('9550efbc-05c9-437a-9b48-cbbbadff7d6f','桐廬','范成大','宋','宋诗','song-poetry','','[]','濕雲垂野淡疎林，十日山行九日陰。',32,'全唐诗/poet.song.137000.json','["濕雲垂野淡疎林，十日山行九日陰。", "梅子弄黄應要雨，不知客路已泥深。"]'),
('3bb1a5da-f202-4c92-b2c3-1db959ea67c2','富陽','范成大','宋','宋诗','song-poetry','','[]','不到江湖恰五年，歙山青繞屋頭邊。',32,'全唐诗/poet.song.137000.json','["不到江湖恰五年，歙山青繞屋頭邊。", "富春渡口明人眼，落日孤舟浪拍天。"]'),
('eeb4c529-162f-40ec-8938-d0dd5f57da3b','餘杭','范成大','宋','宋诗','song-poetry','','[]','春晚山花各靜芳，從教紅紫送韶光。',32,'全唐诗/poet.song.137000.json','["春晚山花各靜芳，從教紅紫送韶光。", "忍冬清馥薔薇釅，薰滿千村萬落香。"]'),
('e109ad03-7d5a-4b2b-8f84-117548084d36','於潛','范成大','宋','宋诗','song-poetry','','[]','邑居官寺兩淒清，晚市都無菜可羹。',32,'全唐诗/poet.song.137000.json','["邑居官寺兩淒清，晚市都無菜可羹。", "何處直能令鬼怕，祗今猶自有人行。"]'),
('dc606083-3dcd-42b9-9579-1c57c0861375','昌化','范成大','宋','宋诗','song-poetry','','[]','翠染南山擁縣門，一洲橫截兩溪分。',32,'全唐诗/poet.song.137000.json','["翠染南山擁縣門，一洲橫截兩溪分。", "長官日永無公事，卧聽灘聲看白雲。"]'),
('801c1a11-4091-4342-bca9-15aac43b9693','百丈山','范成大','宋','宋诗','song-poetry','','[]','沐雨梳風有底忙，解鞍來宿贊公房。',32,'全唐诗/poet.song.137000.json','["沐雨梳風有底忙，解鞍來宿贊公房。", "傳聞三嶺連天峻，未到王千已斷腸。"]'),
('0b53514b-eb0f-4869-a7cb-e3a6ff1d7cac','昱嶺','范成大','宋','宋诗','song-poetry','','[]','竹輿搖兀走婆娑，石滑泥融側足過。',32,'全唐诗/poet.song.137000.json','["竹輿搖兀走婆娑，石滑泥融側足過。", "昱嶺不高人已困，晚登新嶺奈君何。"]'),
('62997f35-79d1-4f27-a0eb-986e4521233b','王千嶺','范成大','宋','宋诗','song-poetry','','[]','山靈設險合崢嶸，行客何須向此行。',32,'全唐诗/poet.song.137000.json','["山靈設險合崢嶸，行客何須向此行。", "羸馬不前人雨汗，此身安得諱勞生。"]'),
('01efd1e0-ab85-4fb2-9736-84ad8e7b4454','刈麥','范成大','宋','宋诗','song-poetry','','[]','麥頭熟顆已如珠，小阨惟憂積雨餘。',32,'全唐诗/poet.song.137000.json','["麥頭熟顆已如珠，小阨惟憂積雨餘。", "丐我一晴天易耳，十分終惠莫乘除。"]'),
('8ca1adc7-92eb-4a15-b60a-90d904d3f92b','插秧','范成大','宋','宋诗','song-poetry','','[]','種密移疎綠毯平，行間清淺縠紋生。',32,'全唐诗/poet.song.137000.json','["種密移疎綠毯平，行間清淺縠紋生。", "誰知細細青青草，中有豐年擊壤聲。"]'),
('461a32f8-0967-4ee7-a4bf-eede06ff0034','曬繭','范成大','宋','宋诗','song-poetry','','[]','隔籬處處雪成窩，牢閉柴荆斷客過。',32,'全唐诗/poet.song.137000.json','["隔籬處處雪成窩，牢閉柴荆斷客過。", "葉貴蠶饑危欲死，尚能包裹一絲窠。"]'),
('548f3841-549a-4d62-aa27-3514290907ca','科桑','范成大','宋','宋诗','song-poetry','','[]','斧斤留得萬枯株，獨速槎牙立暝途。',32,'全唐诗/poet.song.137000.json','["斧斤留得萬枯株，獨速槎牙立暝途。", "飽盡春蠶收罷繭，更殫餘力付樵蘇。"]'),
('82b789bb-6e34-4568-b52c-b2574c925074','龍學尚書新安侯羅公輓詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','今代丹臺籍，頻年綠野居。',48,'全唐诗/poet.song.137000.json','["今代丹臺籍，頻年綠野居。", "鐵冠真御史，革履舊尚書。", "短世浮雲盡，平生半稿餘。", "人言公不朽，蘭玉照前除。"]');
